	('a607a966-d454-4f08-950e-d8e6ec1e1545', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Licenciatura en Ingeniería Electrónica para Sistemas Inteligentes', 'LIES', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('a75b6da6-ad46-43d8-a069-31a203a9d340', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Licenciatura en Ingeniería Mecatrónica', 'LIM', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('c0fb8394-656f-4709-a92e-351daf477c60', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Licenciatura en Ingeniería Industrial', 'LII', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('8f1ce751-949b-45dd-8e38-e10c64b077fd', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Licenciatura en Ingeniería Cibernética y Sistemas Computacionales', 'LICS', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('76224caa-1203-4b18-b9df-758f1f9a97fb', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Licenciatura en Ingeniería Biomédica', 'LIB', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('01552f83-5625-4532-a8ae-723cc864494c', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Maestría en Gerencia de Proyectos Inmobiliarios', 'MGPI', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('81278d11-5487-41b3-b8bd-708cdd147ed4', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Maestría en Dirección Industrial', 'MDI', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('d8089840-c7ba-4e64-b073-d8d93092424f', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Especialidad en Dirección Industrial', 'EDI', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('fbae0d9a-282c-4eb0-bc48-02bb11015d57', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Maestría en Gestión de Proyectos y de Empresas Constructoras', 'MGPC', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('c8f8c573-ec33-446d-886d-338def5d55af', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Especialidad en Energías Renovables', 'EER', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
	('83fcc355-b79b-4650-a757-0c935127e161', '155b5fe7-9e09-420f-8d9d-ddd8219f193d', 'Maestría en Ciberseguridad', 'MCIB', NULL, true, '2026-01-30 20:55:12.677212+00', '2026-01-30 20:55:12.677212+00'),
