INSERT INTO "public"."estructuras_asignatura" ("id", "nombre", "definicion", "creado_en", "actualizado_en", "template_id", "tipo") VALUES
	('7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'Asignatura SEP/ULSA (semilla)', '{"type": "object", "required": ["denominacion_de_la_asignatura_o_unidad_de_aprendizaje", "ciclo", "clave_de_la_asignatura", "fines_de_aprendizaje_o_formacion", "contenido", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico", "actividades_de_aprendizaje_independientes", "criterios_de_evaluacion", "modalidades_tecnologicas_e_informaticas"], "properties": {"ciclo": {"type": "string", "title": "Ciclo", "examples": ["Primer semestre"], "description": "Indicar el ciclo en el que se impartirá la asignatura en el orden establecido en el mapa curricular. En caso de ser flexible; indicar el área o módulo al que pertenece. Para currículum rígido que contemple asignaturas optativas; indicar “Optativa”, y en caso de que se curse en un ciclo determinado, señalar el ciclo acompañado de la leyenda “Optativa”."}, "contenido": {"type": "null", "const": null, "title": "Contenido temático", "x-column": "contenido_tematico", "description": "Enunciar, en idioma español, los temas y subtemas que se abordarán en la asignatura o unidad de aprendizaje; estructurados de manera lógica y secuencial y numerados en orden jerárquico. Éstos deberán ser acordes con la carga horaria asignada, sustentar la denominación de la asignatura y contribuir al logro de los fines de aprendizaje."}, "clave_de_la_asignatura": {"type": "string", "title": "Clave de la asignatura", "examples": ["MAT-101"], "description": "Anotar la clave que identifica a la asignatura o unidad de aprendizaje; la cual debe coincidir con la señalada en el mapa curricular."}, "criterios_de_evaluacion": {"type": "string", "title": "Criterios de evaluación", "x-column": "criterios_de_evaluacion", "description": "Enlistar las actividades o productos que considerarán para valorar los aprendizajes logrados por los estudiantes, señalar el porcentaje para cada uno, de tal manera que sumen el 100%. Éstos deberán ser acordes con las actividades de aprendizaje."}, "fines_de_aprendizaje_o_formacion": {"type": "string", "title": "Fines de aprendizaje o formación", "description": "Describir los aprendizajes y fines que alcanzará el estudiante al concluir la asignatura. Deberá sustentar la denominación de la asignatura, vincularse con los contenidos temáticos y coadyuvar al logro del fin de aprendizaje y perfil de egreso del plan de estudios."}, "modalidades_tecnologicas_e_informaticas": {"type": "string", "title": "Modalidades tecnológicas e informáticas", "description": "Describir los recursos tecnológicos y de comunicación que se emplearán para el desarrollo del proceso de enseñanza-aprendizaje de la asignatura. Para las modalidades no escolarizada y mixta, este elemento es obligatorio."}, "actividades_de_aprendizaje_independientes": {"type": "string", "title": "Actividades de aprendizaje independientes", "description": "Señalar las actividades de aprendizaje que desarrollará el estudiante de manera independiente. Éstas deberán ser acordes con la naturaleza de la asignatura y la modalidad educativa."}, "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": {"type": "string", "title": "Denominación de la asignatura o unidad de aprendizaje", "examples": ["Matemáticas I"], "description": "Señalar el nombre de la asignatura o unidad de aprendizaje de igual manera que en el mapa curricular."}, "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": {"type": "string", "title": "Actividades de aprendizaje bajo conducción de un académico", "description": "Señalar las actividades de aprendizaje que desarrollará el estudiante en las horas-clase. Éstas deberán ser acordes con la naturaleza de la asignatura, modalidad educativa e instalaciones empleadas, además de contribuir al logro de los fines de aprendizaje."}}, "additionalProperties": false}', '2026-01-09 13:45:37.784586+00', '2026-03-20 23:45:09.22654+00', '1373944894291796699', 'CURRICULAR');
INSERT INTO "public"."estructuras_plan" ("id", "nombre", "tipo", "template_id", "definicion", "creado_en", "actualizado_en") VALUES
	('69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Plan base SEP/ULSA (2026)', 'CURRICULAR', '1373945625988937236', '{"type": "object", "required": ["nombre_autorizado_de_la_institucion", "nivel_y_nombre_del_plan_de_estudios", "modalidad_educativa", "vigencia", "antecedente_academico", "area_de_estudio", "clave_del_plan_de_estudios", "diseno_curricular", "total_de_ciclos_del_plan_de_estudios", "duracion_del_ciclo_escolar", "carga_horaria_a_la_semana", "fines_de_aprendizaje_o_formacion", "perfil_de_egreso", "programa_de_investigacion", "curso_propedeutico", "perfil_de_ingreso", "administracion_y_operatividad_del_plan_de_estudios", "sustento_teorico_del_modelo_curricular", "justificacion_de_la_propuesta_curricular", "propuesta_de_evaluacion_periodica_del_plan_de_estudios", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios"], "properties": {"vigencia": {"type": "string", "title": "Vigencia", "examples": ["2024-2029"], "description": "(Espacio para uso exclusivo de la autoridad educativa)", "referencia_normativa": "Dato administrativo del Anexo 1."}, "area_de_estudio": {"type": "string", "title": "Área de estudio", "examples": ["Ingeniería, industria y construcción", "Ciencias sociales y derecho"], "description": "Señalar el “campo amplio” al que pertenece el plan de estudios. Para ello, considerar la Clasificación Mexicana de Planes de Estudio por Campos de Formación Académica (CMPE 2016), publicado por INEGI.", "referencia_normativa": "Deberá vincularse con el fin de aprendizaje y perfil de egreso del plan de estudios."}, "perfil_de_egreso": {"type": "string", "title": "Perfil de egreso", "examples": ["El egresado será capaz de diseñar estrategias legales..."], "description": "Describir los atributos que habrán desarrollado los estudiantes al concluir el plan de estudios, acordes al nivel educativo y denominación propuesta. De preferencia, dividirlo en conocimientos, habilidades y actitudes.", "referencia_normativa": "Corresponde al requisito ''Perfil de egreso'' del Artículo 8, fracción VI del Acuerdo 17/11/17."}, "diseno_curricular": {"enum": ["Rígido", "Flexible"], "type": "string", "title": "Diseño curricular", "examples": ["Flexible"], "description": "Indicar si es “Rígido” o “Flexible”.", "referencia_normativa": "Define la estructura para el requisito ''Mapa curricular'' del Artículo 8, fracción VII del Acuerdo 17/11/17."}, "perfil_de_ingreso": {"type": "string", "title": "Perfil de ingreso", "examples": ["Conocimientos básicos de matemáticas, capacidad de análisis y redacción."], "description": "Indicar las condiciones académicas ideales (conocimientos, habilidades y aptitudes), para incorporarse al plan de estudios. Deberá vincularse con el nivel educativo y campo de estudio.", "referencia_normativa": "Corresponde al requisito ''Perfil de ingreso'' (condiciones mínimas requeridas) del Artículo 8, fracción V del Acuerdo 17/11/17."}, "curso_propedeutico": {"type": ["string", "null"], "title": "Curso propedéutico", "examples": ["Curso de nivelación de 40 horas obligatorio para aspirantes de áreas ajenas."], "description": "Señalar las situaciones en las que aplicará el curso propedéutico, la población a la que estará dirigido, su duración, la relación con el plan de estudios, así como la información que considere relevante.", "referencia_normativa": "Elemento opcional mencionado en las guías de llenado del Anexo 1."}, "modalidad_educativa": {"enum": ["Escolar", "No escolarizada", "Mixta"], "type": "string", "title": "Modalidad educativa", "examples": ["Escolar"], "description": "Señalar la modalidad educativa en la que se impartirá el plan de estudios: escolar, no escolarizada o mixta.", "referencia_normativa": "Corresponde al requisito de ''Modalidad educativa'' del Artículo 8, fracción II del Acuerdo 17/11/17."}, "antecedente_academico": {"type": "string", "title": "Antecedente académico", "examples": ["Bachillerato concluido o equivalente.", "Título de Licenciatura en áreas afines a la salud."], "description": "Señalar el nivel educativo requerido para ingresar al plan de estudios. Para posgrados, además del nivel educativo; indicar la(s) disciplina(s) o área(s) afín(es) al plan de estudios.", "referencia_normativa": "Corresponde al requisito ''Perfil de ingreso'' (antecedente académico necesario) del Artículo 8, fracción V del Acuerdo 17/11/17."}, "carga_horaria_a_la_semana": {"type": "number", "title": "Carga horaria a la semana", "examples": [25], "description": "Indicar la máxima carga horaria impartida a la semana; no mayor a 50 horas bajo la conducción de un académico.", "referencia_normativa": "Corresponde a la restricción ''sin exceder una carga máxima de 50 horas efectivas por semana'' del Artículo 8, fracción III del Acuerdo 17/11/17."}, "programa_de_investigacion": {"type": ["string", "null"], "title": "Programa de investigación", "examples": ["Línea 1: Innovación Educativa. Objetivo: Analizar el impacto de..."], "description": "(Obligatorio para el nivel de Doctorado y para aquéllas Maestrías orientadas a la investigación). Presentar el programa de investigación que describa los objetivos del programa y líneas de investigación con sus respectivos objetivos. Asimismo, detallar la vinculación con las asignaturas que conforman el plan de estudios, la metodología y presentación de las investigaciones, así como el perfil de los docentes que guiarán su desarrollo.", "referencia_normativa": "Requisito obligatorio solo para Doctorados o Maestrías con orientación a investigación según el Artículo 10, fracción III incisos b) y c) del Acuerdo 17/11/17."}, "clave_del_plan_de_estudios": {"type": "string", "title": "Clave / Año del plan", "examples": ["2024"], "description": "Señalar el año en el que solicita el trámite.", "referencia_normativa": "Dato administrativo del Anexo 1."}, "duracion_del_ciclo_escolar": {"type": "string", "title": "Duración mínima en semanas de cada ciclo escolar", "examples": ["16 semanas"], "description": "Señalar el número mínimo de semanas efectivas de clase que integran el tipo de ciclo en el que se imparte el plan de estudios.", "referencia_normativa": "Corresponde exactamente al requisito ''Duración mínima en semanas'' del Artículo 8, fracción III del Acuerdo 17/11/17."}, "fines_de_aprendizaje_o_formacion": {"type": "string", "title": "Fin de aprendizaje o formación", "examples": ["El estudiante analizará los principios fundamentales del derecho penal..."], "description": "Describir los aprendizajes que lograrán los estudiantes al concluir el plan de estudios. Deberá corresponder con el nivel educativo y la denominación del plan de estudios.", "referencia_normativa": "Corresponde al requisito ''Descripción de los fines del aprendizaje o formación'' del Artículo 8, fracción IV del Acuerdo 17/11/17."}, "nivel_y_nombre_del_plan_de_estudios": {"type": "string", "title": "Nivel y nombre del plan de estudios", "examples": ["Licenciatura en Derecho", "Maestría en Ciencias de la Computación"], "description": "Indicar el nivel educativo y denominación del plan de estudios.", "referencia_normativa": "Corresponde al requisito ''Nivel y denominación del plan de estudios'' del Artículo 8, fracción I del Acuerdo 17/11/17."}, "nombre_autorizado_de_la_institucion": {"type": "string", "title": "Nombre autorizado de la institución", "examples": ["Universidad La Salle A.C."], "description": "Proporcionar el nombre de la institución autorizado por SEP.", "referencia_normativa": "Dato administrativo del Anexo 1."}, "total_de_ciclos_del_plan_de_estudios": {"type": "string", "title": "Número de ciclos escolares que integrarán el plan de estudio", "examples": ["9 cuatrimestres", "8 semestres"], "description": "En diseño flexible especificar mínimo y máximo de ciclos. En diseño rígido especificar el total de ciclos.", "referencia_normativa": "Corresponde a ''señalando el número de ciclos en que se impartirá'' del Artículo 8, fracción III del Acuerdo 17/11/17."}, "sustento_teorico_del_modelo_curricular": {"type": ["string", "null"], "title": "Sustento teórico del modelo curricular", "examples": ["Modelo por competencias profesionales fundamentado en el constructivismo..."], "description": "Presentar de forma concreta el marco conceptual en el que se justifica y fundamenta el diseño y organización curricular del plan de estudios.", "referencia_normativa": "Corresponde al ''sustento teórico del modelo curricular'' que el particular puede incluir según el Artículo 8 (párrafo tercero) del Acuerdo 17/11/17."}, "justificacion_de_la_propuesta_curricular": {"type": ["string", "null"], "title": "Justificación de la propuesta curricular en la modalidad no escolarizada o mixta", "examples": ["Se utilizará una plataforma LMS asincrónica complementada con sesiones síncronas..."], "description": "(Exclusivo para modalidades no escolarizada y mixta). Describir cómo se impartirá el plan de estudios en la modalidad educativa elegida, los recursos tecnológicos y/o didácticos que emplearán para su desarrollo y su vinculación con las asignaturas y actividades de aprendizaje.", "referencia_normativa": "Corresponde a lo solicitado en el Artículo 14 (justificación de modalidad) y Artículo 15 (especificaciones de plataforma/modelo) del Acuerdo 17/11/17."}, "administracion_y_operatividad_del_plan_de_estudios": {"type": ["string", "null"], "title": "Administración y operatividad del plan de estudios", "examples": ["El estudiante podrá inscribir un mínimo de 3 y un máximo de 6 asignaturas por ciclo..."], "description": "Describir la administración del plan de estudios, así como su operatividad; considerando el tipo de diseño curricular empleado. Si es flexible; incorporar el número mínimo y máximo de asignaturas que se cursarán por ciclo.", "referencia_normativa": "Corresponde a la ''descripción detallada de la(s) forma(s) de administración y operatividad'' permitida en el Artículo 8 (párrafo tercero) del Acuerdo 17/11/17."}, "propuesta_de_evaluacion_periodica_del_plan_de_estudios": {"type": ["string", "null"], "title": "Propuesta de evaluación periódica del plan de estudios", "examples": ["Revisión quinquenal mediante encuestas a empleadores, egresados y análisis de tendencias del mercado."], "description": "Describir de manera detallada la metodología que emplearán para la evaluación del plan de estudios, incluyendo los instrumentos y periodicidad en la que se llevará a cabo; con la finalidad de mantenerlo actualizado y acorde a las necesidades educativas y disciplinares.", "referencia_normativa": "Corresponde al requisito ''Propuesta de evaluación periódica del Plan de estudio'' del Artículo 8, fracción VIII del Acuerdo 17/11/17."}, "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": {"type": "string", "title": "Nombre y cargo de la persona facultada para autorizar el plan de estudios", "examples": ["Dr. Juan Pérez Gómez, Rector de la Universidad XYZ"], "description": "Indicar el nombre y cargo de la persona facultada para autorizar el plan de estudios.", "referencia_normativa": "Dato administrativo del Anexo 1."}}, "additionalProperties": false}', '2026-01-09 13:45:37.784586+00', '2026-03-20 23:45:31.290918+00');
INSERT INTO "public"."planes_estudio" ("id", "carrera_id", "estructura_id", "nombre", "nivel", "tipo_ciclo", "numero_ciclos", "datos", "estado_actual_id", "activo", "tipo_origen", "meta_origen", "creado_por", "actualizado_por", "creado_en", "actualizado_en") VALUES
	('4660b774-a6e2-44f4-a340-747b41235c7c', '089cdeda-d557-4a57-b49f-eb44921dfa3a', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería en Sistemas Domóticos (2027)', 'Otro', 'Semestre', 9, '{"nivel": "Bachillerato", "nombre": "Especialización en Gravedad Cuántica de Bucles", "area_de_estudio": "Ciencias Físico-Matemáticas", "perfil_de_egreso": "La Specialización en Gravedad Cuántica de Bucles formará a un especialista capaz de integrar creativamente conocimientos avanzados en física, matemáticas y computación para enfrentar problemas teóricos y fenomenológicos en la intersección de la relatividad general y la mecánica cuántica. Al finalizar el programa, el egresado será capaz de: 1) Comprender y aplicar los fundamentos de la gravedad cuántica de bucles, incluyendo su formulación canónica, las variables de Ashtekar y el formalismo de redes de espín; 2) Desarrollar modelos y simulaciones rigurosas de fenómenos cuántico-gravitacionales, empleando métodos numéricos y herramientas de cómputo científico para analizar redes y espumas de espín, así como su relación con la cosmología cuántica; 3) Utilizar y conectar conceptos avanzados de geometría diferencial, teoría de grupos de Lie, representaciones y espinores para la construcción de estados cuánticos geométricos; 4) Resolver y comunicar de manera crítica problemas de frontera en física teórica contemporánea, integrando procesos de modelado matemático, análisis computacional y validación fenomenológica; 5) Evaluar y proponer soluciones innovadoras en entornos de trabajo colaborativo, mostrando habilidad para desarrollar proyectos científicos reproducibles bajo principios éticos y de buenas prácticas en la investigación; 6) Integrarse a comunidades científicas y continuar con estudios de posgrado o desempeñarse en entornos interdisciplinares que involucren física matemática, simulación, cosmología, información cuántica o modelado de sistemas complejos.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "El aspirante debe haber concluido el bachillerato con perfil Área 1 (Ciencias Físico-Matemáticas), lo que implica sólidas bases en matemáticas, física, química, razonamiento lógico y competencia en análisis de problemas. Se espera capacidad para el aprendizaje autónomo y familiaridad con herramientas y conceptos científicos y tecnológicos, así como interés en la resolución de problemas complejos y trabajo experimental.", "curso_propedeutico": "No tiene", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato en Ciencias Físico-Matemáticas, con orientación en matemáticas y física; requisito previo para ingreso a la especialización. El plan asume que el aspirante ha concluido un bachillerato con áreas de Ciencias Físico-Matemáticas.", "carga_horaria_a_la_semana": 27, "programa_de_investigacion": "No aplica", "clave_del_plan_de_estudios": "2020", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Analizar fundamentos de la gravedad cuántica de bucles y su relación con la relatividad general; Diseñar modelos computacionales para explorar redes de espín y espumas cuánticas, con enfoque en cosmología cuántica; Evaluar resultados numéricos mediante criterios de reproducibilidad y validación fenomenológica; Comunicar resultados científicos de forma clara, estructurada y técnica; Integrar conceptos de domótica, electrónica, control y sistemas computacionales mediante herramientas de simulación para proyectos interdisciplinarios y el desarrollo de asistentes virtuales; Aplicar herramientas de cómputo para la creación de proyectos con código reproducible y documentación adecuada; Desarrollar capacidades de trabajo en equipo, ética científica y buenas prácticas en investigación.", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "No aplica", "justificacion_de_la_propuesta_curricular": "No aplica", "administracion_y_operatividad_del_plan_de_estudios": "La administración y operatividad del plan de estudios se ubica bajo la Dirección de Asuntos Académicos - Anexo 1; modalidad escolar; estructura rígida con 9 ciclos; carga horaria semanal de 27 horas; responsable: Lic. María González Pérez, Directora Académica; procesos de revisión y actualización conforme a la Propuesta de Evaluación Periódica y a los lineamientos del Acuerdo 17/11/17.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Nivel de evaluación curricular interna: diagnóstico de estructura y operación. Análisis técnico-pedagógico del planteamiento curricular vigente; consulta a directivos del área académica para valorar problemáticas de formación y operación; consulta a docentes sobre problemáticas de formación, operación y necesidades disciplinarias; estudio de opinión de estudiantes sobre la formación y operación. Nivel de evaluación curricular externa: diagnóstico de impacto y prácticas profesionales. Análisis del estado del conocimiento en campos disciplinarios vinculados al programa, comparación de planes y tendencias en criterios de organismos evaluadores; estudio con egresados y empleadores para valorar inserción laboral y requerimientos actuales; recopilación de criterios y reformas necesarias para mantener el programa actualizado y acorde con la disciplina."}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "notasAdicionales": "Agrega a los asistentes virtuales", "descripcionEnfoque": "Carrera relacionada con la domótica, electrónica, control y sistemas computacionales"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 9812, "total_tokens": 19204, "output_tokens": 9392, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 8256}}, "responseId": "resp_0b1339b15ea08d51006973b4892a20819c954b7fe00a35e1ed", "conversationId": null}}', NULL, NULL, '2026-01-23 17:50:00.85346+00', '2026-01-23 22:00:33.119999+00'),
	('c90aebbb-454e-4a8e-b2a3-99dd1c200e86', '8208da08-d549-4359-8865-9d806bc54f19', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería en Cibernética y Ciberseguridad (2026)', 'Licenciatura', 'Semestre', 9, '{"nivel": "Licenciatura", "nombre": "Ingeniería Cibernética y Ciberseguridad", "area_de_estudio": "5. Ingeniería, manufactura y construcción (CMPE 2016)", "perfil_de_egreso": "Al finalizar, el egresado demostrará los siguientes atributos: Conocimientos Fundamentos de matemáticas, física y probabilidad aplicados a señales, control y comunicaciones. Arquitecturas de redes, sistemas operativos, virtualización, servicios en la nube e integración TI/OT. Modelado y control de sistemas ciberfísicos y embebidos, protocolos industriales e IoT. Criptografía aplicada, gestión de identidades, gobierno y gestión de seguridad de la información. Normativa y marcos de referencia: ISO/IEC 27001/27002, NIST CSF/800-53, MITRE ATT&CK, OWASP, ENS (referencial), legislación mexicana aplicable en protección de datos y delitos informáticos. Auditoría de seguridad, pruebas de penetración éticas, respuesta a incidentes y continuidad del negocio. Gestión de proyectos, economía de la ciberseguridad y ética profesional. HabilidadesDiseñar y desplegar arquitecturas seguras para redes, nube y sistemas ciberfísicos. Programar en C/C++, Python y scripts para automatización, pruebas y análisis. Configurar y operar firewalls, IDS/IPS, SIEM, WAF, VPN, segmentación y Zero Trust básico. Conducir análisis de riesgo, planes de tratamiento y auditorías técnicas y de cumplimiento. Orquestar procesos de detección, respuesta y recuperación ante incidentes. Desarrollar prototipos de IoT seguro y realizar hardening de dispositivos embebidos. Comunicar resultados técnicos mediante informes ejecutivos y presentaciones efectivas. Actitudes y valoresÉtica, responsabilidad social y legalidad en el manejo de información y en pruebas de seguridad. Aprendizaje autónomo y actualización permanente. Trabajo colaborativo, liderazgo y orientación a resultados. Respeto a la diversidad, perspectiva de género e inclusión.", "diseno_curricular": "Flexible", "perfil_de_ingreso": " ConocimientosMatemáticas de bachillerato: álgebra, funciones y trigonometría. Ofimática e informática básica; navegación segura en Internet. Inglés técnico básico (lectura de manuales). HabilidadesPensamiento lógico-matemático y resolución de problemas. Comunicación escrita y oral. Gestión del tiempo y aprendizaje autónomo. ActitudesInterés por la tecnología, la seguridad digital y la innovación. Ética, responsabilidad y respeto a la legalidad. Trabajo colaborativo y apertura al aprendizaje continuo.", "curso_propedeutico": "Aplicará cuando el diagnóstico de ingreso identifique brechas en matemáticas y programación. Población: aspirantes provenientes de bachilleratos no afines. Duración: 40 horas (4 semanas).  Contenidos: Aritmética y álgebra para ingeniería; pensamiento lógico; introducción a programación (Python); fundamentos de redes; ciudadanía digital y nociones de ciberseguridad.  Evaluación: examen criterio-referido (70% mínimo) y evidencias prácticas.  Vinculación: articulado con Programación I, Matemáticas I y Fundamentos de Redes.", "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato general o tecnológico concluido, o Técnico Superior Universitario equivalente, preferentemente en áreas físico-matemáticas, informática, electrónica o afines.", "carga_horaria_a_la_semana": 40, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2025", "duracion_del_ciclo_escolar": "18 semanas efectivas por ciclo semestral", "fines_de_aprendizaje_o_formacion": "El plan de estudios se orienta al desarrollo de competencias profesionales para diseñar, implementar y gestionar sistemas ciberfísicos y de ciberseguridad en organizaciones públicas y privadas, con enfoque de resultados y apego normativo. Al concluir, el egresado será capaz de: Analizar arquitecturas de sistemas ciberfísicos, redes y servicios para identificar riesgos, amenazas y vulnerabilidades. Diseñar estrategias de ciberseguridad basadas en estándares (ISO/IEC 27001, NIST, MITRE ATT&CK) y en principios de ingeniería segura. Implementar controles técnicos y administrativos, incluyendo criptografía aplicada, segmentación de redes, endurecimiento de sistemas y gestión de identidades. Programar y modelar sistemas embebidos y de IoT con prácticas de seguridad por diseño. Administrar infraestructuras de TI/OT y plataformas de monitoreo (SIEM, IDS/IPS) para la detección y respuesta a incidentes. Evaluar la conformidad normativa y el riesgo tecnológico mediante auditorías técnicas y de cumplimiento. Integrar metodologías de ciencia de datos e inteligencia artificial para la detección de anomalías y ciberamenazas. Simular, probar y validar el desempeño y la resiliencia de sistemas cibernéticos en entornos controlados (cyber range/laboratorios). Gestionar proyectos tecnológicos aplicando enfoques ágiles y de calidad, con perspectiva ética y de sostenibilidad. Comunicar hallazgos técnicos y recomendaciones a audiencias técnicas y directivas, sustentando decisiones con evidencia.", "total_de_ciclos_del_plan_de_estudios": "8 a 10 ciclos (semestres)", "sustento_teorico_del_modelo_curricular": "Se adopta un  modelo por competencias y resultados de aprendizaje, con base en: Constructivismo y aprendizaje situado para problemas reales.  Taxonomía de Bloom para progresión cognitiva. OBE/ABET para trazabilidad de resultados de programa-asignatura.  CDIO (Concebir-Diseñar-Implementar-Operar) en proyectos integradores. Evaluación auténtica mediante rúbricas y desempeño en laboratorios físicos y virtuales.", "justificacion_de_la_propuesta_curricular": "La  modalidad mixta combina sesiones presenciales/laboratorio y trabajo en línea para garantizar pertinencia, flexibilidad espacio-temporal y autogestión del aprendizaje. Plataformas tecnológicas: LMS institucional (p. ej., Moodle 4.x) con repositorio de contenidos, foros, cuestionarios, rúbricas y analítica; videoconferencia para sesiones sincrónicas; repositorios de código (Git) y laboratorios virtuales (simuladores de redes y ciberseguridad, sandboxes y máquinas virtuales) articulados con las asignaturas. Distribución horaria: 40-60% de horas bajo conducción (presencial o síncrona) y 60-40% de horas independientes (asíncronas) según la naturaleza de cada asignatura. Funcionalidad con instalaciones: laboratorios de redes, ciberseguridad e IoT; cyber range institucional; aulas de cómputo; todos con políticas de seguridad, bitácoras y control de acceso.  Estrategias de aprendizaje: aula invertida, aprendizaje basado en problemas/proyectos, retos de blue/red team, estudios de caso y simulaciones.  Evaluación: tareas prácticas en plataforma, laboratorios verificados, exámenes en línea con supervisión, presentaciones y defensa técnica.  Perfil docente: ingenierías afines con experiencia en TI/OT, certificaciones deseables (CCNA/Network Security, ISO 27001 LA/LI, CEH o equivalentes) y dominio de herramientas LMS.", "administracion_y_operatividad_del_plan_de_estudios": "El plan es de  diseño flexible con seriación académica por competencias y créditos. Se cursa en  8 a 10 semestres con un total referencial de  320 créditos (≥300 conforme al Art. 10). La operación académica considera: Carga por ciclo: de 5 a 7 asignaturas por semestre. Promedio semanal: 18-22 horas bajo conducción y 18-22 horas independientes (carga máxima 40 h/sem).  Modalidad mixta: al menos el 40% de las horas del programa son bajo conducción de un académico (≥960 h totales); el resto en actividades independientes mediadas por plataforma.  Seriación típica: Programación I → Programación II → Estructuras de Datos → Sistemas Operativos; Matemáticas I → Matemáticas II → Probabilidad y Estadística; Redes I → Redes II → Seguridad en Redes; Control I → Sistemas Embebidos → IoT Seguro.  Componentes de formación: básica (matemáticas, ciencias y programación), profesional (redes, sistemas, control, seguridad), terminal optativa (ciberdefensa, forense, nube, OT/SCADA), <i>Proyecto Integrador</i> y <i>Estancia/Residencia</i>.  Tutoría y asesoría: obligatoria el primer año y bajo demanda en cursos superiores.  Servicio social: 480 horas conforme a normativa aplicable.  Acreditación y titulación: por créditos y opción de titulación por examen general, proyecto aplicado, portafolio de evidencias o tesis.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "La evaluación del plan se realizará con una  periodicidad bienal y cortes anuales, mediante: Método: ciclo PDCA con evidencias OBE: mapeo resultados de programa-asignatura, rúbricas, portafolios y KPIs institucionales.  Instrumentos: encuestas a estudiantes y egresados, panel de empleadores, análisis de EGEL/EXANI (cuando aplique), analítica del LMS, informes de prácticas/residencias y auditorías académicas internas.  Indicadores: eficiencia terminal, tiempo de titulación, empleabilidad, resultados de aprendizaje, certificaciones profesionales obtenidas, producción de proyectos y patentes/prototipos.  Vinculación sectorial: Consejo Consultivo con industria (TI/OT, energía, manufactura, finanzas) para actualización de contenidos al menos cada 2 años.  Uso de resultados: actualización de programas, seriación y recursos didácticos; capacitación docente; adecuaciones a laboratorios y plataforma."}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"response_id": "lsadjf"}', NULL, NULL, '2026-01-09 21:48:48.404283+00', '2026-01-23 22:18:37.320091+00'),
	('ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', '089cdeda-d557-4a57-b49f-eb44921dfa3a', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería Mecatrónica (2026)', 'Licenciatura', 'Semestre', 9, '{"nombre_autorizado_de_la_institucion": "Agregando nuevos datos con persistencia"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "notasAdicionales": "", "descripcionEnfoque": "Dame un plan de estudios realista y enfocado en física médica"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 202327, "total_tokens": 209102, "output_tokens": 6775, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5696}}, "responseId": "resp_08633e9c3f0021c000697299eb9c2881a2a3bdc31d43c4bf0d", "conversationId": null}}', NULL, NULL, '2026-01-22 21:44:28.093643+00', '2026-01-29 21:58:12.447523+00'),
	('58e11252-0491-4b7d-8757-8793a6f60617', '170f14c6-1b9f-49a7-92f0-ccf79c41d750', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Licenciatura en Derecho Financiero', 'Licenciatura', 'Semestre', 9, '{"vigencia": "2026-2031", "area_de_estudio": "Derecho Financiero y Ciencias Jurídicas", "perfil_de_egreso": "El egresado de la Licenciatura en Derecho Financiero habrá adquirido una competencia integral para operar, regular y supervisar operaciones financieras institucionales. Conocimientos: dominio profundo de la normativa CNBV, AML/CTF, regulación de bancos, valores y almacenes de depósito; habilidades: análisis integral de estados contables, interpretación de marcos regulatorios y diseño de soluciones de cumplimiento; actitudes: ética profesional, responsabilidad social, capacidad de toma de decisiones y trabajo colaborativo en entornos multidisciplinarios.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "El aspirante debe presentar Bachillerato completo, preferentemente con orientación en Ciencias Sociales o Humanidades, con base en conocimientos de razonamiento lógico, matemáticas financieras y nociones básicas de derecho; se valora la experiencia de aprendizaje autónomo y la capacidad de lectura crítica, así como habilidades de comunicación oral y escrita para argumentación jurídica y financiera.", "curso_propedeutico": null, "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato general con orientación en Ciencias Sociales o equivalente; se requiere certificado de calificaciones y acreditación de aprobación de asignaturas clave como Historia, Economía, Matemáticas y Literatura; se consideran equivalencias académicas para estudiantes procedentes de sistemas educativos extranjeros.", "carga_horaria_a_la_semana": 18, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "LD-DF-2026-09", "duracion_del_ciclo_escolar": "18", "fines_de_aprendizaje_o_formacion": "Analizar marcos regulatorios CNBV y de valores; Aplicar principios contables y normativos a operaciones de bancos, valores y depósitos; Diseñar estructuras de gobierno corporativo y gestión de riesgos dentro de entidades financieras; Evaluar cumplimiento normativo, auditoría, control interno y reporting; Interpretar estados financieros, balances y flujos de efectivo para la toma de decisiones estratégicas; Implementar prácticas de supervisión y control de operaciones financieras; Comunicar hallazgos y recomendaciones a directivos, reguladores y partes interesadas.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Derecho Financiero", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "El sustento teórico del modelo curricular se apoya en fundamentos de diseño por competencias, constructivismo pedagógico y marcos de regulación financiera contemporánea. Se integra la contabilidad gerencial, la administración estratégica y las finanzas para desarrollar un profesional capaz de analizar, regular y gestionar entidades financieras, bancos, casas de bolsa y almacenes de depósito, con enfoque en ética, responsabilidad y sostenibilidad institucional.", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "La administración del plan se consolida mediante un comité académico responsable de la coordinación de cada bloque disciplinar y la supervisión de la carga horaria. En un diseño flexible se define un mínimo y máximo de asignaturas por ciclo, con control de avances a través de un sistema de gestión académica, portafolios y rúbricas. Se mantiene la coordinación entre Derecho, Contabilidad, Finanzas y Administración para garantizar la coherencia entre contenidos, prácticas y resultados de aprendizaje, así como la operación logística y tecnológica que sostiene el programa.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "La propuesta de evaluación periódica contempla revisión anual de indicadores de desempeño, análisis de resultados de aprendizaje por asignatura mediante rúbricas estandarizadas, retroalimentación de estudiantes, docentes y empleadores, y ajuste del plan de estudio en función de necesidades disciplinares y regulatorias. Se utilizarán mecanismos de calidad educativa, estadísticas de retención y satisfacción, así como auditorías internas para garantizar la vigencia y pertinencia del programa.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Los textos deben ser largos con una extensión de al menos de 100 caracteres", "descripcionEnfoqueAcademico": "Derecho financiero enfocado en las reglas de operación que dicta la comisión nacional bancaria y de valores para la creación de bancos, valores y almacenes de depósito, que incluya una parte de contabilidad, administración de empresas y finanzas."}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 3616, "total_tokens": 12863, "output_tokens": 9247, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 8320}}, "responseId": "resp_0c0739997e516d7200697d2e87677481938e30a85639df4894", "conversationId": null}}', NULL, NULL, '2026-01-30 22:21:06.594763+00', '2026-01-30 22:21:06.594763+00'),
	('49507442-ca7d-4489-b664-534321617950', '20593041-d605-4174-8404-4b152041eece', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Planecito', 'Maestría', 'Cuatrimestre', 6, '{}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'MANUAL', '{}', NULL, NULL, '2026-02-03 21:57:35.015+00', '2026-02-03 21:57:36.758601+00'),
	('f6280a08-226d-480b-ab67-561e4657bfc4', 'b56eb209-245d-4258-a6a7-9dcb1d231cb4', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería Económica y Financiera', 'Licenciatura', 'Semestre', 9, '{"nivel_y_nombre_del_plan_de_estudios": "x", "nombre_autorizado_de_la_institucion": "Unitec"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'MANUAL', '{}', NULL, NULL, '2026-01-30 14:33:50.818+00', '2026-02-05 16:12:47.680511+00'),
	('79fba458-aea4-4ca8-ab76-943ede479f15', 'b56eb209-245d-4258-a6a7-9dcb1d231cb4', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'prueba', 'Licenciatura', 'Semestre', 9, '{"nombre_autorizado_de_la_institucion": "x"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'MANUAL', '{}', NULL, NULL, '2026-01-30 14:44:48.312+00', '2026-02-05 16:12:56.768523+00'),
	('c5d80b6d-5d3d-4730-a4d5-8eaec3287910', '20593041-d605-4174-8404-4b152041eece', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Derecho', 'Licenciatura', 'Semestre', 10, '{"nivel_y_nombre_del_plan_de_estudios": "Lic", "nombre_autorizado_de_la_institucion": "CNCI"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'MANUAL', '{}', NULL, NULL, '2026-01-30 21:03:52.036+00', '2026-01-30 22:39:30.910126+00'),
	('26806567-c5ee-404e-8f90-0f0711c21ea0', '86a8d3ba-99fb-4e67-a03b-ce2c02d36db9', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Derecho Digital', 'Licenciatura', 'Semestre', 9, '{"vigencia": "2026-2031", "area_de_estudio": "Ciencias Sociales y Jurídicas", "perfil_de_egreso": "Conocimientos: fundamentos del derecho civil, mercantil, constitucional y administrativo; regulación de tecnologías de la información, protección de datos personales, propiedad intelectual y ciberseguridad.\nHabilidades: analizar, redactar, asesorar y litigar en entornos digitales; diseñar políticas de cumplimiento, contratos y términos de uso para plataformas; evaluar riesgos y gestionar cumplimiento normativo (compliance) en empresas tecnológicas.\nActitudes: ética profesional, pensamiento crítico, responsabilidad social, adaptabilidad y aprendizaje continuo ante cambios tecnológicos.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Conocimientos previos: nociones de derecho básico, cultura general y fundamentos de ética; habilidades: lectura crítica, redacción formal, argumentación y razonamiento lógico; aptitudes: capacidad de análisis, pensamiento estructurado, trabajo en equipo y comunicación efectiva; competencias tecnológicas básicas: manejo de herramientas ofimáticas, navegación segura, búsqueda de información y uso de plataformas de aprendizaje; condiciones para el ingreso: Bachillerato concluido y predisposición para el estudio presencial y el aprendizaje orientado a proyectos; se valorará interés por la regulación tecnológica y la protección de datos.", "curso_propedeutico": "Curso propedéutico para aspirantes con antecedentes no jurídicos; duración de 2 a 4 semanas; contenidos: introducción al derecho, terminología básica, fundamentos de tecnología y alfabetización digital; relación con el plan de estudios: orientación para la trayectoria semestral y acceso a la plataforma institucional.", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato concluido; para ingreso a Licenciatura en Derecho Digital.", "carga_horaria_a_la_semana": 20, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "DLD-LIC-DIG-2026", "duracion_del_ciclo_escolar": "18 semanas", "fines_de_aprendizaje_o_formacion": "Analizar fundamentos teóricos del derecho aplicados al entorno digital y a plataformas en línea; Aplicar normativas de protección de datos personales, privacidad y seguridad de la información en operaciones digitales; Diseñar contratos, políticas de uso y términos de servicio para plataformas y servicios digitales; Evaluar impactos éticos y sociales de la digitalización en derechos fundamentales y en prácticas empresariales; Elaborar políticas de privacidad, avisos de cookies, cláusulas de tratamiento de datos y estrategias de responsabilidad por datos; Proponer estrategias de cumplimiento normativo (compliance) para organizaciones tecnológicas y start-ups; Desarrollar habilidades de litigio, negociación y mediación en contextos de derecho digital; Integrar marcos nacionales e internacionales para la regulación de tecnologías emergentes.", "nivel_y_nombre_del_plan_de_estudios": "master", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "Fundamento teórico: modelo curricular basado en aprendizaje por competencias, con enfoque constructivista social y aprendizaje situado; se apoya en teorías de derecho, tecnología y ética; integra componentes de aprendizaje activo, proyectos de investigación y prácticas profesionales supervisadas; se apoya en marcos de calidad educativa y en la innovación pedagógica para educación superior; la selección de contenidos y experiencias formativas se orienta a la resolución de problemas reales en entornos digitales con énfasis en la integridad académica; el diseño curricular se coordina con la metodología del Acuerdo 17/11/17 para garantizar coherencia con el marco normativo.", "justificacion_de_la_propuesta_curricular": "La propuesta curricular responde a la necesidad de formar profesionales del derecho capaces de enfrentar los retos jurídicos derivados de la digitalización de servicios, comercio electrónico, plataformas digitales y relaciones laborales en entornos digitales; busca una formación integral, transversal y actualizada que combine fundamentos jurídicos con conocimiento específico en tecnología y datos; se alinea con el perfil institucional de la Universidad La Salle y con el Acuerdo 17/11/17; utiliza una estructura de semestres para facilitar la progresión de competencias y la articulación entre teoría y práctica; incorpora tecnologías y herramientas digitales, fomentando la autogestión del aprendizaje y la disponibilidad de recursos para estudios en modalidad escolar; se propone un enfoque práctico y prospectivo para fortalecer la empleabilidad de los egresados.", "administracion_y_operatividad_del_plan_de_estudios": "La gestión del plan de estudios estará a cargo del Departamento de Derecho Digital, con una Coordinación Académica y un Comité Curricular que supervisan la calidad y la actualización de las asignaturas; se define el calendario semestral, el plan de créditos y la distribución de asignaturas por ciclo; se implementa un sistema de gestión académica para registro de calificaciones y progresión, con controles de carga horaria y límites; se establece la tutoría y el acompañamiento académico; se define el proceso de homologación, cambios de asignaturas y criterios de permanencia; se contemplan recursos y servicios de apoyo estudiantil, bibliotecas especializadas y laboratorios de tecnología; se vigila el cumplimiento de políticas institucionales, de becas y movilidad; se garantiza la consistencia entre el plan de estudios y los objetivos de aprendizaje; se realizan revisiones periódicas para alinearlo con las necesidades del mercado y la evolución tecnológica.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Se implementará un ciclo de evaluación anual para verificar pertinencia, vigencia y efectividad; se utilizarán instrumentos como rúbricas de evaluación de asignaturas, indicadores de logro de competencias, resultados de exámenes y desempeño profesional; se recogerán encuestas a estudiantes, docentes y empleadores; se analizarán métricas de retención, titulación y inserción laboral; se emitirán informes y Planes de Mejora con acciones correctivas; se revisarán bibliografía y recursos tecnológicos; la revisión actualizará el plan de estudios cada cinco años en coherencia con cambios normativos y tecnológicos.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Estos textos deben de ser largos, concretos", "descripcionEnfoqueAcademico": "Este programa es un programa educativo que combina fundamentos jurídicos con conocimiento especializado en el entorno digital y tecnológico, abordando los retos legales derivados de la transformación digital en la sociedad con digitalización de servicios, comercios, relaciones laborales y comerciales, así como comunicaciones. Todos estos elementos aumentan el conflicto legales en el ámbito digital."}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 3627, "total_tokens": 16115, "output_tokens": 12488, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 11136}}, "responseId": "resp_0ce067d662cf90ce006989f70626b481938481e1a6b3b53299", "conversationId": null}}', NULL, NULL, '2026-02-09 15:04:15.579361+00', '2026-02-09 18:29:49.704132+00'),
	('6d1ad1d6-f34b-45fe-8b7c-3aef45d84901', 'e7b89d58-6b55-4993-a96f-bb4eb8c2eb88', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ciencias de la Educación (2026)', 'Licenciatura', 'Semestre', 9, '{"vigencia": "2026-2031", "area_de_estudio": "Educación", "perfil_de_egreso": "Conocimientos: fundamentos de educación, teorías didácticas, políticas públicas en educación, evaluación educativa, investigación educativa, ética profesional; Habilidades: diseño curricular y planificación de unidades didácticas; implementación de estrategias de enseñanza; uso de TIC; evaluación y retroalimentación; investigación educativa; liderazgo y gestión de proyectos; comunicación eficaz; trabajo colaborativo; Actitudes: ética profesional, inclusión y equidad, responsabilidad social, aprendizaje continuo, flexibilidad, valoración de la diversidad.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "Conocimientos previos en fundamentos de la educación, psicología del desarrollo y sociología de la educación; Habilidades: lectura crítica, escritura académica, comunicación oral, manejo básico de tecnologías; Aptitudes: interés por la docencia, responsabilidad, trabajo en equipo, adaptabilidad y pensamiento crítico.", "curso_propedeutico": "xxx", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato concluido; preferentemente en áreas de ciencias sociales, humanidades o educación; se valorará experiencia de servicio comunitario o educativa; para el ingreso se deben cumplir los requisitos institucionales de Universidad La Salle México.", "carga_horaria_a_la_semana": 22, "programa_de_investigacion": "xxx", "clave_del_plan_de_estudios": "PL-EDU-LAS-2026-CEDU", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Analizar enfoques y teorías de la educación para fundamentar prácticas pedagógicas en contextos educativos; Diseñar intervenciones curriculares, planes de evaluación y proyectos de desarrollo docente; Implementar estrategias de enseñanza y evaluación formativa para fomentar el aprendizaje profundo; Desarrollar materiales didácticos y recursos digitales accesibles para diversos contextos; Evaluar procesos de enseñanza-aprendizaje y resultados de aprendizaje para la mejora continua; Aplicar metodologías de investigación educativa para diagnosticar problemáticas y proponer soluciones.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ciencias de la Educación (2026)", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "El modelo curricular se fundamenta en un enfoque por competencias basado en el constructivismo sociocultural; incorpora aprendizaje basado en proyectos, prácticas docentes, evaluación auténtica y desarrollo de capacidades docentes; integra uso de tecnologías de la información y comunicación y principios de equidad e inclusión.", "justificacion_de_la_propuesta_curricular": "La propuesta curricular responde a la necesidad de formar docentes capaces de diseñar, implementar y evaluar procesos educativos de calidad, con atención a la diversidad, equidad y uso de tecnologías, en concordancia con el Acuerdo 17/11/17 y la orientación institucional de la Universidad La Salle México.", "administracion_y_operatividad_del_plan_de_estudios": "La administración del plan recae en la Dirección de la Facultad de Ciencias de la Educación, con apoyo del Comité Curricular. Se define un calendario académico por ciclo, manejo de créditos y requisitos de progresión, y un sistema de gestión académica para registrar asignaturas y resultados. Se establecen políticas de matrícula, asignación de docentes a asignaturas y evaluación institucional, con revisión semestral de indicadores de aprendizaje y planes de mejora.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Realizar evaluación anual del plan con indicadores de desempeño académico, retención y empleabilidad. Ejecutar revisión semestral de contenidos y estrategias didácticas para asegurar relevancia y actualidad. Documentar hallazgos y acciones de mejora para su implementación en el siguiente ciclo.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Genera un plan de estudios realista y detallado."}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 3567, "total_tokens": 15045, "output_tokens": 11478, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 10624}}, "responseId": "resp_0ca298e3df0fcf9300698519d9d4508197b20bf87ea630d208", "conversationId": null}}', NULL, NULL, '2026-02-05 22:31:19.285198+00', '2026-02-05 22:37:53.387433+00'),
	('05863c8a-2a93-42f9-a4b7-65cef2edfe72', '8f1ce751-949b-45dd-8e38-e10c64b077fd', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Licenciatura en Ingeniería de Tecnologías de Inmersión ', 'Licenciatura', 'Semestre', 9, '{"vigencia": "2026-2030", "area_de_estudio": "Ingeniería", "perfil_de_egreso": "La persona egresada habrá desarrollado un conjunto de conocimientos, habilidades y actitudes orientados a la ingeniería de tecnologías de inmersión. Conocimientos: fundamentos de matemáticas y física aplicadas a sistemas de interacción, fundamentos de programación, bases de datos, motores gráficos, diseño de interfaces y principios de usabilidad. Habilidades: diseñar, prototipar y evaluar soluciones de realidad virtual, realidad aumentada y simulaciones inmersivas; gestionar datos y APIs; integrar soluciones de backend con frontend para experiencias de inmersión; aplicar metodologías de desarrollo ágil y gestión de proyectos; comunicarse de forma efectiva en equipos multidisciplinarios. Actitudes: ética profesional, responsabilidad social, aprendizaje autónomo, trabajo en equipo y orientación a la mejora continua.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "Conocimientos previos: Bachillerato concl uido o su equivalente, preferentemente en áreas de ciencias, tecnología o ingeniería. Habilidades previas: razonamiento lógico, manejo básico de computación y lectura comprensiva. Aptitudes: interés por tecnologías de inmersión, creatividad, capacidad de trabajo en equipo y tolerancia a la ambigüedad en entornos de desarrollo.", "curso_propedeutico": null, "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato concluido o su equivalente, preferentemente en ciencias, tecnología o ingeniería. Se valorará experiencia previa en programación básica, diseño de interfaces o modelado 3D.", "carga_horaria_a_la_semana": 20, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "LIC-ITMI-2026", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Analizar fundamentos de matemáticas, física, informática y teoría de la interacción humano–computadora para resolver problemas de inmersión. Diseñar experiencias de inmersión (VR/AR) y interfaces de usuario adecuadas para diferentes plataformas y dispositivos. Desarrollar prototipos de tecnologías de inmersión utilizando motores gráficos y herramientas multimedia. Programar y gestionar bases de datos y APIs para aplicaciones de realidad aumentada y virtual. Evaluar rendimiento, usabilidad y seguridad de las soluciones mediante pruebas y rúbricas. Integrar conocimientos de frontend (diseño de interfaces) con tecnologías de inmersión para producir soluciones integrales.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura - Ingeniería de Tecnologías de Inmersión", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "El modelo curricular se fundamenta en competencias y aprendizaje basado en proyectos, con énfasis en experiencias de inmersión, uso de plataformas digitales y evaluación continua para articular teoría y práctica en tecnologías de VR/AR.", "justificacion_de_la_propuesta_curricular": "La propuesta curricular, en modalidad escolar, responde a la necesidad de formar profesionales capaces de diseñar y desarrollar soluciones de tecnologías de inmersión integrando bases de datos, programación y diseño frontend. La estructura modular y la distribución por semestres permiten progresión gradual, con contenidos alineados a las demandas de la industria y la academia, manteniendo enfoque práctico a través de proyectos y laboratorios.", "administracion_y_operatividad_del_plan_de_estudios": "La administración del plan será responsabilidad de la Dirección de Programas Académicos. El Comité Curricular coordinará las áreas de Ingeniería de Software y Tecnologías de la Inmersión. Cada semestre contará con un conjunto obligatorio de asignaturas y, cuando corresponda, asignaturas optativas para perfilización. Se utilizará la plataforma institucional para gestión de cursos, rúbricas y evaluaciones; se definirán mínimos y máximos de asignaturas por ciclo (p. ej., mínimo 6 y máximo 9) y se establecerán mecanismos de revisión y ajuste del plan.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Se implementará una evaluación periódica semestral del plan de estudios mediante rúbricas de competencia, portafolios de proyectos, evaluaciones prácticas y exámenes. Los resultados se analizarán en sesiones del Comité Curricular y se emitirán informes para la mejora continua, con fechas de revisión cada semestre.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Considera textos largos muy detallados, con palabras simples, sin tecnicismos ", "descripcionEnfoqueAcademico": "Una ingeniería para el desarrollo tecnológico de las tecnologías de inmersión, realidad virtual, realidad aumentada, motores gráficos, herramientas multimedia y otros elementos para integrar elementos de inmersión, adicionalmente deberá tener conocimiento de bases de datos, programación, diseño gráfico de frontend, y de las nuevas tecnologías de realidad virtual, realidad mixta de las diferentes plataformas existentes hoy en día."}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 3651, "total_tokens": 12222, "output_tokens": 8571, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 7488}}, "responseId": "resp_06ad21460230734c00698e66fccf6881a2b7218f123750b882", "conversationId": null}}', NULL, NULL, '2026-02-12 23:50:29.596563+00', '2026-02-12 23:50:29.596563+00'),
	('7ce9da1d-670a-4c28-91be-b6ed66a3b3ed', 'd8089840-c7ba-4e64-b073-d8d93092424f', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingenieria social', 'Licenciatura', 'Semestre', 8, '{"vigencia": "2026-2031", "area_de_estudio": "07 Ingeniería, manufactura y construcción", "perfil_de_egreso": "Conocimientos\n- Fundamentos de ciencias sociales: sociología, economía, ciencia política y psicología social.\n- Teoría de sistemas socio-técnicos, pensamiento sistémico y dinámica de sistemas aplicados a fenómenos sociales.\n- Métodos de investigación cuantitativa y cualitativa, estadística inferencial y análisis de datos.\n- Análisis de redes sociales, minería de datos y visualización de información para toma de decisiones públicas y privadas.\n- Diseño centrado en las personas, innovación pública, diseño de políticas y evaluación de impacto.\n- Gestión de proyectos, finanzas básicas para el sector social y marcos de colaboración intersectorial.\n- Normatividad aplicable en derechos humanos, protección de datos personales, ética e integridad pública.\n- Tecnologías habilitadoras para la intervención social: plataformas cívicas, sistemas de información geográfica y herramientas colaborativas.\n\nHabilidades\n- Diagnosticar problemáticas complejas mediante recolección, integración y análisis de datos de múltiples fuentes.\n- Modelar escenarios y simular alternativas de intervención con base en evidencia y criterios de costo-beneficio social.\n- Diseñar, prototipar e implementar intervenciones, programas y políticas con enfoque participativo y centrado en el usuario.\n- Evaluar procesos y resultados con metodologías rigurosas (RCT, cuasi-experimentos, evaluación costo-efectividad y teoría del cambio).\n- Gestionar proyectos multiactor con planeación, presupuestación, monitoreo y comunicación eficaz de resultados.\n- Integrar tecnologías digitales y analíticas para potenciar la incidencia y la transparencia de las intervenciones.\n- Comunicar hallazgos técnicos a audiencias no especializadas y facilitar procesos deliberativos y de cocreación.\n- Liderar equipos interdisciplinarios con orientación a resultados, mejora continua y aprendizaje organizacional.\n\nActitudes y valores\n- Compromiso ético con la dignidad humana, la protección de datos y la no discriminación.\n- Responsabilidad social, servicio a la comunidad y sostenibilidad alineada a los ODS.\n- Pensamiento crítico, apertura al cambio y aprendizaje autónomo permanente.\n- Empatía intercultural, trabajo colaborativo y resolución pacífica de conflictos.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Conocimientos\n- Aritmética, álgebra y nociones de geometría analítica; manejo básico de estadística descriptiva.\n- Comprensión lectora y redacción académica en español; nivel de inglés recomendado B1 para lectura técnica.\n- Cultura general en ciencias sociales (historia, civismo, economía básica) y actualidad nacional.\n\nHabilidades\n- Razonamiento lógico-matemático y manejo básico de hojas de cálculo.\n- Búsqueda y selección de información fiable; organización del tiempo y autogestión del estudio.\n- Comunicación oral y escrita; trabajo colaborativo.\n\nAptitudes\n- Interés por la resolución de problemas públicos y sociales con enfoque interdisciplinario.\n- Disposición para el trabajo de campo y el trato respetuoso con comunidades diversas.\n- Actitud ética, responsable y orientada al servicio.", "curso_propedeutico": "Objetivo\n  Nivelar saberes clave para el primer año de la licenciatura.\n\nAplicación\n- Dirigido a aspirantes con resultados por debajo del umbral establecido en el diagnóstico de ingreso.\n- Modalidad presencial con apoyo virtual.\n\nDuración y contenidos\n- 40 horas totales distribuidas en 2 semanas previas al inicio del semestre.\n- Módulos: Matemáticas para las ciencias sociales, Introducción a la estadística con hojas de cálculo, Redacción académica y citación, Alfabetización digital y datos.\n\nVinculación con el plan de estudios\n- Asegura el logro de prerrequisitos para Matemáticas aplicadas a lo social, Métodos de investigación I y Pensamiento sistémico.\n\nEvaluación\n- Examen de salida y evidencias prácticas; quienes no acrediten cursarán tutorías obligatorias en el primer semestre.", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato o equivalente. Preferentemente con formación en áreas físico-matemáticas, económico-administrativas o ciencias sociales.", "carga_horaria_a_la_semana": 32, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2026", "duracion_del_ciclo_escolar": "18", "fines_de_aprendizaje_o_formacion": "- Analizar fenómenos sociales complejos mediante marcos teóricos interdisciplinarios y datos empíricos.\n- Diagnosticar problemas públicos y privados identificando causas, actores, incentivos y restricciones.\n- Diseñar intervenciones y políticas con enfoque centrado en las personas, equidad y sostenibilidad.\n- Modelar escenarios y simular alternativas de acción utilizando herramientas cuantitativas y cualitativas.\n- Implementar proyectos socio-técnicos articulando procesos, tecnologías y gobernanza colaborativa.\n- Evaluar resultados e impacto con criterios de validez, confiabilidad y costo-efectividad.\n- Gestionar recursos, riesgos y calidad en proyectos con metodologías ágiles y de mejora continua.\n- Integrar tecnologías de información, análisis de datos y visualización para soportar la toma de decisiones.\n- Comunicar hallazgos y recomendaciones a audiencias diversas con claridad, ética y evidencia.\n- Actuar con responsabilidad social, apego a la normatividad y respeto a los derechos humanos.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ingeniería Social", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "8", "sustento_teorico_del_modelo_curricular": "Enfoque y principios\n- Modelo por competencias profesionales integrales que articula saberes conceptuales, procedimentales y actitudinales.\n- Enfoque socio-técnico y de sistemas, fundamentado en pensamiento sistémico, teoría de redes y dinámica de sistemas.\n- Metodologías activas: aprendizaje basado en problemas y proyectos, estudio de casos, aprendizaje-servicio e investigación formativa.\n- CDIO adaptado al ámbito social (Concebir, Diseñar, Implementar, Operar) para ciclos iterativos de intervención y evaluación.\n- Enfoque de derechos humanos, ética de datos y diseño centrado en las personas como ejes transversales.\n\nArticulación curricular\n- Trayectorias por fases: fundamentos (1.º-2.º), profundización metodológica (3.º-4.º), especialización y práctica (5.º-6.º), integración y transferencia (7.º-8.º).\n- Integración de laboratorios de datos sociales, talleres de intervención y clínicas de proyectos para vincular teoría-práctica.\n- Tutoría académica y proyectos integradores semestrales como evidencia auténtica de logro de competencias.\n\nEvaluación del aprendizaje\n- Evaluación criterial y auténtica mediante rúbricas, portafolios, productos de proyecto, reportes técnicos y presentaciones públicas.", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "Estructura y organización\n- Diseño curricular rígido de 8 semestres, cada uno con 18 semanas efectivas.\n- Carga estándar: 5 a 6 asignaturas por semestre para un máximo de 32 horas/semana bajo conducción docente.\n- Secuenciación con prerrequisitos claros entre núcleos: fundamentos, métodos, tecnologías y práctica profesional.\n\nCréditos y horas\n- Un crédito académico equivale a 16 horas de trabajo bajo conducción docente o su combinación con trabajo independiente, conforme a lineamientos institucionales.\n- Total referencial del plan: 320-340 créditos, distribuidos proporcionalmente por semestre.\n\nComponentes obligatorios\n- Proyecto integrador semestral con problema real, evidencias de análisis, diseño, implementación y evaluación.\n- Servicio Social: 480 horas conforme a la normatividad aplicable, a partir del 5.º semestre.\n- Prácticas profesionales: mínimo 300 horas en organizaciones públicas, privadas o del tercer sector, del 6.º al 8.º semestre.\n- Acreditación de competencia en inglés equivalente a B1 para egreso (lectura de textos técnicos).\n\nGestión académica\n- Comité de Trayectorias para autorizar cargas atípicas, reinscripciones y apoyos académicos.\n- Tutoría académica obligatoria los dos primeros semestres; opcional a partir del tercero.\n- Cursos intersemestrales optativos para nivelación o aceleración del avance.\n- Plataforma institucional para gestión de cursos, portafolios y seguimiento de evidencias.\n\nCriterios de permanencia y egreso\n- Promedio mínimo de 7.0; máximo de 12 semestres para concluir.\n- Cumplimiento de créditos, prácticas, Servicio Social, proyecto terminal y examen de egreso institucional.\n\nVinculación\n- Convenios con dependencias públicas, OSC y empresas para estancias, retos y proyectos con datos abiertos y casos reales.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Objetivo\n  Mantener la pertinencia, calidad y actualización del plan frente a cambios científicos, tecnológicos y sociales.\n\nMetodología\n- Evaluación continua anual: análisis de indicadores académicos (ingreso, egreso, eficiencia terminal, reprobación, empleabilidad) y resultados de proyectos integradores.\n- Evaluación bienal integral: revisión curricular por Comité Académico con participación de docentes, estudiantes, egresados y empleadores.\n- Evaluación externa cada 4 años: pares académicos y consejo asesor del sector social y público.\n\nInstrumentos\n- Rúbricas de competencias, encuestas de satisfacción, grupos focales, portafolios digitales, trazadores de egresados y análisis de impacto de prácticas.\n- Tablero de indicadores con metas y umbrales de alerta; registros de mejora continua (PDCA) por asignatura y por línea de formación.\n\nResultados y mejora\n- Planes de acción con responsables, recursos y cronograma; seguimiento semestral y reporte público de avances.\n- Actualización de contenidos y bibliografía; ajuste de secuencias y horas; incorporación de tecnologías y casos emergentes.\n\nPeriodicidad y registro\n- Informes anuales al Consejo Académico; actualización formal del plan cuando las variaciones superen 20% de contenidos o cambien resultados de aprendizaje clave.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Mtro. Carlos Eduardo Ramírez Ortega, Secretario Académico"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Crea una plan realista de una ingenieria social"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-2025-08-07", "usage": {"input_tokens": 3781, "total_tokens": 8801, "output_tokens": 5020, "input_tokens_details": {"cached_tokens": 3584}, "output_tokens_details": {"reasoning_tokens": 2688}}, "responseId": "resp_0666f0f22a51de140069972898cc28819fa991aa844c35ac84", "conversationId": null}}', NULL, NULL, '2026-02-19 15:15:23.278047+00', '2026-02-19 15:15:23.278047+00'),
	('602c379a-462c-4e9d-bfc7-a11cfda0e436', '73f639f2-71a7-4313-ac21-23420eb6f738', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Licenciatura en Arquitectura Ligera y de bajo costo', 'Licenciatura', 'Semestre', 9, '{"vigencia": "Ciclo 2026-2027", "area_de_estudio": "Arquitectura y construcción", "perfil_de_egreso": "Al concluir la Licenciatura en Arquitectura Ligera y de bajo costo, el egresado habrá desarrollado los siguientes atributos, alineados con un enfoque por competencias, sustentabilidad, pertinencia social y dominio de tecnologías aplicadas a construcciones ligeras.\n\nConocimientos\n- Fundamentos de arquitectura: historia, teoría, ética, habitabilidad, normativa urbana y edificación en México (RCDF y NTC aplicables).\n- Sistemas estructurales ligeros: tensoestructuras, membranas, mallas y cubiertas espaciales, cáscaras delgadas, estructuras neumáticas e inflables, marcos y retículas en acero ligero (LSF), madera laminada (CLT/GLT) y materiales compuestos (FRP).\n- Tecnología y materiales: maderas y bambú estructural, aceros galvanizados de bajo espesor, polímeros y textiles técnicos, paneles sándwich, sistemas modulares y prefabricados, uniones mecánicas y anclajes especializados.\n- Diseño ambiental y bioclimático para arquitecturas ligeras: asoleamiento, ventilación, sombreamiento, confort térmico pasivo, envolventes textiles y reflectivas, y eficiencia energética.\n- Métodos de análisis y simulación: modelado BIM, diseño paramétrico (Rhinoceros/Grasshopper), análisis estructural básico con elementos finitos, evaluación de desempeño térmico y lumínico.\n- Gestión de costos y productividad: estimación y control de costos para vivienda de bajo costo, optimización de materiales, prefabricación, logística y montaje en obra seca.\n- Sustentabilidad y economía circular: análisis de ciclo de vida (ACV), huella de carbono de materiales y sistemas, estrategias de desmontaje, reuso y reciclabilidad.\n- Planeación y producción: prefabricación ligera, ensamblaje in situ, estandarización y control de calidad, seguridad y salud en el montaje.\n- Intervención social: vivienda progresiva, soluciones para emergencia y resiliencia, participación comunitaria, perspectiva de género e interculturalidad en el hábitat.\n\nHabilidades\n- Formular y desarrollar proyectos arquitectónicos ligeros, desde la conceptualización hasta la documentación ejecutiva, con énfasis en eficiencia material y constructiva.\n- Dimensionar preliminarmente sistemas ligeros y coordinar el trabajo con especialistas estructurales para su validación técnica y normativa.\n- Modelar información del edificio (BIM) e integrar parámetros de costo, tiempo y sostenibilidad (4D/5D/6D) para la toma de decisiones.\n- Simular el comportamiento estructural y ambiental a nivel conceptual, iterando soluciones mediante diseño paramétrico.\n- Gestionar obra ligera: planeación, abastecimiento, prefabricación, montaje seguro, supervisión y control de calidad.\n- Comunicar eficazmente ideas de diseño mediante croquis, maquetas físicas, prototipos a escala, modelos digitales y documentación técnica.\n- Conducir procesos participativos con comunidades y actores clave para asegurar pertinencia social y cultural del proyecto.\n- Elaborar presupuestos y análisis costo-beneficio para soluciones de bajo costo, justificando desempeño y viabilidad.\n\nActitudes y valores\n- Compromiso social con el derecho a la vivienda digna, accesible y resiliente, con enfoque de inclusión y reducción de desigualdades.\n- Ética profesional, responsabilidad ambiental y seguridad en obra, priorizando el bienestar de usuarios y trabajadores.\n- Innovación, pensamiento crítico y apertura a la experimentación con materiales y procesos constructivos ligeros.\n- Trabajo colaborativo, liderazgo y gestión interdisciplinaria en proyectos con múltiples actores.\n- Autogestión del aprendizaje, actualización continua y apego a normatividad y estándares técnicos vigentes.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Se considera idóneo el aspirante que cumpla con las siguientes condiciones académicas y aptitudes:\n\nConocimientos\n- Matemáticas básicas (álgebra, trigonometría y geometría analítica) aplicadas a problemas físicos elementales.\n- Física básica (mecánica, estática, nociones de fuerzas y equilibrio) a nivel bachillerato.\n- Historia y apreciación del arte y la arquitectura a nivel introductorio.\n\nHabilidades\n- Razonamiento lógico-matemático y pensamiento espacial.\n- Dibujo a mano alzada y capacidad de representación gráfica básica.\n- Manejo elemental de herramientas digitales (ofimática) y disposición para aprender software de modelado.\n- Comunicación oral y escrita en español; lectura técnica de comprensión en inglés (básico-intermedio).\n\nActitudes y aptitudes\n- Interés por el hábitat social, la sostenibilidad y la innovación técnica.\n- Trabajo colaborativo, disciplina, organización del tiempo y resiliencia ante procesos de crítica y mejora del proyecto.\n- Sensibilidad social y respeto a la diversidad cultural.\n\nCondición académica mínima\n- Haber concluido el bachillerato o equivalente (preferente: área físico-matemática, técnico en construcción o dibujo).", "curso_propedeutico": "Aplicará para aspirantes con antecedentes no afines o con brechas en matemáticas, física o representación gráfica.\nDuración: 40 horas (2 semanas previas al inicio del primer semestre).\nContenido: regularización en álgebra y trigonometría para estática, fundamentos de dibujo técnico, croquis y lectura de planos; introducción a modelado 2D (AutoCAD) y nociones de materiales y sistemas ligeros.\nRelación con el plan: fortalece el desempeño en Taller I, Geometría Descriptiva y Fundamentos de Estructuras.\nEvaluación: diagnóstico inicial y evaluación sumativa (aprobatoria ≥ 80/100).", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato concluido o equivalente (preferente en área físico-matemática o técnico en construcción/dibujo).", "carga_horaria_a_la_semana": 36, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "ARQ-LIG-2026", "duracion_del_ciclo_escolar": "18 semanas", "fines_de_aprendizaje_o_formacion": "- Analizar contextos urbanos y comunitarios para identificar necesidades habitacionales y de infraestructura ligera con criterios de pertinencia social y ambiental.\n- Diseñar soluciones arquitectónicas ligeras y de bajo costo que optimicen recursos materiales y energéticos, asegurando desempeño y seguridad.\n- Modelar digitalmente (BIM y diseño paramétrico) proyectos ligeros, integrando criterios de costo, tiempo y sostenibilidad en el ciclo de vida.\n- Evaluar alternativas de sistemas estructurales ligeros mediante criterios de resistencia, estabilidad, montaje, mantenimiento y desmontaje.\n- Aplicar principios bioclimáticos y de eficiencia energética en el diseño de envolventes ligeras para mejorar el confort ambiental.\n- Gestionar procesos de prefabricación, logística y montaje de obras ligeras, priorizando seguridad, calidad y economía de medios.\n- Integrar la normatividad aplicable (RCDF, NTC Estructurales CDMX, NMX e ISO pertinentes) en el desarrollo del proyecto ejecutivo.\n- Optimizar costos y consumos de materiales mediante análisis comparativos, presupuestos y estrategias de economía circular.\n- Documentar técnica y gráficamente los proyectos, garantizando trazabilidad, especificaciones y manuales de montaje y mantenimiento.\n- Vincular procesos participativos con usuarios y actores locales para co-diseñar soluciones habitacionales resilientes y culturalmente adecuadas.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Arquitectura Ligera y de bajo costo", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "El plan de estudios se fundamenta en un enfoque por competencias, con base constructivista y aprendizaje situado, articulado a través del modelo de Taller de Arquitectura como eje integrador. Se emplean estrategias de aprendizaje basado en proyectos (ABP), aprendizaje basado en problemas, diseño-réplica y prototipado, con integración transversal de sustentabilidad, ética profesional y pertinencia social.\n\nSe adoptan marcos contemporáneos para el desarrollo de habilidades en arquitectura ligera: diseño paramétrico, modelado de información del edificio (BIM) y simulación conceptual de desempeño (estructural y ambiental). La formación se alinea con criterios internacionales de sostenibilidad (ODS 11, economía circular y análisis de ciclo de vida), y con la normatividad nacional aplicable (RCDF, NTC Estructurales CDMX y normas NMX/ISO pertinentes), favoreciendo soluciones de bajo costo, de rápida implementación y alta eficiencia material.\n\nLa estructura incluye un tronco común en arquitectura (1.º a 3.º semestre) para garantizar bases sólidas en diseño, representación, tecnología, historia y normativa. A partir del 4.º semestre se profundiza en la línea de construcciones ligeras: sistemas tensados y neumáticos, madera y bambú estructural, acero ligero, panelería y obra seca, prefabricación, montaje y evaluación de ciclo de vida. El resultado es una progresión formativa de la idea al desempeño, con proyectos integradores y prácticas en contextos reales.", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "Tipo de ciclo: semestral de 18 semanas efectivas, con 36 horas semanales máximas bajo conducción académica.\nEstructura: 9 semestres en diseño curricular rígido con eje vertical de Taller de Arquitectura. Tronco común en arquitectura general de 1.º a 3.º; especialización en arquitectura de construcciones ligeras de 4.º a 9.º.\n\nOrganización académica\n- Asignaturas por semestre: entre 6 y 7, combinando Taller (alto peso práctico), representación, tecnología, teoría-historia y gestión.\n- Secuenciación y prerrequisitos: los Talleres son seriados (Taller I → IX); cursos de estructuras, materiales y representación funcionan como co-requisitos clave del Taller en cada nivel.\n- Integración transversal: sustentabilidad, normatividad y seguridad se abordan en todos los niveles; el uso de BIM y diseño paramétrico es progresivo desde 2.º semestre.\n- Componentes prácticos: laboratorios de materiales y prototipado, maquetas a escala, ensayos de uniones y pruebas de montaje; estancias en obra y visitas técnicas.\n- Vinculación: proyectos con comunidades, ONG, dependencias públicas y empresas de sistemas ligeros; elaboración de prototipos a escala 1:1 cuando sea pertinente.\n\nTrayecto formativo\n- 1.º a 3.º (tronco común): fundamentos de diseño, representación 2D/3D, geometría descriptiva, historia y teoría, construcción básica, física y estática, normativa, introducción a BIM.\n- 4.º a 6.º (especialización intermedia): sistemas ligeros (tensados, mallas, neumáticos), madera/bambú, acero ligero, envolventes bioclimáticas, prefabricación y obra seca, diseño paramétrico aplicado y estimación de costos.\n- 7.º a 8.º (profundización y práctica): residencia profesional supervisada (mín. 320 horas), gestión de obra ligera, control de calidad, LCA/huella de carbono, proyectos en contexto real y servicio social (mín. 480 horas conforme a normativa estatal/federal aplicable).\n- 9.º (síntesis): Proyecto Terminal Integrador en arquitectura ligera y de bajo costo, con expediente ejecutivo, modelado BIM 5D/6D, prototipo o secciones a escala 1:1, manuales de montaje y mantenimiento.\n\nEvaluación del aprendizaje\n- Evaluación continua con rúbricas: avances de Taller (concepto, desarrollo, desempeño, documentación), prácticas de laboratorio, entregables BIM/paramétricos y evidencias de costos/sustentabilidad.\n- Evaluaciones parciales (2) y una final por semestre; ponderaciones alineadas al perfil de la asignatura (Taller con mayor peso).\n- Asistencia mínima: 80% en actividades presenciales de Taller y laboratorios.\n\nGestión académica\n- Tutoría académica semestral y seguimiento de trayectoria escolar.\n- Comité de Taller para coherencia vertical de proyectos y estándares de evaluación.\n- Seguridad y salud: lineamientos para manejo de herramientas, montaje de prototipos y visitas a obra, con inducción obligatoria.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Metodología de mejora continua en ciclos bianuales con revisión intermedia anual.\n\nEstructura y responsables\n- Comité de Evaluación Curricular (CEC): director(a) de programa, coordinadores de áreas (diseño, tecnología, teoría, gestión), representantes docentes, estudiantes y vinculación.\n\nInstrumentos y evidencias\n- Matriz de alineación curricular (perfil de egreso ↔ asignaturas ↔ resultados de aprendizaje ↔ evaluación).\n- Análisis de indicadores: eficiencia terminal, reprobación por unidad de aprendizaje, inserción laboral, participación en proyectos reales y certificaciones de software.\n- Portafolio de evidencias de Taller (niveles clave: 3.º, 6.º y 9.º), con revisión por pares externos.\n- Encuestas de satisfacción de estudiantes y empleadores; panel anual con expertos de la industria (sistemas ligeros, prefabricación, materiales).\n- Seguimiento de egresados (12, 24 y 36 meses) y estudio de pertinencia regional.\n\nPeriodicidad y decisiones\n- Revisión anual de resultados con plan de acción y responsables; ajuste menor de programas analíticos y bibliografía.\n- Revisión bianual para actualización de tecnologías (BIM, paramétrico, nuevos materiales), normatividad y contenidos de sostenibilidad (ACV/huella de carbono).\n- Evaluación cuatrienal integral con asesoría externa para rediseño mayor si procede.\n\nDifusión y control\n- Informe público resumido y actas del CEC; control documental de versiones de programas y rúbricas; calendario de capacitación docente asociado a hallazgos.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Mtra. Ana Sofía Hernández Ruiz, Vicerrectora Académica"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Considera que tendrá un troco común con arquitectura, sin embargo al 4to semestre se separará en arquitectura de construcciones ligeras, considera que toda la información debe ser detallada", "descripcionEnfoqueAcademico": "Construye toda la información de manera detallada y que utilice todos los conceptos de las construcciones ligeras"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-2025-08-07", "usage": {"input_tokens": 3836, "total_tokens": 9510, "output_tokens": 5674, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 2496}}, "responseId": "resp_0db128ae746783b00069986b19e77c81979d73d83b65f38517", "conversationId": null}}', NULL, NULL, '2026-02-20 14:11:22.365956+00', '2026-02-20 14:11:22.365956+00'),
	('dc286072-c649-43aa-8a2f-aa3ef6166647', '991edcde-b77e-4d22-b76b-3bf6ec3d3555', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Químico Farmacéutico Biólogo (2026)', 'Licenciatura', 'Semestre', 8, '{"vigencia": "Por determinar por la autoridad educativa", "area_de_estudio": "07 Salud (CMPE 2016). Campo de formación específico: Química Farmacéutica, Farmacotecnia, Cosmética y Perfumería (con énfasis en análisis instrumental, regulación y seguridad sanitaria).", "perfil_de_egreso": "Conocimientos\n- Fundamentos de química general, analítica, orgánica, bioquímica, fisicoquímica y microbiología, con énfasis en su aplicación a farmacotecnia y cosmética.\n- Estructura, reactividad y síntesis de compuestos orgánicos y aromáticos, aceites esenciales, aromaquímicos y moléculas odorantes relevantes para perfumería.\n- Tecnología farmacéutica y de cosméticos: formas farmacéuticas, sistemas de liberación, excipientes, procesos unitarios, escalamiento y control de procesos.\n- Métodos instrumentales (GC-MS, HPLC/UPLC, IR, UV-Vis, GC-O, cromatografía preparativa) aplicados al análisis de fragancias, cosméticos y medicamentos.\n- Evaluación sensorial, psicofísica del olfato, diseño de paneles, estadística sensorial y técnicas descriptivas/hedónicas aplicadas a fragancias.\n- Gestión de la calidad, Buenas Prácticas de Manufactura (BPM/BPF: NOM, ISO 22716), validación de métodos, metrología y aseguramiento de la calidad.\n- Legislación sanitaria y regulatoria: marco COFEPRIS, NOM aplicables a cosméticos y perfumes, lineamientos IFRA, etiquetado, seguridad del consumidor y dossier técnico.\n- Toxicología, seguridad química, evaluación de riesgo, higiene y bioseguridad en laboratorios y plantas.\n\nHabilidades\n- Formular, optimizar y escalar fragancias finas y productos cosméticos fragranciados, así como formas farmacéuticas sólidas, semisólidas y líquidas.\n- Diseñar y validar métodos analíticos para identificación, cuantificación y control de calidad de ingredientes aromáticos, materias primas y productos terminados.\n- Aplicar diseño de experimentos (DoE), análisis multivariante y herramientas quimiométricas para optimización sensorial y de desempeño.\n- Evaluar estabilidad físico-química, fotoestabilidad, compatibilidad envase-producto y desempeño sensorial en condiciones aceleradas y reales.\n- Operar, calibrar y mantener equipos de laboratorio y planta piloto, asegurando trazabilidad de mediciones y cumplimiento de BPF/BPM.\n- Gestionar sistemas de calidad, documentación técnica (POE, AMEF, PNO), auditorías internas y externas, y liberación de lotes.\n- Integrar conocimientos de mercadotecnia olfativa y tendencias del mercado para alinear el desarrollo de fragancias a perfiles de consumidor y normatividad.\n- Comunicar resultados técnicos mediante reportes, presentaciones y defensa de proyectos ante audiencias técnicas y no técnicas en español e inglés.\n\nActitudes y valores\n- Ética profesional, responsabilidad sanitaria y compromiso con la seguridad del consumidor y la protección ambiental.\n- Pensamiento crítico, innovación y mejora continua con enfoque de sostenibilidad y química verde.\n- Trabajo colaborativo, liderazgo técnico, gestión del tiempo y orientación a resultados en contextos multidisciplinarios e interculturales.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "Conocimientos\n- Matemáticas: álgebra, trigonometría y nociones de cálculo diferencial.\n- Ciencias básicas: química general y orgánica básica, biología celular y microbiología introductoria, física (mecánica y termodinámica) básicas.\n- Comprensión lectora en español e inglés técnico (nivel A2-B1). \n\nHabilidades\n- Razonamiento lógico-matemático y manejo de operaciones algebraicas aplicadas a problemas de química.\n- Competencias básicas de laboratorio: manejo de material volumétrico, seguridad e higiene, preparación de soluciones, registro en bitácora.\n- Uso básico de TIC: hoja de cálculo, procesador de texto, gestor de referencias y plataformas institucionales.\n\nActitudes y aptitudes\n- Disciplina, perseverancia y atención al detalle.\n- Disposición para el trabajo en laboratorio y para el aprendizaje autónomo.\n- Conducta ética, responsabilidad y apertura al trabajo en equipo.", "curso_propedeutico": "Propuesta de curso propedéutico (40–60 h; 2–3 semanas previas al inicio del programa). Población objetivo: aspirantes sin antecedentes en bachillerato químico-biológico o con rezago en ciencias básicas. Objetivos: nivelar competencias en química, matemáticas, seguridad en laboratorio y fundamentos de perfumería; facilitar la transición al plan de estudios y reducir brechas de aprendizaje. Módulos propuestos (con distribución horaria sugerida):\n- Química general y fundamentos de análisis (12 h teoría + 8 h prácticas).\n- Matemáticas para ciencias (12 h teoría + 8 h prácticas).\n- Habilidades de laboratorio y bioseguridad (8 h teoría + 8 h prácticas).\n- Inducción a perfumería y ética (4 h teoría).\n- Competencias digitales y manejo de plataformas institucionales (4 h teoría).\n- Taller de lectura de textos técnicos en español e inglés básico (aleatoriamente integrado, 4 h).\nResultados de aprendizaje esperados: LO1–LO4 (dominio de conceptos básicos de química y matemáticas, competencia en seguridad y buenas prácticas de laboratorio, comprensión básica de perfumería y ética, habilidad para registrar y presentar evidencias de aprendizaje). Evaluación: diagnóstico inicial (pre-test), evaluaciones formativas durante el curso y evaluación final (prueba teórico-práctica o portafolio). Criterios de aprobación: mínimo 80% de asistencia y puntuación aprobatoria en las evaluaciones (generación de bitácora y evidencias). Modalidad: presencial con apoyo de recursos digitales y simuladores cuando sea posible. Requisitos de acreditación: certificación de haber cumplido prácticas y comprendido fundamentos, con registro en el historial académico. Alineación: al finalizar, el estudiante debe presentar evidencia de dominio en química/ matemáticas básicas, seguridad en laboratorio y conceptos introductorios de perfumería para facilitar el rendimiento en las asignaturas del plan.", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato general concluido, preferentemente con orientación químico-biológica o de ciencias de la salud; o bachillerato tecnológico afín (p. ej., Técnico Laboratorista Químico). Presentar certificado de estudios conforme a la normativa vigente.", "carga_horaria_a_la_semana": 34, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "ULSM-QFB-2026", "duracion_del_ciclo_escolar": "18 semanas", "fines_de_aprendizaje_o_formacion": "- Analizar la estructura, propiedades y reactividad de compuestos orgánicos, aromáticos y biomoléculas para resolver problemas de formulación y control de calidad.\n- Diseñar formulaciones de fragancias finas, cosméticos fragranciados y formas farmacéuticas, considerando desempeño, estabilidad, seguridad y normatividad aplicable (IFRA, COFEPRIS).\n- Evaluar la calidad de materias primas, insumos aromáticos y productos terminados mediante métodos instrumentales validados y estadística aplicada.\n- Aplicar Buenas Prácticas de Laboratorio y de Manufactura para asegurar trazabilidad, reproducibilidad y cumplimiento regulatorio.\n- Implementar diseños experimentales y análisis quimiométricos para optimizar perfiles sensoriales y funcionales de productos fragranciados.\n- Gestionar riesgos, seguridad e higiene en laboratorio y planta, incluyendo manejo de sustancias peligrosas y residuos conforme a normatividad.\n- Integrar conocimientos científicos, tecnológicos y de mercadotecnia olfativa para proponer soluciones pertinentes a necesidades del sector salud-cosmético y perfumería.\n- Comunicar resultados técnicos de forma clara, ética y sustentada, en español e inglés, a audiencias especializadas y no especializadas.\n- Emprender proyectos de innovación y mejora continua con enfoque de sostenibilidad y química verde en la industria farmacéutica, cosmética y de perfumería.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Químico Farmacéutico Biólogo (2026) ", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "8", "sustento_teorico_del_modelo_curricular": "El plan se fundamenta en un enfoque por competencias profesionales integrales, con base constructivista y de aprendizaje situado. Se articula mediante:\n- Resultados de aprendizaje observables alineados a la Taxonomía de Bloom y a estándares del sector salud-cosmético.\n- Integración teoría-práctica con alto componente de laboratorio y planta piloto; uso de problemas auténticos (ABP) y proyectos integradores por semestre.\n- Evaluación basada en evidencias: prácticas con bitácora, informes técnicos, portafolio, rúbricas y evaluación sensorial objetiva.\n- Transversalidad de ejes: ciencias básicas, profesionalizantes (farmacotecnia, análisis instrumental, calidad), y eje de perfumería (formulación, análisis, sensorial y regulación).\n- Vinculación industria–academia mediante estancias, seminarios con casas perfumistas y co-diseño de proyectos.\n- Enfoque de calidad y mejora continua (PDCA), seguridad y sostenibilidad (química verde e ISO 22716).", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "Estructura y seriación\n- Diseño curricular rígido en 8 semestres. Semestres 1-4: bases científicas y metodológicas; semestres 5-8: integración profesional y especialización en perfumería y cosméticos.\n- Seriación por prerrequisitos académicos y de competencias de laboratorio; control de acreditaciones seriadas para acceso a talleres avanzados de perfumería.\n\nCargas y componentes formativos por semestre (referenciales)\n- 6 a 7 asignaturas por semestre, combinando teoría y laboratorio. Carga máxima semanal: 34 horas bajo conducción docente.\n- Componentes obligatorios: prácticas de laboratorio, seminarios de industria, proyecto integrador por semestre y actividades de seguridad e higiene.\n\nEje de perfumería (5º a 8º semestre)\n- Asignaturas y talleres: Química de Fragancias y Aromáticos, Análisis Instrumental Aplicado a Perfumería, Tecnología de Cosméticos y Perfumes, Evaluación Sensorial y Marketing Olfativo, Regulación y Seguridad de Fragancias, Taller de Formulación de Fragancias, Proyecto Integrador de Perfumado.\n\nVinculación, prácticas y servicio social\n- Servicio social: mínimo 480 horas a partir de 6º semestre en instituciones de salud, laboratorios de control de calidad o industria cosmética.\n- Prácticas profesionales: 240–480 horas en 7º–8º semestre en casas perfumistas, cosmética o farmacéutica; tutoría académica y evaluación por competencias.\n\nGestión académica y aseguramiento de la calidad\n- Coordinación de programa y Comité Curricular (académicos, industria y egresados) para seguimiento de resultados de aprendizaje y pertinencia.\n- Sistemas de información académica para trazabilidad de competencias, asistencia, calificaciones, bitácoras y POE.\n- Protocolos de seguridad, mantenimiento y calibración de equipo; auditorías internas semestrales de laboratorios.\n\nTitulación\n- Modalidades: tesis/proyecto de aplicación, examen general de conocimientos, o portafolio con evidencia de competencias y proyecto en perfumería.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Metodología y periodicidad\n- Evaluación continua anual y revisión integral trianual del plan bajo ciclo PDCA.\n\nIndicadores clave\n- Eficiencia terminal, tiempo de titulación, empleabilidad a 6 y 12 meses, satisfacción de empleadores, desempeño en EGEL afín, cumplimiento de BPF/ISO 22716 en prácticas, resultados de auditorías de laboratorio, proyectos con industria y producción académica estudiantil.\n\nInstrumentos y fuentes\n- Encuestas a estudiantes/egresados/empleadores, rúbricas de proyectos integradores, análisis de portafolios, evaluación externa por pares académicos e industriales (casas perfumistas y laboratorios cosméticos), benchmarking nacional/internacional y análisis de trazabilidad de evidencias.\n\nProcedimientos\n- Mapeo de resultados de aprendizaje vs. evidencias por asignatura; análisis de brechas; planes de mejora por unidad de aprendizaje; actualización de POE y contenidos; capacitación docente en tendencias de perfumería, métodos instrumentales y estadística sensorial.\n- Informe público de resultados y plan de mejora aprobado por el Comité Curricular y la Dirección Académica.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Mtra. Claudia López Hernández, Directora Académica de la Facultad de Ciencias Químicas y Salud"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Genera un plan de estudios con énfasis especial en perfumería"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-2025-08-07", "usage": {"input_tokens": 3766, "total_tokens": 9774, "output_tokens": 6008, "input_tokens_details": {"cached_tokens": 3712}, "output_tokens_details": {"reasoning_tokens": 3456}}, "responseId": "resp_08652921016d16350069939cf516ac81a0b23dd0d51a15afb0", "conversationId": null}}', NULL, NULL, '2026-02-16 22:42:41.82455+00', '2026-03-04 15:42:54.388936+00'),
	('3ebc1d1c-e950-4a6e-948f-bb89efa40e77', '7075d507-6404-4b18-a5cb-e07a187bae55', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Licenciatura en Mercadotecnia ', 'Licenciatura', 'Semestre', 9, '{"vigencia": "Por definir por la autoridad educativa", "area_de_estudio": "Administración y negocios", "perfil_de_egreso": "Conocimientos:\n- Fundamentos de mercadotecnia estratégica y comportamiento del consumidor.\n- Diseño de investigaciones de mercado cuantitativas, cualitativas e híbridas.\n- Muestreo, estadística aplicada y control de calidad de datos.\n- Analítica de datos, minería de datos y uso de inteligencia artificial de forma ética.\n- Gestión de paneles de consumidores y estudios longitudinales.\n- Herramientas para escucha social y análisis de sentimiento.\n- Diseño de experimentos, pruebas de dos variantes y simulaciones.\n- Ética, protección de datos personales y cumplimiento normativo.\n- Integración omnicanal de fuentes en entornos físicos y digitales.\n- Mercados internacionales y marketing global: estrategias de entrada, adaptación de mensajes y análisis comparativo entre países (si aplica).\n- Enfoque en internacionalización y movilidad: oportunidades de movilidad, alianzas y cooperación con instituciones extranjeras (si aplica).\n\nHabilidades:\n- Formular problemas de investigación con objetivos, hipótesis e indicadores claros.\n- Diseñar instrumentos de captura y protocolos de recolección multicanal.\n- Analizar e interpretar grandes volúmenes de datos con rigor estadístico.\n- Detectar y mitigar sesgos, fraude y actividades automatizadas no deseadas.\n- Integrar información de múltiples fuentes para obtener hallazgos accionables.\n- Comunicar hallazgos con visualizaciones y narrativas persuasivas.\n- Gestionar proyectos de investigación con alcance, tiempos y presupuesto.\n- Colaborar con áreas de producto, ventas y finanzas para la toma de decisiones.\n- Desarrollar capacidades para trabajar en equipos multiculturales y gestionar investigaciones a escala global.\n- Diseñar y ejecutar investigaciones de mercados internacionales, incluyendo adaptaciones culturales y lingüísticas.\n\nActitudes:\n- Pensamiento crítico, curiosidad intelectual y orientación a la evidencia.\n- Responsabilidad social, respeto a la privacidad y cultura de la calidad.\n- Innovación, aprendizaje continuo y adaptabilidad tecnológica.\n- Interés y apertura hacia la internacionalización, movilidad académica y competencias globales.\n- Disposición para movilidad internacional y experiencias de intercambio cuando aplique.\n", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Conocimientos mínimos para ingresar a la Licenciatura en Mercadotecnia (campo de estudio: administración y negocios):\n- Bachillerato o equivalente concluido.\n- Aritmética, álgebra básica y estadística descriptiva elemental.\n- Fundamentos de mercadotecnia y administración a nivel introductorio.\n- Lectura y redacción académica en español, con capacidad de comprender textos técnicos simples.\n- Reconocimiento básico de herramientas digitales (hojas de cálculo y presentaciones).\n\nHabilidades:\n- Manejo básico de hojas de cálculo y presentaciones para análisis simples.\n- Lectura comprensiva de textos introductorios y capacidad de extraer ideas clave.\n- Pensamiento lógico, atención al detalle y disposición para trabajo en equipo y trabajo de campo.\n- Capacidad para formular problemas simples y plantear preguntas de investigación básicas.\n\nAptitudes y actitudes:\n- Interés por la investigación aplicada y el análisis de datos.\n- Ética, responsabilidad, integridad y respeto a la privacidad.\n- Curiosidad intelectual, aprendizaje continuo y adaptabilidad tecnológica.\n- Orientación al trabajo colaborativo y a la comunicación efectiva.\n\nNotas: se mantiene como requisito mínimo el bachillerato concluido y se especifican las competencias esperadas para facilitar la selección y nivelación inicial acorde con el plan de estudios de Mercadotecnia.", "curso_propedeutico": "Propósito: nivelar y adaptar los conocimientos previos en estadística, metodología de investigación y redacción académica, con un enfoque modular y adaptable a diversos perfiles de ingreso.\nPoblación: aspirantes con deficiencias detectadas en diagnóstico y/o necesidad de fortalecimiento de fundamentos.\nDuración: 6 semanas previas al inicio del semestre (40-60 horas totales).\nContenidos por módulos:\n- Módulo 1: Estadística descriptiva, probabilidades básicas y uso básico de hojas de cálculo.\n- Módulo 2: Metodología de la investigación y formulación de problemas.\n- Módulo 3: Limpieza de datos, control de calidad y manejo de datos.\n- Módulo 4: Redacción académica, normas de citación y lectura crítica.\n- Módulo 5: Ética, privacidad y protección de datos.\nMetodología: aprendizaje activo, contenidos asíncronos y sesiones sincrónicas opcionales, proyectos cortos y evaluación formativa con retroalimentación continua; adaptación de contenidos según diagnóstico.\nEvaluación: ejercicios prácticos, pruebas cortas y un proyecto corto de investigación con rúbricas claras.\nResultados de aprendizaje: dominio básico de estadística, investigación, manejo de datos y redacción; capacidad para iniciar proyectos de investigación de mercados con ética y trazabilidad.", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato o equivalente concluido.", "carga_horaria_a_la_semana": 26, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2026", "duracion_del_ciclo_escolar": "18 semanas efectivas de clase.", "fines_de_aprendizaje_o_formacion": "- Analizar comportamientos del consumidor y dinámicas de mercado para detectar oportunidades.\n- Diseñar proyectos de investigación con enfoques cuantitativos, cualitativos e híbridos.\n- Evaluar la calidad de datos y la validez de los hallazgos con criterios estadísticos.\n- Implementar protocolos de recolección multicanal con integridad y trazabilidad.\n- Interpretar información compleja para generar hallazgos accionables y confiables.\n- Integrar fuentes de datos físicas y digitales para construir modelos de comprensión del mercado.\n- Optimizar procesos de investigación mediante automatización e inteligencia artificial responsable.\n- Gestionar proyectos con alcance, tiempo, costo y riesgos definidos.\n- Comunicar resultados con claridad, visualizaciones efectivas y recomendaciones estratégicas.\n- Garantizar el cumplimiento ético y normativo en todas las fases de la investigación", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Mercadotecnia con énfasis en analítica de mercados, ética profesional e internacionalización", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9 semestres", "sustento_teorico_del_modelo_curricular": "El plan se sustenta en el enfoque por competencias profesionales, el aprendizaje basado en proyectos y la investigación aplicada. Integra metodologías activas, estudio de casos y laboratorios de datos para desarrollar competencias técnicas y transversales. El currículo articula asignaturas de fundamentos, metodología de investigación, estadística y analítica, comportamiento del consumidor, diseño de experimentos, escucha social y ética. La progresión por niveles fortalece el dominio conceptual y práctico para generar estudios de mercado pertinentes, válidos y útiles para la toma de decisiones.", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "Diseño rígido en 9 semestres consecutivos.\nOrganización:\n- 6 a 7 asignaturas por semestre, con una carga máxima de 26 horas por semana.\n- Secuencia formativa: fundamentos, metodología, analítica y aplicación.\n- Asignaturas integradoras por semestre con proyectos reales o simulados.\n- Estancia profesional y proyecto terminal de investigación de mercado en el último año.\nOperación:\n- Calendario semestral de 18 semanas efectivas.\n- Tutoría académica y asesoría metodológica por semestre.\n- Evaluación continua mediante evidencias, prácticas y entregables de investigación.\n- Mecanismos de equivalencias y revalidaciones conforme a la normatividad vigente.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Periodicidad:\n- Revisión anual de resultados de aprendizaje, deserción, eficiencia terminal y satisfacción.\n- Evaluación integral cada tres años para actualización curricular.\nMetodología:\n- Comité académico con participación de docentes, estudiantes y empleadores.\n- Análisis de pertinencia con base en tendencias del mercado y requerimientos profesionales.\n- Indicadores de desempeño de proyectos, prácticas y colocación laboral.\n- Retroalimentación externa de organizaciones del sector y egresados.\nMejora continua:\n- Plan de acción con responsables, metas y cronograma.\n- Actualización de contenidos, bibliografía y prácticas en laboratorios de datos.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Maestra Daniela Ruiz Martínez, Directora Académica"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Textos cortos pero concisos y evitar abreviaturas y siglas", "descripcionEnfoqueAcademico": "Genera un plan que este orientado a la generación de estudios de mercado"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-2025-08-07", "usage": {"input_tokens": 4241, "total_tokens": 9491, "output_tokens": 5250, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 3776}}, "responseId": "resp_078e1222e2e46bc800699c64fbd4ac819c94a74d2b9419aa52", "conversationId": null}}', NULL, NULL, '2026-02-23 14:34:25.880983+00', '2026-02-25 22:33:30.583353+00'),
	('54760e2e-406d-483a-962d-875b6d3195fd', '8208da08-d549-4359-8865-9d806bc54f19', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería Cibernética', 'Maestría', 'Semestre', 9, '{"vigencia": "2026-2031", "area_de_estudio": "Ingeniería (Sistemas de Control y Redes)", "perfil_de_egreso": "Conocimientos:\n  - Comprender los fundamentos de la teoría de control, sistemas dinámicos y redes de comunicaciones aplicadas a la cibernética.\n  - Conocer arquitecturas de sistemas embebidos, protocolos de redes y modelos de seguridad informática aplicables a sistemas de control.\n  - Identificar metodologías de diseño, simulación e implementación de sistemas de automatización y control distribuido.\nHabilidades:\n  - Diseñar y modelar sistemas de control retroalimentado mediante herramientas analíticas y de simulación.\n  - Integrar redes de sensores y actuadores en arquitecturas de control distribuido.\n  - Implementar soluciones prácticas de supervisión, adquisición de datos y control en entornos industriales y de servicios.\n  - Analizar y mitigar riesgos en la ciberseguridad de sistemas de control y redes industriales.\nActitudes:\n  - Actuar con responsabilidad ética y profesional ante la seguridad y confiabilidad de sistemas críticos.\n  - Mantener una disposición proactiva hacia la actualización técnica y la investigación aplicada.\n  - Colaborar interdisciplinariamente y comunicar de forma clara resultados técnicos y propuestas de mejora.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "- Evidencia de formación de nivel medio superior (Bachillerato) con preferencia en orientación físico-matemática.\n- Conocimientos básicos de álgebra, trigonometría y cálculo diferencial e integral.\n- Conocimientos elementales de física (mecánica y electricidad) y fundamentos de programación (algoritmos y estructuras de datos simples).\n- Habilidades para la resolución de problemas, razonamiento lógico-matemático y trabajo en equipo.\n- Actitud de interés por sistemas de control, redes y tecnologías de automatización.", "curso_propedeutico": "- Población objetivo: Aspirantes sin dominio suficiente en cálculo, física o programación.\n- Situaciones de aplicación: Detectado mediante diagnóstico de ingreso aplicado la primera semana.\n- Duración: 8 semanas (intensivo previo al inicio del primer semestre).\n- Contenido y relación con el plan: Refuerzo de cálculo diferencial e integral, fundamentos de física aplicada a sistemas, y programación básica en C/Python para acceso a materias de programación y sistemas embebidos.\n- Metodología: Sesiones prácticas y evaluaciones diagnósticas que permiten validar el pase al primer semestre.", "modalidad_educativa": "Mixta", "antecedente_academico": "Requisito mínimo: Bachillerato o su equivalente. Se aceptan múltiples trayectorias previas para mayor flexibilidad de ingreso:\n- Bachillerato general con orientación en física-matemáticas, tecnológico o ciencias aplicadas.\n- Bachillerato técnico o tecnológico en áreas afines: electrónica, mecánica, automatización, mecatrónica, informática, sistemas, telecomunicaciones, robótica, control, redes, etc.\n- Técnico Superior Universitario (TSU) o títulos técnicos equivalentes en áreas afines a la ingeniería (electrónica, eléctrica, mecatrónica, automatización, sistemas, telecomunicaciones, computación, control).\n- Licenciaturas o ingenierías afines: Informática, Computación, Ingeniería Electrónica, Ingeniería Eléctrica, Ingeniería de Sistemas/Computación, Ingeniería Mecatrónica, Ingeniería en Control y Automatización, Ingeniería en Teleinformática, Física, Matemáticas aplicadas.\n- Experiencia profesional relevante acompañada de convalidaciones académicas según normativa institucional (si aplica).", "carga_horaria_a_la_semana": 40, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2026", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "- Analizar modelos matemáticos de sistemas dinámicos para diagnosticar comportamiento y estabilidad.\n- Diseñar controladores clásicos y modernos para regular procesos físicos y cibernéticos.\n- Integrar soluciones de redes y comunicaciones para garantizar la interoperabilidad entre nodos de control.\n- Implementar arquitecturas de sistemas embebidos y plataformas de adquisición para soluciones de automatización.\n- Evaluar y aplicar medidas de ciberseguridad en sistemas de control industrial y redes críticas.\n- Formular propuestas de optimización y mantenimiento predictivo mediante técnicas de monitoreo y análisis de datos.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ingeniería Cibernética", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9 ciclos escolares", "sustento_teorico_del_modelo_curricular": "Lista de pasos conceptuales previos:\n  - Revisar requisitos normativos del Acuerdo 17/11/17 y criterios aplicables a licenciaturas en ingeniería.\n  - Estructurar perfil de ingreso y egreso alineados con el campo de formación (Ingeniería, sistemas y control).\n  - Definir diseño curricular rígido con distribución por semestres y carga horaria máxima conforme a normativa.\n  - Establecer fines de aprendizaje basados en la Taxonomía de Bloom y competencias profesionales.\nSustento teórico y marco conceptual:\n  - Fundamentación: El plan se apoya en enfoques de educación por competencias, teoría de sistemas y cibernética clásica y contemporánea. Integra principios de ingeniería de control, redes de comunicaciones y sistemas embebidos para formar profesionistas capaces de operar, diseñar y asegurar sistemas integrados.\n  - Marcos y referencias: Se consideran textos y estándares internacionales de ingeniería de control y redes, marcos de calidad educativa y criterios de pertinencia laboral. El modelo curricular privilegia la articulación teoría-práctica mediante laboratorios, proyectos integradores y estancias profesionales.\n  - Organización pedagógica: Las asignaturas se articulan en núcleos formativos (fundamentos matemáticos y físicos; teoría de control; redes y comunicaciones; sistemas embebidos; seguridad y ética profesional; proyectos finales) para garantizar progresión cognitiva y construcción de competencias.\n  - Evaluación y aprendizaje: El modelo promueve evaluación continua, aprendizaje activo y resolución de problemas reales como estrategias para el desarrollo de competencias técnicas y profesionales.", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "- Diseño curricular: Rígido. El estudiante cursa un número determinado de asignaturas por semestre conforme al mapa curricular oficial.\n- Carga por semestre: Promedio de 40 horas semanales distribuidas en teoría, laboratorio y actividades guiadas; no excede 50 horas semanales.\n- Asignación docente: Cada asignatura es bajo la responsabilidad de un académico con perfil idóneo (grado mínimo de Maestría en áreas afines; preferentemente doctores en asignaturas avanzadas) y experiencia profesional en sistemas de control y redes.\n- Coordinación: Dirección de la carrera y comité curricular son responsables de la programación, seguimiento y control académico.\n- Operatividad: Horarios presenciales semanales, laboratorios equipados y proyectos integradores. Procedimiento para equivalencias y convalidaciones conforme a reglamento institucional.\n- Evaluación por ciclo: Reportes de avance, reuniones de seguimiento y atención a estudiantes en riesgo académico.\n- Estándares de amplitud: En diseño rígido se establece el número fijo de asignaturas por semestre conforme al mapa curricular autorizado; períodos de recuperación y exámenes extraordinarios según normativa interna.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "- Periodicidad: Revisión curricular anual y evaluación integral cada tres años.\n- Instrumentos: Encuestas a estudiantes y egresados, consulta a empleadores, análisis de resultados de aprendizaje por asignatura, indicadores de titulación y empleabilidad, autoevaluación docente, y reporte de laboratorio y proyectos.\n- Metodología: El comité curricular consolida evidencias y propone ajustes basados en resultados cuantitativos y cualitativos; se realizan mesas de trabajo con profesores, estudiantes y representantes de la industria.\n- Criterios de actualización: Incorporación de avances tecnológicos en redes y ciberseguridad, demanda laboral regional y resultados de investigación aplicada.\n- Productos: Informes de mejora curricular, modificaciones de guías de aprendizaje y plan de capacitación docente.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "La carrera no deberá tener relación con la ofimática", "descripcionEnfoqueAcademico": "Una carrera relacionada con el control y los sistemas, basada en redes"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-mini-2025-08-07", "usage": {"input_tokens": 3792, "total_tokens": 7483, "output_tokens": 3691, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 2048}}, "responseId": "resp_05edeefefaedc7df00699f955e17e881a1a7100ba199e2833f", "conversationId": null}}', NULL, NULL, '2026-02-26 00:36:19.647683+00', '2026-03-25 17:35:31.391867+00'),
	('0e0aea4d-b8b4-4e75-8279-6224c3ac769f', '8208da08-d549-4359-8865-9d806bc54f19', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Ingeniería en Cibernética y Ciberseguridad (2025)', 'Doctorado', 'Semestre', 8, '{"nivel": "Licenciatura", "nombre": "Ingeniería Cibernética", "area_de_estudio": "Tecnologías de la Información y la Comunicación (CMPE 2016)", "perfil_de_egreso": "Conocimientos: redes, sistemas, criptografía. Habilidades: pentesting, hardening, respuesta a incidentes. Actitudes: ética, responsabilidad.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Pensamiento lógico, bases de álgebra, nociones de programación y comunicación escrita.", "curso_propedeutico": null, "modalidad_educativa": "Probando guardado", "antecedente_academico": "Bachillerato concluido; afinidad con matemáticas y computación.", "carga_horaria_a_la_semana": 40, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2026-CIB-ING", "duracion_del_ciclo_escolar": "16", "fines_de_aprendizaje_o_formacion": "Formar profesionales capaces de diseñar, implementar y asegurar sistemas ciberfísicos y plataformas digitales.", "nombre_autorizado_de_la_institucion": "unameditfddfdfdf", "total_de_ciclos_del_plan_de_estudios": "8", "sustento_teorico_del_modelo_curricular": "Enfoque por competencias, aprendizaje basado en problemas y laboratorios.", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "Plan rígido con cargas sugeridas por semestre; asignaturas seriadas por áreas.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Revisión anual por comité académico; actualización por tendencias y retroalimentación de egresados."}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'MANUAL', '{"seed": true, "version": "2026-01-08"}', '11111111-1111-1111-1111-111111111111', '11111111-1111-1111-1111-111111111111', '2026-01-09 13:45:37.784586+00', '2026-02-26 15:30:26.06711+00'),
	('198c763b-9d97-423b-b13a-5713437fc81b', '6d086d1b-aaea-4b76-9b16-fa8f3e29d9fa', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Licenciatura en Educación Especial como sombra', 'Licenciatura', 'Semestre', 9, '{"vigencia": "(Espacio para uso exclusivo de la autoridad educativa)", "area_de_estudio": "Formación docente y ciencias de la educación", "perfil_de_egreso": "Conocimientos:\n  - Marco conceptual de la Educación Especial y modelos de atención a la diversidad, con énfasis en la figura de sombra como mediadora del aprendizaje en educación primaria.\n  - Normativa nacional e internacional sobre inclusión educativa, derechos de las personas con discapacidad y derechos humanos aplicados a contextos escolares.\n  - Características del desarrollo infantil y del aprendizaje en educación primaria, con atención a la diversidad cultural y socioemocional.\n  - Fundamentos de evaluación formativa, diseño universal para el aprendizaje (DUA) y estrategias de adaptación curricular y de apoyo.\n  - Diseño y gestión de entornos de aprendizaje inclusivos, uso de tecnologías de apoyo y técnicas de observación y intervención.\nHabilidades:\n  - Identificar, registrar y analizar barreras de aprendizaje y necesidades educativas a partir de observación estructurada y evidencias.\n  - Diseñar, adaptar y aplicar intervenciones pedagógicas y apoyos individualizados, incluida la figura de sombra, para promover participación y aprendizaje en aula regular.\n  - Planificar y coordinar planes de atención individualizada en colaboración con docentes, familias y equipos de apoyo interprofesional.\n  - Facilitar la mediación, la comunicación y la interacción en contextos diversos, promoviendo estrategias DUA y uso responsable de tecnologías.\n  - Evaluar el progreso estudiantil con instrumentos cualitativos y cuantitativos y ajustar intervenciones con base en evidencia.\nActitudes:\n  - Compromiso ético con la dignidad, derechos y bienestar de las personas con discapacidad; ética profesional, confidencialidad y respeto a la diversidad.\n  - Sensibilidad intercultural y socioemocional; respeto a la diversidad y a la dignidad de la persona.\n  - Enfoque reflexivo y colaborativo; orientación a la mejora continua, investigación-acción y aprendizaje a lo largo de la vida.\n  - Tolerancia, empatía y resiliencia para trabajar en entornos educativos complejos y con comunidades escolares; responsabilidad social y compromiso con la inclusión.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "Conocimientos previos:\n  - Educación media superior (bachillerato) completada.\n  - Conocimientos básicos de psicología del desarrollo y didáctica (preferente).\nHabilidades y destrezas:\n  - Capacidad de comunicación clara y trabajo en equipo.\n  - Habilidad para la observación y registro de conductas y procesos de aprendizaje.\n  - Manejo básico de herramientas informáticas (navegación web, edición de texto y acceso a plataformas educativas).\nAptitudes personales:\n  - Vocación por el trabajo con infancia y jóvenes.\n  - Paciencia, tolerancia y resiliencia para la resolución de conflictos en entornos escolares.\n  - Disponibilidad para realizar estancias prácticas en centros educativos y trabajo de campo.", "curso_propedeutico": "Situaciones de aplicación:\n  - Dirigido a aspirantes que no acrediten formación previa en áreas afines (psicopedagogía, educación o trabajo social).\nPoblación objetivo:\n  - Aspirantes a la licenciatura con bachillerato completo.\nDuración y estructura:\n  - 40 horas (presenciales o en modalidad mixta), organizado en 4 módulos.\nRelación con el plan de estudios:\n  - Introduce fundamentos del desarrollo infantil, terminología de inclusión y manejo básico de registros y observación; prepara para las prácticas iniciales.", "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato concluido (Certificado de educación media superior). Se valorará experiencia previa en entornos educativos o comunitarios; no es requisito excluyente.", "carga_horaria_a_la_semana": 40, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "LLSE-2026", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": " - Analizar los fundamentos teóricos y normativos de la Educación Especial y la atención a la diversidad.\n - Diagnosticar necesidades educativas individuales mediante técnicas de observación y evaluación formativa.\n - Diseñar intervenciones pedagógicas y adaptaciones curriculares orientadas a la inclusión en educación primaria.\n - Implementar estrategias de mediación y apoyo individual (figura de sombra) para facilitar la participación y el aprendizaje.\n - Colaborar con equipos docentes y familias para la planificación y seguimiento de planes de atención individualizada.\n - Evaluar el impacto de las estrategias de apoyo e intervenir de forma reflexiva para su mejora continua.\n - Promover prácticas profesionales éticas y respeto a los derechos de las personas con discapacidad.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura - Licenciatura en Educación Especial (énfasis: figura de sombra para educación primaria)", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9 ciclos semestrales", "sustento_teorico_del_modelo_curricular": "Lista de pasos conceptuales previos a la elaboración:\n  - Revisar requisitos normativos del Acuerdo 17/11/17 y correspondencia con ciclos semestrales.\n  - Definir perfil de egreso alineado con competencias profesionales para la figura de sombra.\n  - Estructurar asignaturas y prácticas que integren teoría, práctica reflexiva y colaboración interprofesional.\n\nMarco conceptual y fundamentos:\n  - Enfoque por competencias: El plan articula saberes, capacidades y actitudes necesarias para la práctica profesional en entornos inclusivos.\n  - Constructivismo social y aprendizaje situado: Se privilegia el aprendizaje contextualizado en aula y en comunidad, con énfasis en la observación y la práctica asistida.\n  - Diseño Universal para el Aprendizaje (DUA): Fundamenta la propuesta de adaptaciones curriculares y estrategias de accesibilidad.\n  - Enfoque de derechos humanos e inclusión educativa: La intervención pedagógica se orienta a garantizar la participación plena y no discriminación.\n  - Investigación-acción y reflexión profesional: Los practicantes desarrollan competencias para investigar su propia práctica y ajustar intervenciones.\n\nVinculación curricular:\n  - Las asignaturas teóricas, metodológicas y las prácticas profesionales se articulan para desarrollar progresivamente la capacidad de intervenir como sombra, evaluar necesidades y coordinar apoyos.", "justificacion_de_la_propuesta_curricular": "Descripción de la modalidad mixta y recursos tecnológicos:\n  - La modalidad mixta combina sesiones presenciales para talleres y prácticas de campo, con componentes virtuales para contenidos teóricos, seminarios y tutorías.\n  - Plataforma educativa: Uso de un LMS institucional (por ejemplo, Moodle o Canvas) para entregar contenidos asincrónicos, foros académicos, rúbricas y actividades de evaluación.\n  - Herramientas sincrónicas: Videoconferencias para seminarios, supervisión de prácticas y sesiones de retroalimentación (Zoom/Teams integradas al LMS).\n  - Recursos didácticos: Banco de recursos multimedia, casos clínicos, simulaciones y módulos interactivos para el desarrollo de competencias de observación y diseño de adaptaciones.\nAutogestión y flexibilidad espacio-temporal:\n  - Los estudiantes disponen de materiales asincrónicos que permiten avanzar de manera flexible, con itinerarios de estudio y fechas de entrega acotadas.\n  - Se garantiza acompañamiento mediante tutorías periódicas (individuales y grupales) y supervisión de prácticas en campo.\nVinculación con actividades de aprendizaje:\n  - Las asignaturas incluyen actividades de observación estructurada en aulas, prácticas acompañadas en centros educativos, diseño y aplicación de adaptaciones y proyectos integradores.\n  - La plataforma registra evidencias de aprendizaje (portafolio digital) y facilita la evaluación formativa por parte de docentes y supervisores de práctica.", "administracion_y_operatividad_del_plan_de_estudios": "Estructura administrativa y académica:\n  - Dirección Académica: Responsable general del programa y de la vinculación institucional.\n  - Coordinación de la Licenciatura: Gestión curricular, seguimiento a planes de estudio y coordinación de prácticas.\n  - Cuerpo académico: Perfil con experiencia en educación especial, psicopedagogía y práctica escolar inclusiva; se exige formación de posgrado preferente y experiencia en supervisión de prácticas.\n  - Tutoría académica: Sistema de tutorías para seguimiento individual del estudiante y acompañamiento en estancias prácticas.\nOperatividad del calendario y carga por ciclo:\n  - Diseño rígido: 9 semestres obligatorios.\n  - Asignaturas por semestre (típico): 5 a 6 asignaturas, combinando teoría, metodología y práctica; una asignatura práctica o de taller por semestre como mínimo.\n  - Estancias y prácticas: Prácticas progresivas con incremento de horas en los semestres superiores y prácticas intensivas de intervención en escuela en los últimos semestres.\nGestión de calidad y recursos:\n  - Espacios formativos: Aulas, laboratorios didácticos, centro de observación y convenios con escuelas de educación primaria para estancias.\n  - Recursos humanos: Profesores con perfil docente-investigador y supervisores de práctica con formación en educación especial.\n  - Documentación operativa: Manuales de práctica, rúbricas de evaluación, convenios de colaboración y normativa interna para el desarrollo de estancias.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Metodología e instrumentos:\n  - Evaluación cuatrienal interna con revisión anual de resultados: combinación de análisis de indicadores cuantitativos y cualitativos.\n  - Instrumentos: Encuestas a egresados y empleadores, informe de seguimiento de egresados (tracer study), evaluación de desempeño de estudiantes en prácticas, análisis de cargas y resultados académicos, reuniones del Comité Académico.\n  - Periodicidad: Revisión anual de indicadores clave (retención, titulación, desempeño en prácticas), evaluación curricular cada tres años para ajustes mayores.\n  - Participación de actores: Voces de estudiantes, egresados, docentes, escuelas vinculadas y sociedad civil en foros de evaluación.\n  - Mecanismos de mejora: Planes de acción derivados de la evaluación, actualización de asignaturas, capacitación docente y revisión de convenios de práctica.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "No considerar específicamente el TDA si no todas las posibilidades de la educación especial, incluyendo discapacidades", "descripcionEnfoqueAcademico": "Una carrera relacionada con la educación especial, relacionada con la figura de sombra para educación primaria, y educación especial para personas con TDA"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai-generate-plan"}', NULL, NULL, '2026-02-27 22:23:03.864946+00', '2026-03-12 21:57:19.162202+00'),
	('f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', 'b4e0ad06-84b0-40fc-8228-a75b0c9cbd9b', '69fb2b77-5a95-47e0-bf1f-389d384200e4', 'Educación Especial como sombra', 'Maestría', 'Semestre', 9, '{"vigencia": "2026-2029 (vigencia sujeta a renovación por la autoridad educativa; se prevé revisión y actualización curricular al inicio de cada ciclo de planificación institucional)", "area_de_estudio": "Educación. Campo amplio: Formación docente para educación inclusiva y atención a la diversidad, con énfasis en educación especial y prácticas de acompañamiento (sombra) en contextos escolares, conforme a CMPE 2016.", "perfil_de_egreso": "Conocimientos:\n- Conocer fundamentos teóricos y normativos de la educación especial y la inclusión educativa, incluidas las leyes y políticas nacionales aplicables.\n- Conocer modelos de atención educativa (modelo ecológico, enfoque por competencias, Diseño Universal para el Aprendizaje, intervención centrada en la diversidad) y sus implicaciones para la práctica de sombra.\n- Conocer características y necesidades educativas de estudiantes con discapacidad, trastornos del desarrollo y necesidades educativas especiales.\n\nHabilidades:\n- Diseñar y aplicar estrategias de acompañamiento (sombra) para facilitar la participación y el aprendizaje en contextos educativos regulares.\n- Realizar observaciones sistemáticas, registros conductuales y adaptaciones curriculares básicas en colaboración con docentes y familias.\n- Colaborar en equipos interdisciplinarios y comunicarse efectivamente con docentes, familias y especialistas para articular apoyos.\n- Aplicar procedimientos de evaluación formativa y ajustar estrategias de intervención basadas en evidencia.\n\nActitudes:\n- Actuar con ética profesional, confidencialidad y respeto hacia la dignidad, autonomía y derechos de las personas con discapacidad.\n- Mantener una actitud reflexiva, crítica y de mejora continua sustentada en la evidencia y en el aprendizaje colaborativo.\n- Mostrar compromiso por la inclusión, la equidad y la promoción de entornos accesibles y participativos.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "Conocimientos previos:\n- Certificado de Bachillerato o equivalente, con dominio básico de lectura, redacción y razonamiento lógico-matemático.\n- Conocimientos introductorios en psicología, pedagogía o atención a la diversidad (deseables, no obligatorios).\n\nHabilidades y aptitudes:\n- Comunicación oral y escrita clara; habilidades para el trabajo en equipo.\n- Observación, registro y análisis de comportamientos en contextos educativos.\n- Actitud empática, paciente y respetuosa hacia la diversidad funcional y cultural.\n- Ética profesional, confidencialidad y compromiso con la práctica educativa.\n- Capacidad básica para usar herramientas digitales y gestionar información.\n\nCondiciones personales:\n- Disponibilidad para prácticas en centros educativos y visitas domiciliarias.\n- Interés explícito por la educación inclusiva y por trabajar en equipos interdisciplinarios.\n- Disposición para formación continua y trabajo con poblaciones vulnerables.\n- Compromiso para cumplir con horarios y requerimientos de la modalidad mixta (presencial y a distancia).", "curso_propedeutico": "Se ofrecerá un curso propedéutico opcional dirigido a aspirantes que no cuenten con formación previa en pedagogía o atención a la diversidad. Características:\n- Población: Aspirantes sin experiencia formal en educación o con antecedentes en áreas no afines.\n- Duración: 8 semanas (40 horas totales), modalidad mixta (sincrónico y asincrónico).\n- Contenidos: Fundamentos de psicología del desarrollo, nociones básicas de pedagogía inclusiva, comunicación efectiva y manejo básico de registros.\n- Relación con el plan de estudios: Prepara al aspirante para cursar asignaturas iniciales de didáctica y atención a la diversidad; no substituye requisitos de admisión, pero fortalece rendimiento académico inicial.\n- Criterios de aplicación: Se recomienda para el 30% de la cohorte cuya evaluación de diagnóstico inicial identifique brechas relevantes en competencias lectoras, comunicativas o conocimientos básicos en educación.", "modalidad_educativa": "Mixta", "antecedente_academico": "Certificado de Bachillerato o equivalente. Preferentemente procedencia de áreas afines como Ciencias de la Educación, Psicología, Trabajo Social, Pedagogía o áreas de ciencias sociales relacionadas con atención a la infancia y discapacidad.", "carga_horaria_a_la_semana": 40, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "LLS-LESE-2026", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "El programa tiene por finalidad formar profesionales de la educación especializados en el acompañamiento tipo ''sombra'', capaces de intervenir en contextos educativos regulares y de atención especializada mediante prácticas fundamentadas en la evidencia, la colaboración interprofesional y el respeto a los derechos de las personas con discapacidad. Los fines de aprendizaje se articulan en competencias que guían la formación:\n- Analizar los marcos normativos, éticos y teóricos que sustentan la educación especial y la inclusión, con el fin de garantizar intervenciones respetuosas de los derechos y la dignidad de las personas con discapacidad.\n- Identificar las características desarrollo-cognitivas, socioemocionales y comunicativas de estudiantes con diferentes tipos de discapacidad o necesidades educativas especiales, para adecuar estrategias de apoyo.\n- Diseñar planes de acompañamiento individualizados basados en la evaluación formativa, que integren adaptaciones curriculares, apoyos conductuales y mediaciones pedagógicas pertinentes al contexto escolar.\n- Implementar técnicas de observación, registro y evaluación del comportamiento y del progreso académico, utilizando instrumentos estandarizados y protocolos de registro confiables.\n- Colaborar y coordinar con docentes titulares, equipos interdisciplinares y familias para articular apoyos, comunicando hallazgos y proponiendo ajustes en el entorno y la práctica pedagógica.\n- Implementar estrategias de mediación y apoyo que promuevan la participación activa, la autonomía funcional y la inclusión social del alumno dentro del aula regular.\n- Evaluar la eficacia de las intervenciones de sombra mediante indicadores cualitativos y cuantitativos, ajustando las acciones en ciclos de mejora continua.\n- Promover entornos accesibles y diseñar ajustes razonables y recursos didácticos adaptados que favorezcan el aprendizaje y la interacción social.\n- Fomentar actitudes profesionales basadas en la ética, la confidencialidad, el respeto a la diversidad cultural y la toma de decisiones centrada en la persona.\n- Difundir prácticas basadas en evidencia y favorecer la investigación aplicada en contextos escolares para la mejora de modelos de acompañamiento y políticas inclusivas.\n\nEstos fines se desarrollan a través de una secuencia curricular que integra formación teórica avanzada, práctica supervisada en distintos niveles educativos y proyectos integradores que promueven la investigación aplicada en contexto.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Educación Especial (orientación: Sombra)", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "Lista de pasos conceptuales previos:\n- Revisar requisitoss normativos del Acuerdo 17/11/17 y la normativa educativa nacional aplicable.\n- Estructurar campos obligatorios del Anexo 1 y verificar coherencia entre ingreso, perfil y fines de aprendizaje.\n- Diseñar el marco curricular alineado con teorías de inclusión, UDL y prácticas basadas en evidencia.\n- Determinar la operatividad administrativa y los mecanismos de evaluación periódica.\n- Validar la carga horaria, duración de ciclos y practicum con estándares nacionales y de buenas prácticas.\n\nMarco teórico y justificación del modelo curricular:\n  El modelo curricular de la Licenciatura en Educación Especial con orientación en acompañamiento tipo sombra parte de la premisa de que la inclusión educativa es un derecho humano y una responsabilidad institucional que requiere profesionales formados de manera específica para acompañar procesos de aprendizaje y participación en contextos escolares regulares. Se sustenta en los siguientes referentes teóricos y conceptuales:\n  - Diseño Universal para el Aprendizaje (UDL): plantea principios para anticipar barreras y diseñar múltiples vías de acceso al currículo, favoreciendo la planificación de adaptaciones y apoyos que el profesional en sombra debe conocer y aplicar.\n  - Enfoque ecológico y bio-psicosocial: reconoce que las necesidades de los estudiantes emergen de la interacción entre individuo, familia, escuela y comunidad; por tanto, la intervención del profesional sombra se concibe como mediación contextual, no como sustitución del docente.\n  - Teorías socioculturales del aprendizaje (Vygotsky): sustentan la importancia del andamiaje y la zona de desarrollo próximo, herramientas clave para la intervención individualizada y para promover la autonomía del estudiante mediante mediación intencional.\n  - Modelos colaborativos y de co-intervención: el plan se apoya en evidencia sobre la efectividad de prácticas colaborativas entre docente titular, especialista y familia para lograr inclusión sostenible; el profesional sombra es formado para integrarse de forma articulada en estos equipos.\n  - Prácticas basadas en evidencia y evaluación formativa: el currículo incorpora métodos de observación sistemática, medición del progreso y diseño de intervenciones ajustadas a resultados, promoviendo la investigación aplicada y la cultura de evaluación.\n  - Perspectiva de derechos y normativa nacional: el modelo articula la formación con el marco legal mexicano en materia educativa y de discapacidad, así como con principios de ética profesional y confidencialidad.\n\n  La estructura curricular combina contenidos conceptuales, metodológicos y prácticos; integra prácticas supervisadas desde el primer año, seminarios de reflexión profesional, y proyectos integradores que vinculan investigación aplicada con mejora institucional. La formación busca que el egresado maneje herramientas para la evaluación, diseño e implementación de apoyos que fomenten la inclusión, la participación y el desarrollo integral del estudiante.", "justificacion_de_la_propuesta_curricular": "Modalidad mixta: explicación de implementación tecnológica, autogestión y flexibilidad espacio-temporal.\n- Plataforma tecnológica: El programa empleará un LMS institucional (por ejemplo, Moodle institucional o plataforma propietaria) que soporta contenidos asincrónicos (módulos temáticos, lecturas, foros), actividades evaluables y repositorio de recursos adaptativos. Además se dispondrá de herramientas para videoconferencia (Zoom/Teams) para sesiones sincrónicas, tutorías y supervisión de práctica.\n- Autogestión del aprendizaje: Las actividades asincrónicas incluirán guías de estudio, rúbricas claras y recursos multimedia. Se promoverá la metacognición mediante diarios de aprendizaje y portafolios electrónicos que permitan evidenciar competencias profesionales.\n- Flexibilidad espacio-temporal: El diseño mixto permite que agentes (estudiantes, tutores, docentes) articulen sesiones presenciales para prácticas y evaluación, con trabajo a distancia para contenidos teóricos y asesorías. Esto facilita el acceso y la posibilidad de estancias en centros educativos diversos.\n- Recursos didácticos y tecnológicos: Materiales accesibles (texto enriquecido, transcripciones, subtítulos, lecturas en formatos alternativos) y simuladores para entrenamiento de situaciones complejas. Herramientas para registro y análisis de observación (plantillas digitales, apps para registro de conductas) soportarán la formación práctica.\n- Vinculación con asignaturas: Las plataformas alojarán los recursos de cada asignatura, enlaces a prácticas supervisadas, y espacios de interacción interprofesional. Los procesos de evaluación combinarán evidencias en línea y en campo, asegurando validez y confiabilidad.\n- Soporte institucional: Tutorías académicas y tecnopedagógicas, acompañamiento para prácticas y mesas de análisis de casos. Se garantizará la interoperabilidad entre las actividades presenciales y virtuales para mantener coherencia pedagógica y cumplimiento de competencias.", "administracion_y_operatividad_del_plan_de_estudios": "Estructura administrativa y operativa:\n- Coordinación académica: Existirá una Coordinación de la Licenciatura responsable del seguimiento académico, la vinculación con centros de práctica y la supervisión de procesos de aseguramiento de la calidad.\n- Organización de la oferta: Diseño rígido en 9 semestres, con secuencia establecida de asignaturas obligatorias y optativas estructuradas por niveles formativos.\n- Carga por ciclo: La carga promedio por semestre se organizará en torno a 40 horas semanales efectivas, que incluyen docencia teórica, actividades prácticas y tiempo de estudio guiado.\n- Prácticas y estancias: Prácticas profesionales progresivas desde el segundo semestre, con incremento de horas prácticas hasta culminar en estancias intensivas en contextos escolares en el último año. Se definirá un manual de prácticas con perfiles de supervisores y criterios de evaluación.\n- Plantilla docente: Perfil docente con grado mínimo de maestría en áreas afines, experiencia en inclusión y prácticas de sombra, y formación en investigación aplicada. Se promoverá la actualización continua y la supervisión por expertos.\n- Gestión curricular: Cronograma anual, sesiones de coordinación docente por asignatura, sistema de registro de evidencias curriculares y control de avance estudiantil.\n- Siembra de asignaturas por semestre (ejemplo operativo): Semestre 1-3: fundamentos y diagnóstico; Semestre 4-6: intervención y metodologías; Semestre 7-9: prácticas intensivas, proyectos integradores y seminario de titulación.\n- Tutoría académica: Cada estudiante contará con un tutor académico y un tutor de prácticas, responsables de seguimiento del avance y apoyo en la articulación teoría-práctica.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Metodología de evaluación del plan de estudios:\n- Objetivo: Mantener actualización curricular y pertinencia disciplinar mediante evaluación anual y revisiones integrales cada tres años.\n- Instrumentos: Encuestas de egresados y empleadores, análisis de desempeño en prácticas, revisión de trayectorias académicas, indicadores de inserción laboral y evaluación por pares académicos.\n- Periodicidad: Informes anuales de seguimiento; revisión curricular bianual focalizada en asignaturas clave; evaluación integral cada 3 años con participación de comité externo.\n- Procedimiento: Recolección de datos cuantitativos y cualitativos, análisis por la coordinación, diseño de plan de mejora con responsables y plazos, seguimiento de indicadores y reporte público de avances.\n- Indicadores clave: Tasa de titulación, desempeño en prácticas (evaluación de supervisores), satisfacción de empleadores, cumplimiento de cargas académicas, actualización de contenidos y vinculación con evidencia científica.\n- Participación: Incluye estudiantes, docentes, empleadores, instituciones receptoras de prácticas y expertos externos para asegurar validez y pertinencia.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Dr. Francisco Javier Ortega, Rector"}', '18f49b67-8077-4371-be6e-2019a3be3562', true, 'IA', '{"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Textos largos y extensos", "descripcionEnfoqueAcademico": "Textos extensos acerca de la educación especial con base a ser especialista en sombra, considera que deberán ser una investigación profunda y las respuestas deben tener al menos 500 palabras"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai-generate-plan"}', NULL, NULL, '2026-02-27 22:28:10.322716+00', '2026-03-25 21:06:51.916127+00');
