INSERT INTO "public"."asignaturas" ("id", "plan_estudio_id", "estructura_id", "codigo", "nombre", "tipo", "creditos", "numero_ciclo", "linea_plan_id", "orden_celda", "datos", "contenido_tematico", "tipo_origen", "meta_origen", "creado_por", "actualizado_por", "creado_en", "actualizado_en", "horas_academicas", "horas_independientes", "estado", "criterios_de_evaluacion", "prerrequisito_asignatura_id", "search_vector") VALUES
	('48e962bd-4dd5-49f5-bc69-d8604d69384b', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'LESE102', 'Desarrollo y diversidad neuropsicológica', 'TRONCAL', 6, 4, '32708950-6f54-48e2-b0e2-a205686a2ec7', NULL, '{"ciclo": "Segundo ciclo (TRONCAL)", "clave_de_la_asignatura": "LESE102", "criterios_de_evaluacion": "Exámenes parciales teóricos 25%; Proyecto integrador (evaluación e intervención de caso) 30%; Portafolio con informes neuropsicológicos y análisis de casos 20%; Talleres prácticos y demostraciones 15%; Participación y seminarios dirigidos 10%. Total 100%.", "fines_de_aprendizaje_o_formacion": "Proveer al estudiante de conocimientos y habilidades para comprender las bases neurobiológicas del desarrollo infantil, identificar perfiles neuropsicológicos asociados a discapacidades y trastornos del desarrollo, seleccionar y aplicar instrumentos de evaluación adecuados, y diseñar intervenciones y planes de inclusión basados en evidencia que integren perspectiva familiar e interdisciplinaria.", "modalidades_tecnologicas_e_informaticas": "Uso de plataforma educativa (LMS) para materiales, actividades y foros; videoconferencia para seminarios y supervisión; recursos multimedia (lecturas, cápsulas en video); software de presentación y procesamiento de datos (p. ej., hojas de cálculo, R/SPSS); acceso a baterías de evaluación neuropsicológica informatizadas y bancos de casos clínicos. Para modalidades mixtas o a distancia se garantizará acceso a bibliografía digital, herramientas de evaluación remota y entornos seguros para compartir informes.", "actividades_de_aprendizaje_independientes": "Lecturas críticas de artículos y capítulos; elaboración de informes neuropsicológicos a partir de casos; preparación del proyecto integrador (evaluación y plan de intervención); análisis estadístico básico de datos de evaluación; diarios de reflexión sobre práctica clínica y ética; estudio dirigido para exámenes parciales y preparación de seminarios.", "de