	('15b16f67-8580-4b63-85e6-d519d8885b76', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CIB306', 'Control en Tiempo Real y Adquisición de Datos', 'TRONCAL', 5, NULL, NULL, NULL, '{"ciclo": "Ciclo 8 (TRONCAL)", "clave_de_la_asignatura": "CIB306", "criterios_de_evaluacion": "Exámenes parciales (teoría y problemas): 25%; Proyecto final (implementación, informe y demostración en tiempo real): 30%; Prácticas de laboratorio y sus reportes: 20%; Tareas y ejercicios de simulación y análisis: 15%; Participación, entregas parciales y asistencia: 10%. Total: 100%.", "fines_de_aprendizaje_o_formacion": "Formar al estudiante para diseñar, implementar y validar sistemas de control en tiempo real con adquisición de datos, garantizando requisitos de latencia, determinismo y robustez. Al finalizar la asignatura el estudiante será capaz de seleccionar hardware y software adecuados, aplicar técnicas de programación y sincronización en entornos RTOS, procesar datos con restricciones temporales y realizar pruebas y validaciones (incluyendo HIL) para verificar el cumplimiento de requisitos de tiempo real y calidad de datos.", "modalidades_tecnologicas_e_informaticas": "Se emplearán entornos y herramientas como RTOS (por ejemplo FreeRTOS, RT-Linux), plataformas embebidas (microcontroladores y SBC), tarjetas DAQ industriales/comerciales, herramientas de modelado y simulación (MATLAB/Simulink), entornos de desarrollo integrados (IDE) para sistemas embebidos, herramientas de comunicación en tiempo real (EtherCAT, CAN, Ethernet determinista) y repositorios/gestión de versiones (Git). Se utilizará un LMS institucional para distribución de materiales, envío de tareas y retroalimentación. En modalidad mixta o no escolarizada será obligatorio el uso de acceso remoto a laboratorios virtuales y/o bancadas con acceso seguro para prácticas y pruebas.", "actividades_de_aprendizaje_independientes": "Lectura y estudio de documentación técnica y artículos especializados; desarrollo de tareas y ejercicios de simulación (modelado de control, análisis de latencia); diseño e implementación de módulos del proyecto final (codificación, pruebas unitarias); elaboración de reportes de laboratorio y documentación del proyecto; preparación para exámenes. Se estiman 44 horas de trabajo independiente distribuidas en estudio teórico, simulaciones y avance en proyecto/entregables.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Control en Tiempo Real y Adquisición de Datos", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales para presentación de conceptos y metodologías; sesiones prácticas en laboratorio con instrumentación y tarjetas DAQ para implementación y medición en tiempo real; sesiones guiadas de programación en RTOS y de integración hardware-software; demostraciones y análisis de casos; tutorías para asesorar el proyecto final; evaluaciones parciales en clase y retroalimentación continua."}', '[{"temas": [{"nombre": "Conceptos básicos de sistemas en tiempo real: latencia, jitter y determinismo", "horasEstimadas": 3}, {"nombre": "Requisitos temporales, métricas de rendimiento y modelos de tiempo", "horasEstimadas": 3}], "titulo": "Fundamentos de sistemas en tiempo real y adquisición de datos", "unidad": 1}, {"temas": [{"nombre": "Sensores, acondicionamiento de señal y conversión A/D y D/A", "horasEstimadas": 4}, {"nombre": "Plataformas de adquisición: tarjetas DAQ, buses (USB, PCIe, Ethernet) y consideraciones de muestreo", "horasEstimadas": 4}], "titulo": "Hardware y estrategias de adquisición de datos", "unidad": 2}, {"temas": [{"nombre": "Introducción a RTOS: tareas, interrupciones y manejo de recursos", "horasEstimadas": 4}, {"nombre": "Planificación y sincronización: algoritmos de scheduling, prioridad e inversión de prioridad", "horasEstimadas": 4}], "titulo": "Sistemas operativos en tiempo real y manejo de concurrencia", "unidad": 3}, {"temas": [{"nombre": "Algoritmos de control en tiempo real: PID y control en espacio de estados con restricciones temporales", "horasEstimadas": 5}, {"nombre": "Consideraciones de implementación: punto fijo, optimización de cómputo y manejo de deadlines", "horasEstimadas": 3}], "titulo": "Diseño e implementación de control en tiempo real", "unidad": 4}, {"temas": [{"nombre": "Canales de adquisición de datos: buffering, DMA y técnicas para evitar pérdida de muestras", "horasEstimadas": 4}, {"nombre": "Procesamiento en tiempo real: filtrado, transformadas y transmisión determinista (EtherCAT, CAN, RTPS)", "horasEstimadas": 4}], "titulo": "Procesamiento de datos y comunicación de baja latencia", "unidad": 5}, {"temas": [{"nombre": "Pruebas en tiempo real: benchmarking, pruebas de latencia, HIL y validación de requisitos temporales", "horasEstimadas": 6}, {"nombre": "Desarrollo e integración del proyecto final: diseño, implementación y documentación", "horasEstimadas": 6}], "titulo": "Validación, pruebas y proyecto integrador", "unidad": 6}, {"temas": [{"nombre": "Seguridad funcional y normativas aplicables a sistemas en tiempo real", "horasEstimadas": 3}, {"nombre": "Estudios de caso de aplicaciones industriales y emergentes en control en tiempo real", "horasEstimadas": 3}], "titulo": "Seguridad, normativas y estudios de caso", "unidad": 7}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "usage": {"input_tokens": 1150, "total_tokens": 3877, "output_tokens": 2727, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 1280}}, "responseId": "resp_0b2b5db0454706640069a1b0c6bc3c81a0b9605c38a749f5f5", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Diseño de sistemas de control en tiempo real, adquisición y procesamiento de datos con requisitos de latencia y determinismo."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-27 14:57:08.739803+00', '2026-03-26 14:13:13.144237+00', 56, 44, 'borrador', '[]', NULL, '''1'':415B ''10'':58B ''100'