	('bd68b521-1338-42ab-95bf-639006e7f582', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CIB402', 'Proyecto de Integración Hardware-Software Industrial', 'OBLIGATORIA', 8, NULL, NULL, NULL, '{"ciclo": "Ciclo 8", "clave_de_la_asignatura": "CIB402", "criterios_de_evaluacion": "Diseño y documentación técnica del proyecto: 20%; Implementación de hardware (dispositivos y PCB): 20%; Desarrollo de firmware/software y calidad del código: 25%; Integración, pruebas y resultados de validación: 20%; Presentación, demostración y defensa del proyecto: 10%; Participación, bitácoras y entregables parciales: 5%.", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura, el estudiante será capaz de concebir, diseñar, implementar y validar un sistema industrial integrado que combine electrónica de potencia y señal, plataformas de control (microcontroladores/PLCs), comunicaciones industriales y software embebido. Desarrollará competencias para tomar decisiones de diseño, aplicar normas de seguridad y confiabilidad, elaborar documentación técnica completa y llevar a cabo la puesta en marcha y defensa de un proyecto industrial real o simulado.", "modalidades_tecnologicas_e_informaticas": "Clases presenciales en laboratorio con estaciones de trabajo equipadas (osciloscopios, analizadores lógicos, fuentes, bancos de carga), acceso a kits de desarrollo y PLCs, software de diseño electrónico (ECAD/PCB), simuladores SPICE/RTOS y entornos de programación embebida (IDE para microcontroladores). Plataforma LMS para entrega de actividades, repositorio Git para control de versiones, herramientas de gestión de proyectos (Trello/Planner) y videoconferencia para seguimiento. Conexiones a redes de prueba y herramientas de análisis de tráfico para prácticas de comunicaciones y ciberseguridad.", "actividades_de_aprendizaje_independientes": "Búsqueda y estudio de documentación técnica y normas; simulación de circuitos y algoritmos de control; diseño y verificación de PCB; desarrollo y prueba de módulos de firmware en entornos locales; preparación de documentación técnica (manuales, especificaciones y plan de pruebas); elaboración de reportes de avance y preparación de la demostración final.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Proyecto de Integración Hardware-Software Industrial", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Sesiones de laboratorio guiadas para diseño y montaje de prototipos; talleres de programación embebida y configuración de PLCs; revisión de diseño y code reviews semanales; prácticas de integración y pruebas supervisadas; asesorías de gestión del proyecto, seguridad y normas; ensayos de puesta en marcha y simulacros de defensa final con retroalimentación del académico."}', '[{"temas": [{"nombre": "Introducción al proyecto integrador y definición de alcance", "horasEstimadas": 4}, {"nombre": "Requisitos funcionales y de rendimiento", "horasEstimadas": 4}, {"nombre": "Selección de arquitectura hardware y componentes", "horasEstimadas": 4}, {"nombre": "Normas, seguridad eléctrica y confiabilidad en entornos industriales", "horasEstimadas": 4}], "titulo": "Análisis y especificación del sistema industrial", "unidad": 1}, {"temas": [{"nombre": "Sensores y transductores: selección y acondicionamiento de señal", "horasEstimadas": 6}, {"nombre": "Actuadores y drivers de potencia: diseño y protección", "horasEstimadas": 6}, {"nombre": "Fuentes de alimentación industriales y gestión energética", "horasEstimadas": 6}], "titulo": "Diseño electrónico para aplicaciones industriales", "unidad": 2}, {"temas": [{"nombre": "Microcontroladores y PLCs: características y criterios de selección", "horasEstimadas": 6}, {"nombre": "Diseño de PCB para entornos industriales y prácticas de ensamblado", "horasEstimadas": 6}, {"nombre": "Interfaces físicas: buses industriales, aislamiento y protección electromagnética", "horasEstimadas": 6}], "titulo": "Plataformas de control y diseño de placas", "unidad": 3}, {"temas": [{"nombre": "Programación embebida en tiempo real y uso de RTOS", "horasEstimadas": 6}, {"nombre": "Diseño y sintonización de controladores PID y avanzados", "horasEstimadas": 6}, {"nombre": "Implementación de funciones de seguridad y supervisión", "horasEstimadas": 6}], "titulo": "Desarrollo de firmware y estrategias de control", "unidad": 4}, {"temas": [{"nombre": "Redes industriales y arquitecturas de comunicación", "horasEstimadas": 4}, {"nombre": "Protocolos clave: Modbus, Profinet, OPC UA y sus aplicaciones", "horasEstimadas": 6}, {"nombre": "IIoT, telemetría y consideraciones de seguridad en redes industriales", "horasEstimadas": 6}], "titulo": "Comunicaciones y ciberseguridad industrial", "unidad": 5}, {"temas": [{"nombre": "Integración HW-SW: pruebas funcionales, de integración y validación", "horasEstimadas": 4}, {"nombre": "Gestión del proyecto, documentación técnica y normas de entrega", "horasEstimadas": 3}, {"nombre": "Puesta en marcha, demostración y defensa del proyecto integrador", "horasEstimadas": 3}], "titulo": "Integración, pruebas y entrega del proyecto", "unidad": 6}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "usage": {"input_tokens": 1146, "total_tokens": 3787, "output_tokens": 2641, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 1216}}, "responseId": "resp_0659d9630024d1ca0069a1b0c6fa0c8195a04b78b79d447693", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Desarrollo integrador de un sistema industrial completo que combine diseño electrónico, firmware, comunicaciones y control."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-27 14:57:08.739803+00', '2026-03-26 14:13:13.144237+00', 96, 80, 'borrador', '[]', NULL, '''1'':395B ''10'':55B ''2'':436B ''20'':26B,33B,48B ''25'':41B ''3'':482B,593B,605B ''4'':358B,366B,375B,386B,526B,536B,581B ''5'':61B,567B ''6'':407B,418B,428B,448B,461B,472B,495B,506B,516B,548B,560B,6