	('4afb3a31-e84a-4a2a-ad43-b385fcf63916', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CYB302', 'Control Robusto y Estocástico', 'TRONCAL', 6, 1, NULL, NULL, '{"ciclo": "6 (TRONCAL)", "clave_de_la_asignatura": "CYB302", "criterios_de_evaluacion": "Exámenes parciales (2): 30%; Proyecto integrador (diseño, implementación y defensa): 25%; Examen final: 20%; Informes de laboratorio y ejercicios de simulación: 15%; Participación, exposiciones y actividades en clase: 10%. (Total 100%)", "fines_de_aprendizaje_o_formacion": "Proveer al estudiante de los fundamentos teóricos y herramientas prácticas para el diseño y análisis de controladores robustos y estocásticos. Al concluir la asignatura, el estudiante será capaz de modelar incertidumbres y ruido, evaluar estabilidad robusta (determinista y en sentido probabilístico), formular y resolver problemas H-infinito y LQG mediante LMIs y optimización convexa, desarrollar filtros robustos, y validar soluciones mediante simulación y experimentación en casos de estudio aplicados.", "modalidades_tecnologicas_e_informaticas": "Uso de MATLAB/Simulink (incluyendo Robust Control Toolbox y Control System Toolbox), Python (NumPy, SciPy, control, cvxpy), entornos Jupyter, solvers de SDP (por ejemplo, SeDuMi, SDPT3 desde YALMIP o CVX), herramientas de control robusto y análisis de incertidumbre, repositorios Git para gestión de código, plataforma LMS para entrega de tareas y foros, y herramientas de videoconferencia para tutorías y presentaciones.", "actividades_de_aprendizaje_independientes": "Lectura crítica de capítulos asignados y artículos; resolución de problemas teóricos; desarrollo de simulaciones y experimentos computacionales; preparación del proyecto integrador (diseño, implementación y reporte); prácticas con solvers de LMI y análisis numérico; revisión y estudio de herramientas de software recomendadas.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Control Robusto y Estocástico", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales con demostraciones y derivaciones formales; sesiones guiadas de resolución de problemas; prácticas de laboratorio computacional supervisadas (implementación de controladores y filtros, uso de solvers); seminarios sobre artículos y casos de estudio; tutorías para el proyecto integrador; evaluaciones parciales y retroalimentación."}', '[{"temas": [{"nombre": "Revisión de sistemas lineales: modelos en espacio de estados y funciones de transferencia", "horasEstimadas": 3}, {"nombre": "Normas, métricas de estabilidad y funciones de Lyapunov", "horasEstimadas": 3}, {"nombre": "Introducción a la probabilidad y procesos estocásticos aplicados al control", "horasEstimadas": 2}], "titulo": "Fundamentos matemáticos y modelado de incertidumbres", "unidad": 1}, {"temas": [{"nombre": "Tipos de incertidumbres: estructuradas y no estructuradas; modelado de perturbaciones", "horasEstimadas": 2}, {"nombre": "Teorema del pequeño ganancia, estabilidad robusta y passivity", "horasEstimadas": 3}, {"nombre": "Introducción al control H-infinito: objetivos y formulación básica", "horasEstimadas": 5}], "titulo": "Fundamentos del control robusto", "unidad": 2}, {"temas": [{"nombre": "Formulación matricial del problema H-infinito y ecuaciones de Riccati", "horasEstimadas": 4}, {"nombre": "Enfoques basados en LMI para diseño robusto", "horasEstimadas": 3}, {"nombre": "Interpretación en frecuencia y selección de filtros de ponderación", "horasEstimadas": 3}], "titulo": "Diseño H-infinito y métodos relacionados", "unidad": 3}, {"temas": [{"nombre": "Ecuaciones diferenciales estocásticas e introducción al cálculo de Itô", "horasEstimadas": 3}, {"nombre": "Control óptimo estocástico: teoría LQG", "horasEstimadas": 3}, {"nombre": "Filtrado de Kalman: formulación y propiedades", "horasEstimadas": 2}], "titulo": "Fundamentos de control estocástico", "unidad": 4}, {"temas": [{"nombre": "Formulaciones risk-sensitive y combinaciones H2/H-infinito en presencia de ruido", "horasEstimadas": 3}, {"nombre": "Estimación robusta y filtros con incertidumbre de modelo", "horasEstimadas": 3}, {"nombre": "Estabilidad en sentido medio-cuadrático y criterios probabilísticos", "horasEstimadas": 2}], "titulo": "Robustez en escenarios estocásticos", "unidad": 5}, {"temas": [{"nombre": "Planteamiento de problemas con LMI, solvers y verificación numérica", "horasEstimadas": 3}, {"nombre": "Optimización convexa y programación semidefinida aplicada al control", "horasEstimadas": 3}, {"nombre": "Cuestiones numéricas, reducción de modelos y validación por simulación", "horasEstimadas": 2}], "titulo": "Herramientas computacionales y LMIs", "unidad": 6}, {"temas": [{"nombre": "Control adaptativo y estimación de parámetros en presencia de incertidumbre", "horasEstimadas": 2}, {"nombre": "Modos deslizantes y técnicas robustas para sistemas no lineales", "horasEstimadas": 2}, {"nombre": "Visión general de μ-análisis, D-K iteration y gain-scheduling", "horasEstimadas": 2}], "titulo": "Temas avanzados en control robusto", "unidad": 7}, {"temas": [{"nombre": "Casos de estudio: vehículos autónomos, redes de control y sistemas críticos", "horasEstimadas": 2}, {"nombre": "Laboratorios de simulación: implementación de H-infinito, LQG y filtros robustos", "horasEstimadas": 2}, {"nombre": "Presentación y defensa del proyecto integrador", "horasEstimadas": 2}], "titulo": "Aplicaciones, simulaciones y proyecto integrador", "unidad": 8}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "usage": {"input_tokens": 1151, "total_tokens": 4585, "output_tokens": 3434, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 1728}}, "responseId": "resp_068d88af81f5c8770069a1b0c6d78c819e9a12c3f4c7ff8c05", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Fundamentos y técnicas para diseñar controladores robustos y estocásticos que garanticen estabilidad frente a incertidumb