	('5df8f36f-6bd6-41ce-beac-63e3bc2736c0', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CIB-EMB101', 'Software para Sistemas Embebidos', 'TRONCAL', 6, 4, 'cabe3be1-346a-4660-b15e-6b6051c4e2b6', NULL, '{"ciclo": "Cuarto ciclo", "clave_de_la_asignatura": "CIB-EMB101", "criterios_de_evaluacion": "Prácticas de laboratorio y ejercicios (40%), Proyecto final de integración (30%), Examen teórico-práctico (20%), Tareas, informes y participación (10%). Total 100%.", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura el estudiante será capaz de desarrollar software para microcontroladores usando C/C++ y Python (MicroPython/CircuitPython), diseñar e implementar controladores de periféricos, establecer comunicaciones serie (UART, SPI, I2C) y aplicar técnicas de depuración y diagnóstico en plataformas embebidas. (Asignatura troncal; 6 créditos: 4 horas académicas presenciales y 8 horas independientes).", "modalidades_tecnologicas_e_informaticas": "Recursos: placas de desarrollo (STM32, ESP32, Raspberry Pi Pico), toolchains y compiladores (GCC ARM, toolchains para ESP), entornos y extensiones (VS Code, PlatformIO, Arduino IDE), depuradores y herramientas (GDB, OpenOCD, J-Link, ST-Link), analizadores lógicos y osciloscopio, terminales serie (PuTTY, minicom), simuladores/emuladores y repositorios de código (Git/GitHub). Para la modalidad mixta o no escolarizada se emplearán entornos virtuales, acceso remoto a placas y laboratorios virtuales.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas y estudio de manuales de microcontroladores; resolución de ejercicios de programación en C/C++ y Python; desarrollo y prueba de drivers para periféricos; diseño y documentación del proyecto final; realización de informes de laboratorio; prácticas con herramientas de depuración disponibles; participación en foros y revisión de material digital.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Software para Sistemas Embebidos", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales para presentación de conceptos y arquitecturas; sesiones prácticas en laboratorio con montaje de placas y programación en vivo; talleres guiados de desarrollo de drivers y comunicaciones; demostraciones de depuración con JTAG/SWD y análisis con osciloscopio/analizador lógico; tutorías para el proyecto final y revisiones de avances."}', '[{"temas": [{"nombre": "Introducción a sistemas embebidos: arquitecturas, restricciones y modelos de ejecución", "horasEstimadas": 1}, {"nombre": "Nuevo tema", "horasEstimadas": 2}], "titulo": "Fundamentos y entorno de desarrollo", "unidad": 1}, {"temas": [{"nombre": "Programación en C/C++ para microcontroladores: estructura de proyectos, manejo de memoria y drivers básicos", "horasEstimadas": 1}, {"nombre": "Python en microcontroladores (MicroPython/CircuitPython) y comunicaciones serie: UART, SPI, I2C", "horasEstimadas": 1}], "titulo": "Programación y manejo de periféricos", "unidad": 2}, {"temas": [{"nombre": "Técnicas de depuración en plataformas embebidas: JTAG/SWD, GDB/OpenOCD; uso de osciloscopio y analizador lógico; integración y pruebas del sistema", "horasEstimadas": 1}], "titulo": "Depuración, pruebas e integración", "unidad": 3}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "usage": {"input_tokens": 1158, "total_tokens": 3636, "output_tokens": 2478, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 1600}}, "responseId": "resp_0f157e45c1eb391200699f98bebf9c819395176225457b2391", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Programación en C/C++ y Python para microcontroladores, manejo de periféricos, comunicaciones serie y técnicas de depuración en plataformas embebidas."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-26 00:50:04.132967+00', '2026-03-26 14:13:13.144237+00', 4, 8, 'borrador', '[]', NULL, '''1'':306B,319B,337B,350B,381B ''