	('784a2af2-8828-4c96-992d-339ede5e5b92', '3ebc1d1c-e950-4a6e-948f-bb89efa40e77', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'MKT-EXP305', 'Diseño experimental y pruebas A/B para mercados', 'TRONCAL', 5, NULL, NULL, NULL, '{"ciclo": "Troncal", "clave_de_la_asignatura": "MKT-EXP305", "criterios_de_evaluacion": "Participación y actividades en clase: 10%; Cuestionarios y ejercicios prácticos: 15%; Tareas y laboratorios de implementación: 20%; Examen parcial teórico-práctico: 20%; Proyecto final (diseño, ejecución simulada/real y reporte de resultados): 35%. Total: 100%.", "fines_de_aprendizaje_o_formacion": "Formar profesionales capaces de diseñar, implementar y analizar experimentos y pruebas A/B en contextos de marketing digital para optimizar campañas y decisiones comerciales. El estudiante será competente en definir métricas relevantes, calcular tamaños de muestra, ejecutar pruebas en entornos reales, analizar resultados aplicando métodos estadísticos (frecuentistas y bayesianos), identificar y controlar sesgos, y aplicar criterios éticos y regulatorios en experimentación con usuarios.", "modalidades_tecnologicas_e_informaticas": "Uso de plataformas de experimentación (p. ej. Optimizely, VWO, LaunchDarkly), herramientas de analítica (Google Analytics, Mixpanel), entornos de análisis estadístico (R, Python/Jupyter), bases de datos y pipelines ETL, control de versiones (Git), plataformas de visualización (Tableau, Power BI) y herramientas colaborativas (Slack, Google Workspace). Para la modalidad mixta o a distancia se requerirá conexión estable, entorno virtual de laboratorios y acceso a datos de prueba anonimizados.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas de artículos y guías técnicas, resolución de ejercicios de cálculo de potencia y análisis estadístico, implementación de pruebas en entornos de laboratorio, preparación del proyecto final (diseño experimental, recolección/uso de datos simulados o reales, análisis e informe), revisión por pares y estudio de casos de la literatura.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Diseño experimental y pruebas A/B para mercados", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales sobre teoría y casos; sesiones prácticas guiadas en laboratorio para instrumentación y análisis; talleres de diseño de experimentos y revisión crítica; sesiones de equipo para desarrollo del proyecto final; presentaciones y defensa de proyectos con retroalimentación."}', '[{"temas": [{"nombre": "Introducción a los experimentos y pruebas A/B: objetivos y casos de uso", "horasEstimadas": 2}, {"nombre": "Métricas clave y definición de KPI para pruebas", "horasEstimadas": 2}, {"nombre": "Calidad de datos y preparación para experimentos", "horasEstimadas": 2}], "titulo": "Fundamentos de experimentación en marketing", "unidad": 1}, {"temas": [{"nombre": "Principios de aleatorización y asignación de unidades", "horasEstimadas": 3}, {"nombre": "Diseños factoriales, multivariantes y segmentación", "horasEstimadas": 3}, {"nombre": "Tamaño de muestra y potencia estadística", "horasEstimadas": 2}, {"nombre": "Bloqueo, estratificación y manejo de covariables", "horasEstimadas": 2}, {"nombre": "Pruebas piloto y validación previa", "horasEstimadas": 2}], "titulo": "Diseño experimental", "unidad": 2}, {"temas": [{"nombre": "Arquitectura de experimentación: front-end, back-end y flags", "horasEstimadas": 3}, {"nombre": "Instrumentación y seguimiento: eventos, cohortes y atribución", "horasEstimadas": 3}, {"nombre": "Asignación de tráfico, ramp-up y control de calidad en producción", "horasEstimadas": 2}, {"nombre": "Integración con pipelines de datos y testing automatizado", "horasEstimadas": 2}], "titulo": "Implementación de pruebas A/B en plataformas", "unidad": 3}, {"temas": [{"nombre": "Planteamiento de hipótesis, pruebas de significancia y errores tipo I/II", "horasEstimadas": 3}, {"nombre": "Intervalos de confianza, tamaños del efecto y métricas prácticas", "horasEstimadas": 3}, {"nombre": "Métodos bayesianos y comparativa con enfoques frecuentistas", "horasEstimadas": 2}, {"nombre": "Corrección por comparaciones múltiples y control del FDR", "horasEstimadas": 2}, {"nombre": "Pruebas secuenciales, stopping rules y problemas de peeking", "horasEstimadas": 2}], "titulo": "Análisis estadístico de resultados", "unidad": 4}, {"temas": [{"nombre": "Fuentes de sesgo: desviaciones de selección y supervivencia", "horasEstimadas": 2}, {"nombre": "Confusores, spillover y efectos indirectos", "horasEstimadas": 2}, {"nombre": "Violaciones de supuestos y diagnóstico de datos experimentales", "horasEstimadas": 2}, {"nombre": "Modelos de inferencia causal y análisis de uplift", "horasEstimadas": 2}], "titulo": "Validez, sesgos y causalidad", "unidad": 5}, {"temas": [{"nombre": "Ética en pruebas con usuarios: consentimiento, privacidad y daño mínimo", "horasEstimadas": 2}, {"nombre": "Cumplimiento normativo y manejo seguro de datos", "horasEstimadas": 2}, {"nombre": "Estudios de caso: campañas optimizadas y lecciones aprendidas", "horasEstimadas": 1}, {"nombre": "Presentación y defensa del proyecto final", "horasEstimadas": 1}], "titulo": "Aspectos éticos, regulatorios y casos aplicados", "unidad": 6}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "responseId": "resp_0940d0c7754514fe0069a1e6954bb481a088e6aaeffbbe102e"}, "iaConfig": {"archivosAdjuntos": [], "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Métodos de diseño experimental, pruebas A/B y análisis de resultados para optimizar campañas; incluye validación estadística, control de sesgos y ética en pruebas con usuarios."}, "generado_por": "ai_generate_subject_unified"}', NULL, NULL, '2026-02-27 18:46:42.854824+00', '2026-03-26 14:13:13.144237+00', 54, 72, 'borrador', '[]', NULL, '''/uso'':230B ''1'':354B,613B,622B ''10'':28B ''100'':57B ''15'':33B ''2'':325B,336B,346B,382B,391B,399B,404B,444B,455B,500B,511B,522B,541B,549B,560B,571B,592B,602B ''20