	('f4c16a62-3b5c-486e-b263-cd1c5fd57046', '3ebc1d1c-e950-4a6e-948f-bb89efa40e77', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'MKT-VIS304', 'Visualización avanzada de datos para marketing', 'OBLIGATORIA', 4, NULL, NULL, NULL, '{"ciclo": "6", "clave_de_la_asignatura": "MKT-VIS304", "criterios_de_evaluacion": "Proyecto final (dashboard interactivo aplicado a un caso de marketing) 50%; Actividades prácticas y entregables semanales (mini-dashboards, ejercicios de diseño) 30%; Presentación y defensa del proyecto 10%; Participación y evaluaciones formativas (críticas de pares, quizzes) 10%. Total: 100%", "fines_de_aprendizaje_o_formacion": "Que el estudiante diseñe, implemente y valide visualizaciones interactivas y dashboards orientados a marketing capaces de comunicar insights de mercado y apoyar decisiones comerciales. Desarrollará habilidades para seleccionar representaciones gráficas adecuadas, aplicar principios de usabilidad, integrar datos de diversas fuentes y optimizar visualizaciones para distintos públicos y canales.", "modalidades_tecnologicas_e_informaticas": "Uso de plataformas y herramientas: Tableau Desktop/Server, Power BI, bibliotecas web (Plotly, D3.js), Python (Pandas, Plotly, Altair) y/o R (ggplot2, Shiny). Entorno virtual de aprendizaje (LMS) para entrega y retroalimentación, repositorio de código (Git/GitHub), navegador web moderno, acceso a bases de datos de marketing (CSV/SQL/APIs) y servicios de hospedaje para despliegue de dashboards. Recursos multimedia para demostraciones y software de control de versiones para trabajo colaborativo.", "actividades_de_aprendizaje_independientes": "Revisión de lecturas y casos de estudio sobre visualización y storytelling; tutoriales prácticos en Tableau/Power BI y bibliotecas web; implementación de ejercicios guiados y retos de optimización; elaboración y refinamiento del proyecto final; análisis de datasets de marketing y preparación de materiales para la presentación.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Visualización avanzada de datos para marketing", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales cortas sobre principios de diseño y narrativa; sesiones prácticas guiadas en laboratorio para construcción de dashboards; talleres de usabilidad y pruebas de usuario; revisiones críticas de trabajos en clase (crítica guiada); tutorías para acompañar el desarrollo del proyecto final y presentación de casos reales del sector."}', '[{"temas": [{"nombre": "Percepción visual, encuadres y narrativa de datos para insights de mercado", "horasEstimadas": 1}], "titulo": "Principios de visualización y storytelling aplicado al marketing", "unidad": 1}, {"temas": [{"nombre": "Diseño y desarrollo de dashboards interactivos con Tableau, Power BI y bibliotecas web (Plotly/D3)", "horasEstimadas": 1}], "titulo": "Herramientas y técnicas interactivas", "unidad": 2}, {"temas": [{"nombre": "Métricas de usabilidad, pruebas A/B, performance y publicación en entornos comerciales", "horasEstimadas": 1}], "titulo": "Evaluación, optimización y despliegue de visualizaciones para la toma de decisiones", "unidad": 3}]', 'IA', '{"ai": {"model": "gpt-5-mini-2025-08-07", "responseId": "resp_027a42aa035d66610069a1e3b1ba808190808204bd46d69fc9"}, "iaConfig": {"archivosAdjuntos": [], "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Técnicas y herramientas para diseñar visualizaciones interactivas y dashboards que comuniquen insights de mercado y apoyen la toma de decisiones."}, "generado_por": "ai_generate_subject_unified"}', NULL, NULL, '2026-02-27 18:34:22.194933+00', '2026-03-26 14:13:13.144237+00', 3, 6, 'borrador', '[]', NULL, '''1'':318B,329B,347B,369B ''10'':50B,59B ''100'':61B ''2'':354B ''3'':383B ''30'':44B ''50'':32B ''6'':11B ''a'':27B,79B,157B ''a/b'':361B ''academico'':255B ''acceso'':156B ''acompanar'':291B ''actividades'':33B,185B,248B ''adecuadas'':97B ''al'':326B ''altair'':135B ''analisis'':222B ''aplicado'':26B,325B ''apl