	('ab4cf9d3-cacb-4a27-81e6-eebe6f2bf182', '3ebc1d1c-e950-4a6e-948f-bb89efa40e77', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'MKT-SOC320', 'Escucha social y análisis de redes', 'OBLIGATORIA', 6, NULL, NULL, NULL, '{"ciclo": "Sexto ciclo", "clave_de_la_asignatura": "MKT-SOC320", "criterios_de_evaluacion": "Proyecto final integrado con reporte técnico y dashboard (30%); Prácticas y ejercicios de laboratorio (25%); Examen parcial teórico-práctico (15%); Presentación y defensa del estudio de caso (15%); Participación, tareas y entregables individuales (15%). Total 100%.", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura, el estudiante será capaz de diseñar y operar procesos de escucha social, seleccionar y configurar fuentes y herramientas de monitoreo, aplicar técnicas de procesamiento de texto y análisis de sentimiento, construir y analizar redes sociales para detectar comunidades e influenciadores, y generar insights accionables presentados en reportes y dashboards. Además, integrará criterios de calidad y prácticas éticas en la recolección y análisis de datos para apoyar la toma de decisiones en marketing y comunicación.", "modalidades_tecnologicas_e_informaticas": "Empleo de plataformas de monitoreo y escucha (p. ej., Brandwatch, Talkwalker, Hootsuite, herramientas con API), APIs públicas (X/Twitter, Reddit u otras según disponibilidad), software de análisis y scripting (Python con librerías como pandas, scikit-learn, spaCy, NetworkX; o R con tidyverse y igraph), herramientas de visualización (Gephi, Tableau, Power BI o librerías de Python/R), entornos de desarrollo colaborativo (Jupyter Notebooks, Git/GitHub) y servicios en la nube para procesamiento y almacenamiento. Se privilegiará el uso de datasets reales y entornos que permitan reproducibilidad y control de accesos por privacidad.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas y revisión de artículos técnicos; preparación y limpieza de conjuntos de datos; desarrollo de scripts de preprocesamiento y modelos de sentimiento; análisis exploratorio de redes y visualizaciones; elaboración de informes parciales; preparación del proyecto final (recolección de datos, análisis, dashboard y reporte escrito); reflexión crítica sobre ética y sesgos en casos reales.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Escucha social y análisis de redes", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales sobre conceptos y metodologías; sesiones prácticas guiadas en laboratorio para configuración de herramientas y desarrollo de scripts; talleres de visualización y construcción de dashboards; sesiones de análisis de casos reales con discusión dirigida; tutorías para avance del proyecto final; presentaciones y defensa de trabajos con retroalimentación del académico."}', '[{"temas": [{"nombre": "Panorama de la escucha social: objetivos y alcances", "horasEstimadas": 2}, {"nombre": "Actores, canales y ecosistema mediático (medios tradicionales vs. digitales)", "horasEstimadas": 2}, {"nombre": "Indicadores y KPIs para monitoreo y análisis", "horasEstimadas": 2}], "titulo": "Fundamentos de escucha social y métricas clave", "unidad": 1}, {"temas": [{"nombre": "Fuentes relevantes: redes sociales, foros, blogs y medios", "horasEstimadas": 3}, {"nombre": "Herramientas y plataformas de monitoreo: configuración y uso básico", "horasEstimadas": 3}, {"nombre": "Consideraciones de muestreo, representatividad y sesgos de datos", "horasEstimadas": 2}], "titulo": "Fuentes de datos y recolección", "unidad": 2}, {"temas": [{"nombre": "Preprocesamiento de texto: tokenización, lematización y normalización", "horasEstimadas": 3}, {"nombre": "Detección de idioma, manejo de jerga y emojis", "horasEstimadas": 2}, {"nombre": "Técnicas de análisis de sentimiento: enfoques lexicón vs. ML/Deep Learning", "horasEstimadas": 3}, {"nombre": "Extracción de tópicos y reconocimiento de entidades para enriquecer insights", "horasEstimadas": 2}], "titulo"