	('fe5eb09c-501b-4db6-b6d3-f02bdcfdc4b4', 'dc286072-c649-43aa-8a2f-aa3ef6166647', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'ASDF', 'Química Orgánica', 'OBLIGATORIA', 5, 8, 'bff47d5f-7a05-473b-bb07-0c4769f07dea', NULL, '{"ciclo": "Ciclo 1", "contenido_tematico": "1. Fundamentos de Química Orgánica\n\n1.1 Estructura y tipos de enlaces\\n1.2 Nomenclatura y representación de moléculas\\n1.3 Hidrocarburos: alifáticos y aromáticos\\n2. Química de biomoléculas y bioorganica\\n2.1 Carbohidratos: estructuras, funciones y recorridos metabólicos\\n2.2 Lípidos: propiedades, almacenamiento y señales\\n2.3 Aminoácidos y proteínas: enlaces peptídicos, estructuras y funciones biológicas\\n2.4 Nucleótidos y ácidos nucleicos: estructura, replicación y expresión genética\\n3. Transformaciones químicas relevantes para biología\\n3.1 Reacciones de adición, sustitución y eliminación relevantes para biomoléculas\\n3.2 Mecanismos y cinética en bioquímica\\n4. Técnicas y espectros\\n4.1 Espectroscopía (NMR, IR, MS) y aplicaciones en bioquímica\\n5. Metodología y ética de laboratorio, seguridad, diseño experimental y enfoque humano\\n5.1 Seguridad y buenas prácticas de laboratorio\\n5.2 Diseño experimental centrado en casos biomoleculares humanos", "clave_de_la_asignatura": "QO-101", "criterios_de_evaluacion": "- Examen parcial 1: 20%\\n- Examen parcial 2: 20%\\n- Laboratorio práctico: 25%\\n- Trabajo de investigación o informe crítico: 25%\\n- Participación y tareas: 10%", "fines_de_aprendizaje_o_formacion": "- Comprender fundamentos de química orgánica aplicados a contextos biomoleculares humanos y de salud.\\n\\n- Desarrollar la capacidad de diseñar e interpretar rutas de síntesis simples relevantes para biomoléculas.\\n\\n- Aplicar técnicas de análisis estructural y espectroscopía para confirmar estructuras de compuestos biomoleculares.", "modalidades_tecnologicas_e_informaticas": "- Plataformas de gestión de aprendizaje (LMS) para recursos, foros y entrega de trabajos.\\n- Software de química: ChemDraw, Avogadro, y herramientas de simulación.\\n- Simuladores de mecanismos y reacciones orgánicas.\\n- Laboratorios virtuales y análisis de datos experimentales remotos si aplica.", "actividades_de_aprendizaje_independientes": "- Lecturas dirigidas de textos y artículo sobre química orgánica en biología molecular.\\n- Resolución de ejercicios y problemas de mecánica de reacciones y espectros.\\n- Elaboración de un informe o mini-proyecto de revisión bibliográfica centrado en una molécula biomolecular.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "QUÍMICA ORGÁNICA", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "- Clases magistrales con explicación de conceptos clave y ejemplos aplicados a biología molecular.\\n- Resolución guiada de ejercicios de mecanismos y reacciones relevantes.\\n- Demostraciones de laboratorio y supervisión de prácticas básicas de síntesis y purificación de compuestos orgánicos.\\n- Análisis guiado de espectros de moléculas biomoleculares modelo.\\n- Discusión y revisión de artículos científicos focalizados en bioquímica orgánica."}', '[{"temas": [{"nombre": "Nuevo tema", "horasEstimadas": 2}], "titulo": "Nueva Unidad", "unidad": 1}]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1274, "total_tokens": 7438, "output_tokens": 6164, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5376}}, "responseId": "resp_0c254aaf80ff45630069939eba50e08197bdc8ee0af7b0f941", "conversationId": null}, "iaConfig": {"instruccionesAdicionalesIA": "No consideres elementos de animales pero si de humanos", "descripcionEnfoqueAcademico": "Relacionado con la química molecular biológica"}, "referencias": {"archivosReferenciaIds": [], "repositoriosReferencia": []}, "generado_por": "ai_generate_subject"}', NULL, NULL, '2026-02-16 22:49:06.043499+00', '2026-03-26 14:13:13.144237+00', NULL, NULL, 'borrador', '[]', NULL, '''-101'':138B ''1'':6B,9B,144B,394B ''10'':