	('626d1fab-1056-4a1f-8861-a93cea5fbdd3', '198c763b-9d97-423b-b13a-5713437fc81b', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'LLSE-305', 'Colaboración familia-escuela para intervención inclusiva', 'OBLIGATORIA', 6, 2, 'c32ca3be-e422-444a-a534-7f9af61e8d14', NULL, '{"ciclo": "Ciclo 3 - Educación inclusiva y fortalecimiento de la colaboración entre familias y escuelas", "clave_de_la_asignatura": "LLSE-305 - Colaboración familia-escuela para intervención inclusiva", "criterios_de_evaluacion": [{"criterio": "Participación activa y colaboración en sesiones de co-diseño (con familias y docentes): evidencia mediante actas de reunión, aportes documentados y seguimiento de compromisos", "porcentaje": 25}, {"criterio": "Diseño de un plan de intervención inclusiva con familia: entrega de plan co-diseñado, firmado y viable, con evidencias y alineación diagnóstica", "porcentaje": 30}, {"criterio": "Implementación y seguimiento de un plan en un caso práctico: implementación y seguimiento con progreso registrado, ajustes realizados y reportes de avance a las partes interesadas", "porcentaje": 25}, {"criterio": "Análisis crítico de un caso en base a evidencia y ética: análisis fundamentado en evidencia, principios éticos y consideraciones de privacidad, con recomendaciones y reflexión", "porcentaje": 20}], "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el/la estudiante será capaz de coordinar con familias y docentes la co-construcción de planes de apoyo y su seguimiento en contextos escolares inclusivos, promoviendo la participación y el aprendizaje equitativo. Específicamente: 1) Coordinar con familias y docentes la co-construcción de planes de intervención: entregar planes co-diseñados y firmados dentro de 15 días desde la identificación de necesidades, con evidencias (actas, plantillas, firmas) disponibles para al menos el 90% de los casos; 2) Facilitar la comunicación efectiva y el seguimiento del progreso: responder a consultas en ≤48 horas; realizar reuniones de seguimiento cada 4 semanas; satisfacción promedio de las partes ≥4.5/5 en encuestas trimestrales; 3) Promover aprendizaje equitativo y adaptaciones: aplicar adaptaciones para al menos 80% de los estudiantes y registrar progreso en metas; reducir la brecha de logro entre grupos a ≤0.2 desviación estándar al final del ciclo; 4) Garantizar ética profesional, privacidad y manejo de datos: obtener consentimiento informado y cumplir con la normativa, asegurando el uso responsable de TICs para facilitar la coordinación y el trabajo colaborativo entre actores educativos.", "modalidades_tecnologicas_e_informaticas": "Se emplearán plataformas de gestión de aprendizaje (LMS) para materiales y foros, videoconferencias síncronas (Zoom/Teams) para reuniones con familias y docentes, herramientas colaborativas (Google Workspace o Microsoft 365) para co-diseño de planes, y formatos accesibles (lectura fácil, PDF y documentos editables).", "actividades_de_aprendizaje_independientes": "1) Lecturas guiadas y revisión de documentos de casos reales: entregable = resumen crítico de 2 páginas; plazo = 1 semana; rúbrica = claridad, justificación y vínculo con resultados de aprendizaje; 2) Análisis de estudios de caso: entregable = informe analítico de 3–4 páginas con diagnóstico y recomendaciones; plazo = 2 semanas; rúbrica = calidad del análisis y uso de evidencia; 3) Elaboración de un plan de intervención hipotético en formato colaborativo (Google Docs/Sheets): entregables = borrador editable y versión final en PDF; plazo = 2 semanas; rúbrica = viabilidad, coherencia diagnóstica y alcance; 4) Revisión y reflexión de videos o material interactivo: entregable = reflexión escrita de 500–750 palabras; plazo = 1 semana; rúbrica = profundidad y conexión con principios éticos; 5) Participación asíncrona en foros: entregables = aportes y respuestas; requisito = al menos 3 publicaciones por semana; 6) Entrega de evidencias: todos artefactos deben incluir evidencias (registro de progreso, capturas) y presentarse en formato editable y PDF.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Colaboración familia-escuela para intervención inclusiva", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Sesiones presenciales o virtuales con el docente para discusión de casos, talleres de co-diseño de planes de apoyo con familias, simulaciones de reuniones de coordinación, retroalimentación y evaluación de avances en proyectos de intervención, y revisión de artefactos (plan de apoyo)."}', '[{"temas": [{"nombre": "Modelo de intervención inclusiva y marco normativo para la atención a la diversidad", "horasEstimadas": 6}, {"nombre": "Roles y responsabilidades de docentes, familias y otros actores", "horasEstimadas": 5}, {"nombre": "Comunicación efectiva, construcción de alianzas y gestión de conflictos", "horasEstimadas": 7}], "titulo": "Fundamentos de la colaboración familia-escuela para intervención inclusiva", "unidad": 1}, {"temas": [{"nombre": "Diagnóstico de necesidades y metas de aprendizaje", "horasEstimadas": 6}, {"nombre": "Co-diseño de planes de apoyo con familias", "horasEstimadas": 6}, {"nombre": "Implementación, seguimiento y ajuste de planes", "horasEstimadas": 6}], "titulo": "Diseño y seguimiento de planes de apoyo", "unidad": 2}, {"temas": [{"nombre": "Instrumentos de registro, monitoreo y evidencias", "horasEstimadas": 4}, {"nombre": "Privacidad, consentimiento y ética profesional en intervención", "horasEstimadas": 4}, {"nombre": "Casos prácticos y resolución de conflictos", "horasEstimadas": 4}], "titulo": "Herramientas, evaluación y ética", "unidad": 3}, {"temas": [{"nombre": "Evaluación de impacto a largo plazo y sostenibilidad", "horasEstimadas": 2}, {"nombre": "Transferencia y escalabilidad de planes a otros contextos educativos", "horasEstimadas": 2}, {"nombre": "Comunidades de aprendizaje y redes de apoyo entre familias y escuelas", "horasEstimadas": 2}], "titulo": "Sostenibilidad y transferencia de prácticas inclusivas",