	('52b51837-fe6c-4552-9500-efcf16071d9a', '05863c8a-2a93-42f9-a4b7-65cef2edfe72', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'MAT102', 'Álgebra lineal y geometría analítica', 'TRONCAL', 6, 1, '35e06a47-655d-4ce4-8b5f-52dc068c271c', NULL, '{"ciclo": "Segundo ciclo", "contenido_tematico": "Carga horaria: Horas académicas presenciales: 5; Horas de trabajo independiente: 6. A continuación se presentan los temas y subtemas, estructurados de forma lógica y secuencial: 1. Vectores y operaciones en espacios vectoriales; 1.1 Vectores en R^n, operaciones; 1.2 Distancia y norma; 1.3 Productos escalares; 2. Espacios vectoriales; 2.1 Definición, axiomas; 2.2 Subespacios; 2.3 Base y dimensión; 3. Transformaciones lineales; 3.1 Definición; 3.2 Matriz asociada a una transformación; 3.3 Núcleo e imagen; 3.4 Cambio de base; 4. Matrices y resolución de sistemas; 4.1 Operaciones con matrices; 4.2 Rango y resolución con Gauss; 4.3 Inversa; 5. Geometría analítica; 5.1 Coordenadas y sistemas de referencia en plan y espacio; 5.2 Rectas y planos; 5.3 Intersecciones de subespacios; 6. Aplicaciones y problemas; 6.1 Aplicaciones de transformaciones lineales; 6.2 Problemas de optimización lineal básica.", "clave_de_la_asignatura": "MAT102", "criterios_de_evaluacion": "Actividades de evaluación: - Exámenes parciales (2): 25% total (12.5% cada uno). - Examen final: 35%. - Tareas y ejercicios: 20%. - Participación y asistencia: 20%.", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante podrá: validar el razonamiento lógico y algebraico para resolver problemas que involucren vectores, matrices, espacios vectoriales y transformaciones lineales; aplicar técnicas de resolución de sistemas lineales y análisis geométrico en R^2 y R^3; interpretar resultados en contextos geométricos y de modelado; comunicar soluciones de forma clara y precisa.", "modalidades_tecnologicas_e_informaticas": "Recursos tecnológicos: plataforma de gestión del aprendizaje (LMS), computadoras con acceso a internet, software de álgebra lineal (Octave/NumPy/Python o MATLAB), herramientas de visualización (GeoGebra, matplotlib), procesadores de texto y presentaciones, pizarras interactivas, proyectores, acceso a repositorios de ejercicios y evaluaciones en línea.", "actividades_de_aprendizaje_independientes": "Estudio autónomo de conceptos teóricos; resolución de ejercicios propuestos de distinta dificultad; lectura de material didáctico y referencias; práctica de problemas de sistemas lineales; autoevaluación mediante cuestionarios y revisión de soluciones.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Álgebra lineal y geometría analítica", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales con resolución guiada de ejercicios; sesiones de discusión de problemas y ejemplos; talleres y prácticas en grupo con feedback del docente; tutorías para reforzar conceptos clave; resolución de ejercicios en tiempo real con retroalimentación del académico."}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1075, "total_tokens": 6593, "output_tokens": 5518, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 4800}}, "responseId": "resp_0c00e5dab5344ba200698e6ae8bc70819e83d70d92c00144d4", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Álgebra lineal, así como geometría analítica, Vectores, matrices, espacios vectoriales y transformaciones lineales"}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-13 00:05:59.544199+00', '2026-03-26 14:13:13.144237+00', 5, 6, 'borrador', '[]', NULL, '''1'':37B ''1.1'':44B ''1.2'':50B ''1.3'':54B ''12.5'':158B ''2'':57B,155B,214B ''2.1'':60B ''2.2'':63B ''2.3'':65B ''20'':167B,171B ''25'':156B ''3'':69B,217B ''3.1'':72B ''3.2'':74B ''3.3'':80B ''3.4'':84B ''35'':163B ''4'':88B ''4.1'':94B ''4.2'':98B ''4.3'':104B ''5'':17B,106B ''5.1'':109B ''5.2'':119B ''5.3'':123B ''6'':22B,127B ''6.1