	('0401ca75-ea1d-4422-b4f6-1beee8459c52', '79fba458-aea4-4ca8-ab76-943ede479f15', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'MS320', 'Modelado y Simulación', 'OBLIGATORIA', 4, 2, '2021b495-d369-4988-be1f-8aaf508932f5', NULL, '{"ciclo": "Tercer ciclo", "contenido_tematico": "1. Fundamentos de modelado y simulación\\n1.1 Conceptos esenciales\\n1.2 Tipos de modelos: deterministas y estocásticos\\n2. Modelado matemático\\n2.1 Formulación de problemas\\n2.2 Modelos de colas, redes y procesos de producción\\n3. Métodos de simulación\\n3.1 Simulación en tiempo discreto\\n3.2 Simulación continua\\n3.3 Verificación y validación de modelos\\n4. Diseño e implementación en software de simulación\\n4.1 Matlab/Simulink\\n4.2 Python y SimPy\\n4.3 AnyLogic y otras herramientas\\n5. Análisis de resultados y toma de decisiones\\n5.1 Análisis de sensibilidad y experimentos de diseño (DOE)\\n5.2 Métricas de rendimiento\\n6. Aplicaciones en sistemas productivos y logísticos\\n6.1 Optimización de operaciones\\n6.2 Gestión de colas y capacidad\\n7. Ética, reproducibilidad y documentación de modelos\\nCarga horaria: 60 horas académicas presenciales y 80 horas de estudio independiente.", "clave_de_la_asignatura": "MS320", "criterios_de_evaluacion": "Examen final 40%; Proyecto de modelado y simulación con entrega de código y reporte 30%; Tareas y ejercicios prácticos 15%; Presentación y defensa del proyecto 15%.", "fines_de_aprendizaje_o_formacion": "Al finalizar, el estudiante será capaz de: 1) comprender y diferenciar fundamentos de modelado matemático y simulación; 2) diseñar, implementar y validar modelos de simulación para sistemas reales; 3) analizar escenarios y tomar decisiones informadas; 4) aplicar herramientas computacionales (Matlab/Simulink, Python/SimPy, AnyLogic) para construir y ejecutar modelos; 5) comunicar resultados y conclusiones de manera clara; 6) trabajar de forma colaborativa en proyectos de modelado y simulación.", "modalidades_tecnologicas_e_informaticas": "Software y herramientas: Matlab/Simulink; Python (SimPy, NumPy, SciPy); AnyLogic; Excel con macros; Jupyter Notebooks; Git y repositorios remotos; plataformas de gestión del aprendizaje y videoconferencia; recursos de hardware para simulación (PCs con capacidad de cómputo moderada). Para modalidades no presenciales o mixtas, se requiere acceso a entornos de simulación y a materiales digitales.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas y revisión bibliográfica; resolución de ejercicios de modelado; construcción de modelos simples de casos prácticos; desarrollo de un proyecto de simulación de ciclo completo; estudio de casos de la industria; elaboración de informe de resultados y reporte técnico; estudio de DOE y análisis de sensibilidad.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Modelado y Simulación (Obligatoria)", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales breves para introducir conceptos; talleres prácticos guiados con software de simulación; laboratorios computacionales para construcción de modelos; revisión y discusión de casos de estudio; sesiones de asesoría para avance del proyecto; presentaciones parciales de avances y feedback del docente."}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1068, "total_tokens": 6982, "output_tokens": 5914, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5120}}, "responseId": "resp_0f7b2b0f1c5fd88100698f49ba541c8190b4120e0bacf9f6e1", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Técnicas de modelado matemático y simulación computacional para análisis de sistemas y apoyo a decisiones."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-13 15:56:39.845265+00', '2026-03-26 14:13:13.144237+00', 60, 80, 'borrador', '[]', NULL, '''1'':10B,182B ''15'':163B,169B ''2'':192B ''3'':203B ''30'':158B ''4'':210B ''40'':146B ''5'':222B ''6'':2