	('c056750a-df0b-4aec-a0e6-4face0a0cd13', '05863c8a-2a93-42f9-a4b7-65cef2edfe72', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CIC101', 'Metodos numéricos y computación científica', 'OBLIGATORIA', 5, 7, '35e06a47-655d-4ce4-8b5f-52dc068c271c', NULL, '{"ciclo": "Ciclo 2", "contenido_tematico": "1. Fundamentos de métodos numéricos y computación científica; 1.1 Representación numérica de problemas y discretización; 1.2 Errores numéricos: truncación y round-off; 2. Resolución de sistemas lineales; 2.1 Métodos directos: eliminación de Gauss y factorización LU; 2.2 Métodos iterativos: Jacobi, Gauss-Seidel, SOR; 2.3 Condicionamiento y estabilidad; 3. Interpolación y ajuste de curvas; 3.1 Interpolación polinomial (Lagrange y Newton); 3.2 Interpolación con splines cúbicos; 3.3 Ajuste de curvas y mínimos cuadrados; 4. Métodos de aproximación e integración numérica; 4.1 Aproximación de funciones y diferencias; 4.2 Integración numérica: reglas del trapecio y Simpson; 4.3 Estimación de errores y convergencia; 5. Análisis de errores y aplicaciones en ingeniería; 5.1 Análisis de errores en discretización y propagación de error; 5.2 Casos de ingeniería: simulación numérica y estudio de sensibilidad; 5.3 Implementación y herramientas de computación científica (Python/ MATLAB).", "clave_de_la_asignatura": "CIC101", "criterios_de_evaluacion": "1) Exámenes parciales y final: 40%; 2) Laboratorios y prácticas de programación: 30%; 3) Tareas y ejercicios de curso: 20%; 4) Proyecto o informe de aplicación en ingeniería: 10%", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante será capaz de: describir y explicar los fundamentos de métodos numéricos; implementar algoritmos para resolución de sistemas lineales e interpolación; analizar errores, estabilidad y convergencia; aplicar herramientas computacionales (Python/NumPy/SciPy o MATLAB) para resolver problemas de ingeniería; evaluar resultados y presentar informes técnicos.", "modalidades_tecnologicas_e_informaticas": "Entornos de programación: Python con NumPy/SciPy y MATLAB/Octave; entornos de desarrollo como Jupyter notebooks, IDEs; recursos de cómputo (laboratorio de cómputo y/o plataformas en la nube); herramientas de control de versiones; plataformas de entrega de tareas y evaluación; bibliotecas numéricas para álgebra lineal, integración y interpolación.", "actividades_de_aprendizaje_independientes": "Lecturas dirigidas y revisión de literatura; ejercicios de programación y simulación independientes; resolución de problemas de ingeniería; prácticas de simulación numérica; preparación de informes y revisión de documentación técnica;", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Métodos numéricos y computación científica", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales y prácticas guiadas; resolución de ejercicios en grupo; desarrollo de laboratorio de cómputo con supervisión; demostraciones de algoritmos y revisión de código; feedback y discusión de resultados de casos de ingeniería."}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1077, "total_tokens": 7691, "output_tokens": 6614, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5888}}, "responseId": "resp_0ff920af511a3e9b00698e6ae8e494819c9ec28e189161d369", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Algoritmos para aproximación numérica, resolución de sistemas lineales, interpolación y análisis de errores en problemas de ingeniería."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-13 00:05:59.544199+00', '2026-03-26 14:13:13.144237+00', 4, 6, 'borrador', '[]', NULL, '''1'':12B,157B ''1.1'':20B ''1.2'':27B ''10'':185B ''2'':9B,35B,163B ''2.1'':40B ''2.2'':49B ''2.3'':57B ''20'':176B ''3'':61B,170B ''3.1'':67B ''3.2'':73B ''3.3'':78B ''30'':169B ''4'':85B,177B ''4.1'':92B ''4.2'':98B ''4.3'':106B ''40'':162B ''5'':112B ''5.1'':120B ''5.2'':130B