	('52260576-55df-4fc6-9603-e8654d84bed7', '05863c8a-2a93-42f9-a4b7-65cef2edfe72', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'ITMI-610', 'Economía de Productos Digitales y Emprendimiento para Inmersión', 'OPTATIVA', 4, 4, '35e06a47-655d-4ce4-8b5f-52dc068c271c', NULL, '{"ciclo": "Optativa", "contenido_tematico": "1. Fundamentos de economía de productos digitales\\n1.1 Definición y alcance de los productos digitales inmersivos\\n1.2 Tecnología de inmersión (VR/AR/MR) y experiencia de usuario\\n1.3 Dinámica del mercado y modelos de negocio en la economía de la inmersión\\n2. Modelos de negocio y monetización para productos de inmersión\\n2.1 Modelos de ingresos: venta, suscripción, freemium, microtransacciones\\n2.2 Ecosistemas de productos y servicios complementarios\\n2.3 Estrategias de monetización escalables y sostenibles\\n3. Propuesta de valor, diseño y desarrollo de productos\\n3.1 Segmentación de clientes y necesidades de usuarios inmersivos\\n3.2 Propuesta de valor para productos inmersivos\\n3.3 Diseño y MVP de una experiencia o producto en VR/AR\\n4. Propiedad intelectual, regulación y ética\\n4.1 Derechos de autor, patentes y secretos comerciales\\n4.2 Licenciamiento de contenidos y uso de IP de terceros\\n4.3 Privacidad, ética y cumplimiento en datos de inmersión\\n5. Estrategias de mercado, lanzamiento y crecimiento\\n5.1 Análisis de mercado, competencia y tendencias\\n5.2 Canales de comercialización, alianzas y distribución\\n5.3 Go-to-market, pricing y estrategias de lanzamiento\\n6. Evaluación, métricas y gobernanza\\n6.1 Métricas de rendimiento y engagement\\n6.2 Cumplimiento legal y consideraciones éticas\\n7. Casos de estudio y prácticas aplicadas\\n7.1 Casos de éxito en productos de inmersión\\n7.2 Talleres de simulación de negocio y presentaciones\\n8. Talleres, prototipos y planes de negocio\\n8.1 Elaboración de plan de negocio para producto inmersivo\\n8.2 Presentación ante panel de evaluación", "clave_de_la_asignatura": "ITMI-610", "criterios_de_evaluacion": "40% Proyecto de negocio y plan de monetización para un producto inmersivo (trabajo en equipo); 25% Análisis de caso de mercado y defensa en clase; 15% Documentos de propiedad intelectual, licenciamiento y ética; 20% Participación, tareas prácticas y presentaciones de talleres", "fines_de_aprendizaje_o_formacion": "Al completar esta asignatura, el estudiante será capaz de: 1) comprender y aplicar modelos de negocio y monetización para productos digitales inmersivos; 2) analizar requerimientos de propiedad intelectual, licencias y regulaciones aplicables; 3) diseñar una propuesta de valor y un plan de negocio para un prototipo inmersivo; 4) desarrollar habilidades de análisis de mercado, toma de decisiones éticas y sostenibilidad del negocio; 5) realizar trabajo colaborativo en equipos multidisciplinarios y presentar resultados ante un panel.", "modalidades_tecnologicas_e_informaticas": "Se emplearán recursos como plataformas de aprendizaje en línea (LMS), herramientas de realidad virtual y aumentada (VR/AR/MR) para experiencias inmersivas, motores de desarrollo (Unity, Unreal Engine) para prototipos, herramientas de diseño y prototipado (Figma, Miro), hojas de cálculo (Excel/Sheets), herramientas de análisis de datos (Google Analytics, Tableau), herramientas de gestión de proyectos (Trello, Jira) y plataformas de videoconferencia y foros; acceso a bibliotecas de contenidos y casos de estudio sobre IP y marcos de regulación.", "actividades_de_aprendizaje_independientes": "72 horas de aprendizaje independiente: lectura y análisis de fundamentos económicos de productos digitales, revisión de casos de estudio, investigación de mercado para inmersiones, desarrollo de un plan de negocio y monetización, revisión de propiedad intelectual y licencias, elaboración de un MVP conceptual y prototipos en VR/AR, y preparación de la documentación de ética y cumplimiento, así como la presentación final.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Economía de Productos Digitales y Emprendimiento para Inmersión", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "48 horas de aprendizaje bajo conducción académica: clases magistrales y prácticas, talleres guiados, laboratorios de prototipos en VR/AR, análisis de casos en grupo, sesiones de retroalimentación y asesoría de un académico, y presentaciones de avances con evaluación continua."}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1083, "total_tokens": 8086, "output_tokens": 7003, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 5952}}, "responseId": "resp_0c0112a430ccf9a500698e6ae939bc81979d4f4e6eb0f5df9c", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Modelos de negocio, monetización, propiedad intelectual y estrategias de mercado para productos y servicios basados en tecnologías de inmersión."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-02-13 00:05:59.544199+00', '2026-03-26 14:13:13.144237+00', 48, 72, 'borrador', '[]', NULL, '''-610'':10A,253B ''1'':15B,312B ''15'':282B ''2'':325B ''20'':290B ''25'':272B ''3'':335B ''4'':350B ''40'':257B ''48'':546B ''5'':365B ''72'':461B ''a'':443B ''academica'':552B ''academico'':545B,576B ''acceso'':442B ''actividades'':457B,538B ''al'':303B ''alcance'':25B ''alianzas'':173B ''analisis'':163B,273B,354B,423B,468B,564B ''analizar'':326B ''analytics'':427B ''ante'':244B,375B ''aplicables'':334B ''aplicadas'':209B ''aplicar'':315B ''aprendizaje'':300B,388B,459B,464B,529B,540B,549B ''asesoria'':573B ''asi'':517B ''asignatura'':251B,306B,525B ''aumentada'':397B ''autor'':131B ''avances'':580B ''bajo'':541B,550B ''bibliotecas'':444B ''calculo'':419B ''canales'':170B ''capaz'':310B ''caso'':275B ''casos'':204B,211B,448B,477B,566B ''ciclo'':11B ''clase'':281B ''clases'':553B ''clave'':248B ''clientes'':98B ''colaborativo'':368B ''comerciales'':135B ''comercializacion'':172B ''como'':385B,518B