	('8cd2e6e4-edb8-4447-aa9c-a2d33587382c', '54760e2e-406d-483a-962d-875b6d3195fd', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'CIB401', 'Proyecto Integrador de Programación y Control', 'TRONCAL', 6, 9, 'e8de5e3f-3ac1-45bf-a1fb-454cca534f71', NULL, '{"ciclo": "Octavo (8)", "clave_de_la_asignatura": "CIB401", "criterios_de_evaluacion": "Diseño y planificación del proyecto: 15% | Desarrollo del prototipo (hardware y software): 35% | Integración y pruebas de desempeño: 25% | Documentación técnica y manual de usuario: 15% | Presentación y defensa del proyecto (demo y exposición): 10% (Total 100%)", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura, el estudiante será capaz de integrar conocimientos de programación, redes y control para concebir, desarrollar y validar un prototipo funcional; elaborar la documentación técnica correspondiente; ejecutar pruebas de desempeño y presentar resultados. Se busca consolidar competencias de diseño de sistemas embebidos, comunicación entre módulos, formulación y ajuste de estrategias de control, gestión de proyectos y trabajo colaborativo orientado a entregables profesionales.", "modalidades_tecnologicas_e_informaticas": "Recursos: entornos de desarrollo integrados (VS Code, PlatformIO), toolchains y SDKs para microcontroladores, simuladores y herramientas de modelado (MATLAB/Simulink o Python), sistemas de control de versiones (Git/GitHub/GitLab), plataformas de gestión de proyectos (Trello, Jira), herramientas de comunicación y diagnóstico de red (Wireshark), equipos de laboratorio (osciloscopio, analizadores lógicos), bancos de prueba y acceso al LMS institucional para entregas y foros. Se prevé uso de repositorios remotos y ambientes de CI para pruebas automatizadas cuando aplique.", "actividades_de_aprendizaje_independientes": "Investigación bibliográfica y técnica sobre tecnologías seleccionadas; desarrollo de módulos de software y firmware; ensamblaje y configuración de hardware; elaboración de planes de prueba y ejecución de experimentos; redacción de documentación técnica y manuales; gestión de repositorios y control de versiones; preparación de la presentación final y la demostración del prototipo.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Proyecto Integrador de Programación y Control", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Sesiones de definición y revisión de requerimientos; tutorías de diseño arquitectónico; laboratorios guiados para integración hardware-software; talleres de configuración de redes y diagnóstico; sesiones de validación de estrategias de control y ajuste; revisiones de avance (code reviews y pruebas dirigidas); evaluación presencial de la demo y retroalimentación para la mejora de la documentación."}', '[{"temas": [{"nombre": "Análisis de requerimientos funcionales y no funcionales", "horasEstimadas": 2}, {"nombre": "Arquitectura del sistema: módulos de control, comunicaciones y UI", "horasEstimadas": 2}, {"nombre": "Selección de hardware y plataformas de software", "horasEstimadas": 2}, {"nombre": "Planificación del proyecto, cronograma y gestión de riesgos", "horasEstimadas": 2}], "titulo": "Planificación y diseño del sistema integrador", "unidad": 1}, {"temas": [{"nombre": "Programación embebida: arquitectura, toolchain y buenas prácticas", "horasEstimadas": 3}, {"nombre": "Diseño de algoritmos de control (PID, control en lazo cerrado, discretización)", "horasEstimadas": 3}, {"nombre": "Integración de sensores y actuadores; adquisición y preprocesamiento de señales", "horasEstimadas": 2}], "titulo": "Desarrollo de software y diseño de control", "unidad": 2}, {"temas": [{"nombre": "Diseño de la red: topología, protocolos (TCP/IP, MQTT, CAN), calidad de servicio", "horasEstimadas": 2}, {"nombre": "Comunicaciones inalámbricas y cableadas: implementación y diagnóstico", "horasEstimadas": 3}, {"nombre": "Seguridad, sincronización y tolerancia a fallos en redes de control", "horasEstimadas": 3}], "titulo": "Redes y com