	('93aefc3a-f7ea-474b-9b9b-e2e155815c0f', '05863c8a-2a93-42f9-a4b7-65cef2edfe72', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'ITMI-606', 'Arquitectura de Software para Realidad Virtual y Aumentada', 'TRONCAL', 6, 6, '0a35f63e-a6d0-465a-94ce-ca2d7db1d239', NULL, '{"ciclo": "Sexto semestre", "contenido_tematico": "1. Fundamentos de Arquitectura de Software para VR/AR\n1.1. Requisitos de rendimiento, baja latencia y escalabilidad\n1.2. Arquitecturas para VR/AR: cliente/servidor, multicliente, streaming\n2. Patrones arquitectónicos para VR/AR\n2.1. Arquitecturas en capas\n2.2. Arquitecturas orientadas a servicios y microservicios\n2.3. Arquitecturas orientadas a eventos y streaming de datos\n2.4. Patrones para gestión de recursos y consistencia\n3. Integración con motores gráficos\n3.1. Interoperabilidad entre Unity/Unreal y la capa de aplicación\n3.2. Gestión de escenas, assets y pipelines de render\n3.3. Optimización de rendimiento en VR/AR\n3.4. Plugins y APIs para comunicación entre motor y servicios\n4. Comunicación cliente-servidor en VR/AR\n4.1. Modelos de red para VR/AR\n4.2. Latencia, predicción y sincronización\n4.3. Seguridad, autenticación y autorización\n5. Arquitectura para VR/AR escalable y eficiente\n5.1. Arquitecturas multiusuario y replicación de estados\n5.2. Streaming y balanceo de carga de contenidos\n5.3. Infraestructura en la nube, microservicios y CDN\n5.4. Resiliencia, tolerancia a fallos y observabilidad\n6. Laboratorios y estudio de casos\n6.1. Laboratorio de diseño de arquitectura\n6.2. Caso práctico: VR multijugador\n6.3. Caso práctico: rendimiento y escalabilidad\nCarga horaria: 64 horas académicas y 96 horas de trabajo independiente.", "clave_de_la_asignatura": "ITMI-606", "criterios_de_evaluacion": "Participación y asistencia: 10%; Talleres y laboratorios: 35%; Proyecto de arquitectura VR/AR: 25%; Examen teórico: 15%; Defensa/Examen práctico del proyecto final: 15%", "fines_de_aprendizaje_o_formacion": "Al finalizar la asignatura, el estudiante podrá diseñar y evaluar arquitecturas de software para aplicaciones de realidad virtual y aumentada, integrar patrones arquitectónicos con motores gráficos, y diseñar comunicaciones cliente-servidor eficientes y escalables para experiencias VR/AR multijugador.", "modalidades_tecnologicas_e_informaticas": "Entorno de desarrollo: Unity3D y/o Unreal Engine; lenguajes C#, C++, Python; herramientas de streaming y networking (Photon, Mirror, WebRTC); motores de render; herramientas de profiling; control de versiones (Git); plataformas VR/AR (Oculus, SteamVR, WebXR); soluciones en la nube (AWS/Azure/GCP); tecnologías de seguridad y autenticación; API REST/GraphQL; contenedores y orquestación opcional.", "actividades_de_aprendizaje_independientes": "Lecturas de artículos y papers sobre VR/AR, revisión de patrones de arquitectura, diseño de un microproyecto de arquitectura VR/AR, experimentación con una pequeña integración entre motor gráfico y servidor, evaluación de rendimiento y latencia.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Arquitectura de Software para Realidad Virtual y Aumentada (6 créditos)", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Conducción de clases magistrales, sesiones de laboratorio supervisadas, revisiones de diseño de arquitectura, asesoría de implementación del prototipo, defensa de entregables y retroalimentación focalizada."}', '[]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 1080, "total_tokens": 8798, "output_tokens": 7718, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 6912}}, "responseId": "resp_01db74aca9bf0c9e00698e6ae91e0481a2937500f749f75b86", "conversationId": null}, "iaConfig": {"descripcionEnfoqueAcademico": "Patrones arquitectónicos, integración con motores gráficos y comunicación cliente‑servidor para aplicaciones VR/AR escalables y eficientes."}, "generado_por": "ai_generate_subject_update_json"}', NULL, NULL, '2026-0