	('7ea81d9d-df61-407f-afa5-76ca14d91029', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'LESE108', 'Tecnologías y recursos educativos accesibles', 'OPTATIVA', 4, 1, '07a19d6f-a412-4993-b07d-4bc02b3d544a', NULL, '{"ciclo": "Optativa 21", "clave_de_la_asignatura": "LESE108", "criterios_de_evaluacion": "Actividades en clase y participación activa: 15%; Tareas prácticas y adaptaciones de materiales: 25%; Proyecto integrador de recurso accesible: 30%; Evaluación teórica (conceptos y normas): 15%; Portafolio de evidencias y autocorrección: 15%. (Total 100%)", "fines_de_aprendizaje_o_formacion": "Al concluir la asignatura, el estudiante será capaz de identificar y aplicar principios y normas de accesibilidad digital, seleccionar y usar tecnologías asistivas, adaptar y producir materiales educativos accesibles y diseñar recursos que fomenten la autonomía del estudiantado. Contribuye a formar profesionales capaces de integrar prácticas inclusivas en entornos de enseñanza y aprendizaje, garantizando equidad y cumplimiento de estándares técnicos y pedagógicos.", "modalidades_tecnologicas_e_informaticas": "Se emplearán plataformas LMS (Moodle, Canvas), editores de texto y presentaciones (Word, PowerPoint, Google Docs/Slides), herramientas de autoría (H5P, SCORM), software de accesibilidad y lectores de pantalla (NVDA, VoiceOver), herramientas de subtitulado y transcripción automática (Amara, YouTube, auto-caption), validadores y auditorías de accesibilidad (WAVE, axe), herramientas de edición multimedia (Audacity, OBS, editores de video) y entornos de colaboración en línea (Google Workspace, Teams). Se recomienda acceso a navegadores actualizados y a dispositivos con capacidades de lectura de pantalla para actividades prácticas.", "actividades_de_aprendizaje_independientes": "Lecturas sobre normativa y principios de accesibilidad; tutoriales y prácticas con lectores de pantalla y herramientas de subtitulado; adaptación de documentos y presentaciones; creación de un recurso multimedia accesible; pruebas con usuarios o pares y recolección de retroalimentación; preparación del proyecto integrador y portafolio de evidencias. Estimular la autoevaluación y el aprendizaje basado en la resolución de casos reales.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Tecnologías y recursos educativos accesibles", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Clases magistrales sobre normativa y pedagogía; demostraciones en vivo de tecnologías asistivas; talleres prácticos guiados para adaptar documentos y producir multimedia accesible; sesiones de laboratorio para evaluar accesibilidad con herramientas automatizadas y pruebas manuales; dinámicas de trabajo colaborativo y revisión por pares; asesoría y seguimiento del proyecto integrador; retroalimentación formativa continua."}', '[{"temas": [{"nombre": "Principios básicos de accesibilidad e inclusión 123", "horasEstimadas": 2}, {"nombre": "Normativa, estándares y pautas (WCAG, eIDAS, legislación educativa)", "horasEstimadas": 3}, {"nombre": "Impacto pedagógico y Diseño Universal para el Aprendizaje (DUA)", "horasEstimadas": 3}], "titulo": "Fundamentos de accesibilidad en educación digital", "unidad": 1}, {"temas": [{"nombre": "Lectores de pantalla y tecnologías asistivas", "horasEstimadas": 3}, {"nombre": "Herramientas de subtitulado, transcripción y audiodescripción", "horasEstimadas": 3}, {"nombre": "Extensiones y software de personalización de la interfaz (contraste, tamaño, navegación)", "horasEstimadas": 2}], "titulo": "Herramientas y tecnologías de apoyo", "unidad": 2}, {"temas": [{"nombre": "Diseño y edición de documentos accesibles (PDF, Word, PowerPoint)", "horasEstimadas": 4}, {"nombre": "Creación de contenidos multimedia accesibles (video, audio, imágenes)", "horasEstimadas": 2}, {"nombre": "Recursos interactivos y evaluaciones accesibles (H5P, SCORM, cuestionarios)", "horasEstimadas": 2}], "titulo": "Adaptación y producción de re