	('291d7b5c-beea-494d-b94b-9a37f75fbcc6', '198c763b-9d97-423b-b13a-5713437fc81b', '7856e9cc-9ac1-4a31-b93a-0624d4c5e1de', 'LLSE-302', 'Diseño Universal para el Aprendizaje y materiales accesibles', 'TRONCAL', 4, 2, '7021a138-5ae4-4231-86db-3d02ce1901d7', NULL, '{"ciclo": "Ciclo 3", "clave_de_la_asignatura": "LLSE-302", "fines_de_aprendizaje_o_formacion": "Aplicar los principios del Diseño Universal para el Aprendizaje (DUA) para crear y adaptar materiales didácticos accesibles que favorezcan la participación y autonomía de estudiantes con necesidades educativas, integrando buenas prácticas de accesibilidad, evaluación formativa y herramientas de apoyo.", "modalidades_tecnologicas_e_informaticas": "Se utilizarán plataformas y herramientas de gestión del aprendizaje (LMS), herramientas de autoría accesible y diseño inclusivo, lectores de pantalla (NVDA, JAWS), navegadores en modos de alto contraste, subtitulación y transcripción, verificación de accesibilidad (WAVE, axe-core) y herramientas de creación de materiales accesibles (texto claro, estructuras semánticas, descripciones de imágenes). Se contemplan entornos presenciales, mixtos o no escolares, con apoyo de tecnología para la inclusión.", "actividades_de_aprendizaje_independientes": "Actividades de aprendizaje independientes incluyen revisión de literatura, estudio de casos, análisis de normativas de accesibilidad y diseño, diseño de materiales prototipo, realización de auditorías de accesibilidad y desarrollo de guías de buenas prácticas. Estas actividades suman aproximadamente 64 horas de trabajo autónomo y complementan las 48 horas de aula.", "denominacion_de_la_asignatura_o_unidad_de_aprendizaje": "Diseño Universal para el Aprendizaje y materiales accesibles", "actividades_de_aprendizaje_bajo_conduccion_de_un_academico": "Durante las horas de conducción académica, se realizarán clases magistrales, análisis de casos, talleres prácticos, revisión de proyectos de diseño, asesoría individual y en grupo, y actividades de retroalimentación orientadas a lograr la aplicación de DUA en la creación de materiales accesibles."}', '[{"temas": [{"nombre": "Fundamentos del DUA y principios clave para la enseñanza inclusiva", "horasEstimadas": 6}, {"nombre": "Marco legal, estándares y principios de accesibilidad educativa", "horasEstimadas": 6}], "titulo": "Fundamentos y marco del Diseño Universal para el Aprendizaje (DUA) y accesibilidad", "unidad": 1}, {"temas": [{"nombre": "Diseño de contenidos accesibles: claridad, lenguaje inclusivo y estructuras", "horasEstimadas": 8}, {"nombre": "Estrategias de mediación y uso de medios múltiples (texto, audio, video, imágenes)", "horasEstimadas": 6}, {"nombre": "Evaluaciones y retroalimentación accesibles", "horasEstimadas": 4}], "titulo": "Diseño de materiales didácticos accesibles y estrategias de mediación", "unidad": 2}, {"temas": [{"nombre": "Herramientas y tecnologías de apoyo (lectores de pantalla, subtítulos, etc.)", "horasEstimadas": 8}, {"nombre": "Pruebas de accesibilidad y validación con usuarios", "horasEstimadas": 6}, {"nombre": "Plan de implementación institucional y gestión del cambio", "horasEstimadas": 4}], "titulo": "Implementación, validación y herramientas de apoyo para la accesibilidad", "unidad": 3}]', 'IA', '{"ai": {"model": "gpt-5-nano-2025-08-07", "responseId": "resp_045f8adc23bcf09e0069ab168dec0c81a39d8728e8fb8c9d33"}, "iaConfig": {"archivosAdjuntos": [], "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Aplicación del DUA para crear y adaptar materiales didácticos accesibles que favorezcan la participación y autonomía de estudiantes con necesidades educativas."}, "generado_por": "ai_generate_subject_unified"}', NULL, NULL, '2026-03-06 18:01:48.558777+00', '2026-03-26 14:13:13.144237+00', 48, 64, 'borrador', '[{"criterio": "Participación y asistencia en sesiones teóricas y prácticas", "porcentaje": 20}, {"criterio": "Actividades de aprendizaje independientes y entregables", "porcentaje": 25}, {"criter