	('8bb0fa5d-f9f5-453c-99f0-e38daa0efeb9', '68e057f9-9014-4736-aaa3-ccd6ca51a569', NULL, '2026-03-25 15:50:11.946624+00', 'ACTUALIZACION', 'criterios_de_evaluacion', '[]', '[{"criterio": "Participación y contribución en clase: asistencia, participación activa, colaboración y cumplimiento de normas éticas.", "porcentaje": 15}, {"criterio": "Prácticas dirigidas y role-play: ejecución de intervenciones simuladas, calidad de intervención, uso de guiones y retroalimentación formativa.", "porcentaje": 25}, {"criterio": "Informes de evaluación y recolección de datos: diseño y ejecución de la recolección de datos, análisis descriptivo básico, claridad y precisión del informe.", "porcentaje": 20}, {"criterio": "Plan de apoyo conductual individual (proyecto): diseño, implementación, monitoreo, toma de decisiones basadas en datos y revisión del plan.", "porcentaje": 25}, {"criterio": "Examen final teórico-práctico: evaluación de conocimientos teóricos y aplicación práctica de estrategias de apoyo conductual, razonamiento ético y profesional.", "porcentaje": 15}]', NULL, NULL),
	('569445b2-f86b-4eb4-a63f-8e5548da6c1d', '68e057f9-9014-4736-aaa3-ccd6ca51a569', NULL, '2026-03-25 17:07:07.246487+00', 'ACTUALIZACION_CAMPO', 'actividades_de_aprendizaje_bajo_conduccion_de_un_academico', '"Clases magistrales teórico-prácticas; demostraciones y análisis de casos; sesiones de role-play y retroalimentación; supervisión de prácticas y talleres de diseño de planes de apoyo; seminarios de discusión y trabajo en equipo para elaboración y evaluación de intervenciones."', '"Clases magistrales teóricas y prácticas; demostraciones y análisis de casos; sesiones de role-play con retroalimentación; supervisión de prácticas y talleres de diseño de planes de apoyo; seminarios de discusión y trabajo en equipo para la elaboración y evaluación de intervenciones."', NULL, NULL),
	('40acc312-c4c5-4850-825b-62b53215f1c8', '68e057f9-9014-4736-aaa3-ccd6ca51a569', NULL, '2026-03-25 17:07:07.246487+00', 'ACTUALIZACION_CAMPO', 'actividades_de_aprendizaje_independientes', '"Lectura crítica de artículos y guías basadas en evidencia; diseño y ajuste de planes de apoyo conductual; recolección y análisis de datos en contextos reales o simulados; reflexión y bitácora de práctica; realización de módulos en línea y preparación de presentaciones y del proyecto final."', '"Lecturas críticas de literatura basada en evidencia; diseño y ajuste de planes de apoyo conductual; recolección y análisis de datos en contextos reales o simulados; reflexión mediante bitácora de prácticas; realización de módulos en línea, preparación de presentaciones y desarrollo del proyecto final."', NULL, NULL),
	('f58ef685-d408-473d-9e85-d411052c9574', '68e057f9-9014-4736-aaa3-ccd6ca51a569', NULL, '2026-03-25 17:07:07.246487+00', 'ACTUALIZACION_CAMPO', 'fines_de_aprendizaje_o_formacion', '"Formar profesionales con competencias para diseñar, implementar y evaluar intervenciones basadas en evidencia para el manejo de conductas en el aula, empleando refuerzo positivo, estrategias proactivas y promoción de habilidades socioemocionales, garantizando prácticas éticas y colaboración con la comunidad educativa."', '"Formar profesionales capaces de diseñar, implementar y evaluar intervenciones basadas en evidencia para el manejo de conductas en el aula, promoviendo el refuerzo positivo, estrategias proactivas y el desarrollo de habilidades socioemocionales, con enfoque ético y en colaboración con la comunidad educativa."', NULL, NULL),
