INSERT INTO "public"."cambios_plan" ("id", "plan_estudio_id", "cambiado_por", "cambiado_en", "tipo", "campo", "valor_anterior", "valor_nuevo", "response_id") VALUES
	('9750ab31-f898-4e2e-971d-07e21bea6d50', '0e0aea4d-b8b4-4e75-8279-6224c3ac769f', '11111111-1111-1111-1111-111111111111', '2026-01-09 13:45:37.784586+00', 'CREACION', 'datos', NULL, '{"nivel": "Licenciatura", "nombre": "Ingeniería Cibernética", "area_de_estudio": "Tecnologías de la Información y la Comunicación (CMPE 2016)", "perfil_de_egreso": "Conocimientos: redes, sistemas, criptografía. Habilidades: pentesting, hardening, respuesta a incidentes. Actitudes: ética, responsabilidad.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Pensamiento lógico, bases de álgebra, nociones de programación y comunicación escrita.", "curso_propedeutico": null, "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato concluido; afinidad con matemáticas y computación.", "carga_horaria_a_la_semana": 40, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "2026-CIB-ING", "duracion_del_ciclo_escolar": "16", "fines_de_aprendizaje_o_formacion": "Formar profesionales capaces de diseñar, implementar y asegurar sistemas ciberfísicos y plataformas digitales.", "total_de_ciclos_del_plan_de_estudios": "8", "sustento_teorico_del_modelo_curricular": "Enfoque por competencias, aprendizaje basado en problemas y laboratorios.", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "Plan rígido con cargas sugeridas por semestre; asignaturas seriadas por áreas.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Revisión anual por comité académico; actualización por tendencias y retroalimentación de egresados."}', NULL),
	('565ef79e-4a20-42cd-9aa9-41fa22fd476d', '4660b774-a6e2-44f4-a340-747b41235c7c', NULL, '2026-01-23 22:00:33.119999+00', 'ACTUALIZACION', 'nombre', '"Ingeniería en Sistemas Domóticos (2026)"', '"Ingeniería en Sistemas Domóticos (2027)"', NULL),
	('e37fb4cc-1280-4d71-8d97-23e8d5c3162c', '0e0aea4d-b8b4-4e75-8279-6224c3ac769f', '11111111-1111-1111-1111-111111111111', '2026-01-23 22:37:05.875968+00', 'ACTUALIZACION', 'nivel', '"Licenciatura"', '"Maestría"', NULL),
	('4e1edec0-8723-403f-a856-6aa22505fc1f', '0e0aea4d-b8b4-4e75-8279-6224c3ac769f', '11111111-1111-1111-1111-111111111111', '2026-01-23 22:39:07.266896+00', 'ACTUALIZACION', 'conversation_id', NULL, '"123"', NULL),
	('c9a74e54-653d-4e21-a961-98acd3efcd0c', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'perfil_de_ingreso', '"Ingreso esperado para la Licenciatura en Física Médica: antecedentes académicos en bachillerato con fuerte formación en matemáticas y física (álgebra lineal, cálculo diferencial e integral, física general); habilidades de razonamiento lógico y resolución de problemas; aptitudes para trabajo colaborativo y cumplimiento de normas de seguridad y ética; interés en aplicaciones biomédicas y manejo básico de herramientas de laboratorio."', NULL, NULL),
	('82be7c12-5b7b-465e-9018-cea7f11f4213', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'programa_de_investigacion', 'null', NULL, NULL),
	('36a747b7-1105-4f8c-b9f5-0e59c73b1173', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'justificacion_de_la_propuesta_curricular', '"La necesidad de profesionales especializados en física médica que aporten diagnósticos precisos y tratamientos seguros justifica una formación que combine fundamentos teóricos sólidos con prácticas clínicas y laboratoriales. La modalidad mixta facilita la integración de laboratorios, simulaciones y aprendizaje autogestionado, manteniendo flexibilidad espacial y temporal para estudiantes trabajadores. Se incorporan plataformas tecnológicas, simuladores y experiencias clínicas supervisadas para asegurar la calidad educativa y la empleabilidad, alineándose con las metas y lineamientos del Acuerdo 17/11/17 y el marco de la SEP."', NULL, NULL),
	('ea313ce3-898f-40d5-9e6c-288d7f711009', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'perfil_de_egreso', '"Al finalizar el plan, el egresado estará equipado para: 1) Conocer y comprender fundamentos teóricos y prácticos de la física médica aplicados a diagnóstico y tratamiento; 2) Desarrollar habilidades de evaluación y diseño de protocolos clínicos en radiología, medicina nuclear y radioterapia; 3) Aplicar técnicas de dosimetría, calibración de equipos y control de calidad en contextos médicos; 4) Interpretar resultados de imágenes y de pruebas de diagnóstico por imagen con rigor científico; 5) Actuar con ética profesional, seguridad de pacientes y manejo responsable de información clínica; 6) Trabajar de forma colaborativa en equipos interdisciplinarios para la mejora continua de procesos en medios de salud."', NULL, NULL),
	('76a0e4dc-d93d-409b-8ce5-97400efcc51d', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'nivel', '"Licenciatura"', NULL, NULL),
	('6542239b-1d70-447c-a15f-569a9d7178b2', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'propuesta_de_evaluacion_periodica_del_plan_de_estudios', '"La evaluación periódica del Plan de Estudio se realizará de manera anual y cada tres años se revisará en conjunto con comités de docentes, estudiantes y empleadores. Se emplearán rúbricas de competencias, evaluaciones prácticas, portafolios, indicadores de empleabilidad y calidad de servicios, con mecanismos de retroalimentación y acciones correctivas para actualizar contenidos, métodos pedagógicos y recursos tecnológicos. Los resultados guiarán ajustes curriculares y la mejora institucional."', NULL, NULL),
	('e4f4992f-149b-44a3-860d-eccbaf7cbb65', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'carga_horaria_a_la_semana', '16', NULL, NULL),
	('56ae5448-0842-4b4f-97fe-5c29ca8fbd3f', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'area_de_estudio', '"Ciencias Físicas – Física Médica (CMPE 2016: Física)"', NULL, NULL),
	('90154137-ae23-4017-813f-d30c7b90443b', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'curso_propedeutico', '"Curso propedéutico de 4 semanas dirigido a reforzar fundamentos de cálculo, física general y conceptos básicos de biomedicina. Este curso se ofrece a la población con deficientes antecedentes en áreas de ciencias; su implementación se vincula como preparación para los cursos introductorios de la población clínica y técnica."', NULL, NULL),
	('9deff71b-4eaf-463e-be1b-9a8c6a127046', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'administracion_y_operatividad_del_plan_de_estudios', '"La administración del plan estará a cargo de la Dirección Académica y un Comité de Planes y Programas. Existirá un Responsable de Carrera, coordinadores de laboratorio y tutores. Se establecerá un mapa curricular con asignaturas y unidades de aprendizaje, criterios de evaluación y un ciclo de revisión anual para ajustes conforme a necesidades regionales y nacionales. Se dispondrá de un Comité de Acreditación interna para garantizar la congruencia entre plan, laboratorio y clínica."', NULL, NULL),
	('0a6bd6f5-e376-42c2-a72f-e86d7f24701e', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'sustento_teorico_del_modelo_curricular', '"El sustento teórico del plan se apoya en modelos de diseño curricular por competencias, aprendizaje basado en problemas y blended learning, con énfasis en la seguridad, la ética y la calidad en servicios de salud. Se integran marcos de referencia de educación superior y estándares SEP para garantizar pertinencia y rigor científico, así como la interoperabilidad con normativas de dispositivos médicos y protección radiológica."', NULL, NULL),
	('da561ec9-1156-46db-88cf-5d5a9e2f3fe7', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'duracion_del_ciclo_escolar', '"16 semanas por ciclo"', NULL, NULL),
	('f1d9cfc3-12bb-4a9d-8b78-affc1ff793b6', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'total_de_ciclos_del_plan_de_estudios', '"8"', NULL, NULL),
	('13779695-78e1-4f10-8ca2-16ee34b572c1', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'fines_de_aprendizaje_o_formacion', '":[\"Analizar fundamentos de física médica, radiación, dosimetría y protección radiológica para su implementación clínica.\",\"Diseñar protocolos de adquisición de imágenes y dosimetría en entornos clínicos con criterios de calidad.\",\"Aplicar técnicas de imagen médica y radioterapia cumpliendo normativas de protección y seguridad.\",\"Evaluar equipos y procesos de calibración, mantenimiento y control de calidad en laboratorios y unidades clínicas.\",\"Comunicar resultados, hallazgos y recomendaciones técnicas a equipos médicos y pacientes con claridad y ética.\",\"Integrar enfoques de investigación y mejora continua para optimizar resultados en radiología y medicina física.\"]"', NULL, NULL),
	('8b8fb619-54b7-4fa1-bf85-b604bee00472', 'ddf2203b-2f55-4a32-9ee6-a99a6ff5947e', NULL, '2026-01-27 15:34:16.6225+00', 'ACTUALIZACION_CAMPO', 'nombre', '"Física Médica"', NULL, NULL),
