	('761bc69b-0a28-4840-8ac8-ed6b77621454', '6756a45c-e6b7-477b-918d-821ad7efbc58', NULL, '2026-01-30 18:31:10.882192+00', 'CREACION', NULL, NULL, '{"id": "6756a45c-e6b7-477b-918d-821ad7efbc58", "datos": {"vigencia": "2026-2031", "area_de_estudio": "Ingeniería y Tecnología", "perfil_de_egreso": "Conocimientos: fundamentos de mecánica, electrónica, control, robótica, sensores y actuadores; Habilidades: diseño y simulación de sistemas mecatrónicos, integración de hardware y software, gestión de proyectos y comunicación técnica; Actitudes: ética profesional, seguridad, trabajo en equipo, aprendizaje continuo y enfoque a la mejora continua.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "Bachillerato en ciencias, tecnología o equivalente, con base sólida en matemáticas (álgebra, cálculo), física general y química; habilidades básicas de lectura técnica, razonamiento lógico y manejo de herramientas informáticas (al menos conceptos de programación y modelado).", "curso_propedeutico": null, "modalidad_educativa": "Mixta", "antecedente_academico": "Bachillerato en Ciencias y/o Tecnologías con promedio mínimo de 7.0; acceso preferente a carreras de ingeniería y tecnología; cumplimiento de requisitos de ingreso institucional.", "carga_horaria_a_la_semana": 28, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "IM-2026-LIC-MEC", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Analizar problemas de ingeniería desde una visión integral de mecánica, electrónica y control; Diseñar sistemas mecatrónicos que integren hardware y software; Implementar modelos y simulaciones para validación de desempeño; Evaluar alternativas de diseño considerando seguridad, costo y sostenibilidad; Aplicar metodologías de gestión de proyectos para desarrollo de prototipos; Integrar tecnologías de manufactura avanzada y robótica en entornos industriales; Desarrollar habilidades de comunicación técnica y trabajo en equipo en contextos multidisciplinarios.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Ingeniería Mecatrónica", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "El modelo curricular se fundamenta en un enfoque de ingeniería multidisciplinaria que integra principios de mecánica, electrónica, control, robótica y manufactura. Se sustenta en un continuum de aprendizaje basado en proyectos, ciencias de la ingeniería y prácticas de laboratorio, con énfasis en competencias profesionales y capacidad de adaptación tecnológica. Se alinea con el registro de planes de estudio vigente y con el marco de la CMPE 2016 para planes de estudio por campos de formación académica.", "justificacion_de_la_propuesta_curricular": "La modalidad Mixta exige flexibilidad para autogestión y aprendizaje autónomo, soportada por plataformas tecnológicas y recursos digitales. La propuesta aprovecha Moodle u otras LMS, laboratorios virtuales y contenidos asincrónicos para complementar la enseñanza presencial, permitiendo continuidad educativa ante variaciones geográficas o laborales de los estudiantes.", "administracion_y_operatividad_del_plan_de_estudios": "La administración del plan está a cargo de la Dirección de Ingeniería y la Coordinación de Planes de Estudio. Se asigna un Coordinador Académico por ciclo y se mantiene un registro central en el sistema de gestión institucional. Se establecen reglas para la aprobación de cambios curriculares, distribución de asignaturas por ciclo y seguimiento de requisitos de egreso. Se definen criterios de admisión, permanencia y titulación, con responsable de cumplimiento institucional.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Evaluación anual del plan mediante análisis de resultados de aprendizaje, desempeño de proyectos y prácticas; Instrumentos: rúbricas de cursos, guías de laboratorio, evaluaciones de conocimiento y competencias, y cuestionarios de satisfacción. Periodicidad: revisión anual con reporte a la instancia institucional y a SEP cuando corresponda; indicadores de calidad: tasa de retención, satisfacción estudiantil, empleabilidad y ajuste curricular por áreas de conocimiento.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}, "nivel": "Licenciatura", "activo": true, "nombre": "Ingeniería Mecatrónica (2026)", "creado_en": "2026-01-30T18:31:10.882192+00:00", "plan_hash": "49aaec4fef4d574887fc6a60", "carrera_id": "089cdeda-d557-4a57-b49f-eb44921dfa3a", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Genera un plan de estudios sin rodeos."}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 3565, "total_tokens": 10864, "output_tokens": 7299, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 6400}}, "responseId": "resp_07eb32291fa2232900697cf8a8e7f4819dbaab7110202db4bf", "conversationId": null}}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "ingenieria mecatronica (2026)", "numero_ciclos": 9, "actualizado_en": "2026-01-30T18:31:10.882192+00:00", "actualizado_por": null, "conversation_id": null, "estado_actual_id": "18f49b67-8077-4371-be6e-2019a3be3562"}', NULL),
