	('3cec7887-aa2e-4704-936d-97dd1ab69196', '05863c8a-2a93-42f9-a4b7-65cef2edfe72', NULL, '2026-02-12 23:50:29.596563+00', 'CREACION', NULL, NULL, '{"id": "05863c8a-2a93-42f9-a4b7-65cef2edfe72", "datos": {"vigencia": "2026-2030", "area_de_estudio": "Ingeniería", "perfil_de_egreso": "La persona egresada habrá desarrollado un conjunto de conocimientos, habilidades y actitudes orientados a la ingeniería de tecnologías de inmersión. Conocimientos: fundamentos de matemáticas y física aplicadas a sistemas de interacción, fundamentos de programación, bases de datos, motores gráficos, diseño de interfaces y principios de usabilidad. Habilidades: diseñar, prototipar y evaluar soluciones de realidad virtual, realidad aumentada y simulaciones inmersivas; gestionar datos y APIs; integrar soluciones de backend con frontend para experiencias de inmersión; aplicar metodologías de desarrollo ágil y gestión de proyectos; comunicarse de forma efectiva en equipos multidisciplinarios. Actitudes: ética profesional, responsabilidad social, aprendizaje autónomo, trabajo en equipo y orientación a la mejora continua.", "diseno_curricular": "Flexible", "perfil_de_ingreso": "Conocimientos previos: Bachillerato concl uido o su equivalente, preferentemente en áreas de ciencias, tecnología o ingeniería. Habilidades previas: razonamiento lógico, manejo básico de computación y lectura comprensiva. Aptitudes: interés por tecnologías de inmersión, creatividad, capacidad de trabajo en equipo y tolerancia a la ambigüedad en entornos de desarrollo.", "curso_propedeutico": null, "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato concluido o su equivalente, preferentemente en ciencias, tecnología o ingeniería. Se valorará experiencia previa en programación básica, diseño de interfaces o modelado 3D.", "carga_horaria_a_la_semana": 20, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "LIC-ITMI-2026", "duracion_del_ciclo_escolar": "16 semanas", "fines_de_aprendizaje_o_formacion": "Analizar fundamentos de matemáticas, física, informática y teoría de la interacción humano–computadora para resolver problemas de inmersión. Diseñar experiencias de inmersión (VR/AR) y interfaces de usuario adecuadas para diferentes plataformas y dispositivos. Desarrollar prototipos de tecnologías de inmersión utilizando motores gráficos y herramientas multimedia. Programar y gestionar bases de datos y APIs para aplicaciones de realidad aumentada y virtual. Evaluar rendimiento, usabilidad y seguridad de las soluciones mediante pruebas y rúbricas. Integrar conocimientos de frontend (diseño de interfaces) con tecnologías de inmersión para producir soluciones integrales.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura - Ingeniería de Tecnologías de Inmersión", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "9", "sustento_teorico_del_modelo_curricular": "El modelo curricular se fundamenta en competencias y aprendizaje basado en proyectos, con énfasis en experiencias de inmersión, uso de plataformas digitales y evaluación continua para articular teoría y práctica en tecnologías de VR/AR.", "justificacion_de_la_propuesta_curricular": "La propuesta curricular, en modalidad escolar, responde a la necesidad de formar profesionales capaces de diseñar y desarrollar soluciones de tecnologías de inmersión integrando bases de datos, programación y diseño frontend. La estructura modular y la distribución por semestres permiten progresión gradual, con contenidos alineados a las demandas de la industria y la academia, manteniendo enfoque práctico a través de proyectos y laboratorios.", "administracion_y_operatividad_del_plan_de_estudios": "La administración del plan será responsabilidad de la Dirección de Programas Académicos. El Comité Curricular coordinará las áreas de Ingeniería de Software y Tecnologías de la Inmersión. Cada semestre contará con un conjunto obligatorio de asignaturas y, cuando corresponda, asignaturas optativas para perfilización. Se utilizará la plataforma institucional para gestión de cursos, rúbricas y evaluaciones; se definirán mínimos y máximos de asignaturas por ciclo (p. ej., mínimo 6 y máximo 9) y se establecerán mecanismos de revisión y ajuste del plan.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Se implementará una evaluación periódica semestral del plan de estudios mediante rúbricas de competencia, portafolios de proyectos, evaluaciones prácticas y exámenes. Los resultados se analizarán en sesiones del Comité Curricular y se emitirán informes para la mejora continua, con fechas de revisión cada semestre.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Lic. María González Pérez, Directora Académica"}, "nivel": "Licenciatura", "activo": true, "nombre": "Licenciatura en Ingeniería de Tecnologías de Inmersión ", "creado_en": "2026-02-12T23:50:29.596563+00:00", "plan_hash": "f96d011c347414ccb74ffe1a", "carrera_id": "8f1ce751-949b-45dd-8e38-e10c64b077fd", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Considera textos largos muy detallados, con palabras simples, sin tecnicismos ", "descripcionEnfoqueAcademico": "Una ingeniería para el desarrollo tecnológico de las tecnologías de inmersión, realidad virtual, realidad aumentada, motores gráficos, herramientas multimedia y otros elementos para integrar elementos de inmersión, adicionalmente deberá tener conocimiento de bases de datos, programación, diseño gráfico de frontend, y de las nuevas tecnologías de realidad virtual, realidad mixta de las diferentes plataformas existentes hoy en día."}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-nano-2025-08-07", "usage": {"input_tokens": 3651, "total_tokens": 12222, "output_tokens": 8571, "input_tokens_details": {"cached_tokens": 0}, "output_tokens_details": {"reasoning_tokens": 7488}}, "responseId": "resp_06ad21460230734c00698e66fccf6881a2b7218f123750b882", "conversationId": null}}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "licenciatura en ingenieria de tecnologias de inmersion ", "numero_ciclos": 9, "actualizado_en": "2026-02-12T23:50:29.596563+00:00", "actualizado_por": null, "estado_actual_id": "18f49b67-8077-4371-be6e-2019a3be3562"}', NULL),
	('eb2a44d5-244f-4663-9525-6e234865b36e', 'dc286072-c649-43aa-8a2f-aa3ef6166647', NULL, '2026-02-16 22:42:41.82455+00', 'CREACION', NULL, NULL, '{"id": "dc286072-c649-43aa-8a2f-aa3ef6166647", "datos": {"vigencia": "Por determinar por la autoridad educativa", "area_de_estudio": "07 Salud (CMPE 2016, campo amplio)", "perfil_de_egreso": "Conocimientos\n- Fundamentos de química general, analítica, orgánica, bioquímica, fisicoquímica y microbiología, con énfasis en su aplicación a farmacotecnia y cosmética.\n- Estructura, reactividad y síntesis de compuestos orgánicos y aromáticos, aceites esenciales, aromaquímicos y moléculas odorantes relevantes para perfumería.\n- Tecnología farmacéutica y de cosméticos: formas farmacéuticas, sistemas de liberación, excipientes, procesos unitarios, escalamiento y control de procesos.\n- Métodos instrumentales (GC-MS, HPLC/UPLC, IR, UV-Vis, GC-O, cromatografía preparativa) aplicados al análisis de fragancias, cosméticos y medicamentos.\n- Evaluación sensorial, psicofísica del olfato, diseño de paneles, estadística sensorial y técnicas descriptivas/hedónicas aplicadas a fragancias.\n- Gestión de la calidad, Buenas Prácticas de Manufactura (BPM/BPF: NOM, ISO 22716), validación de métodos, metrología y aseguramiento de la calidad.\n- Legislación sanitaria y regulatoria: marco COFEPRIS, NOM aplicables a cosméticos y perfumes, lineamientos IFRA, etiquetado, seguridad del consumidor y dossier técnico.\n- Toxicología, seguridad química, evaluación de riesgo, higiene y bioseguridad en laboratorios y plantas.\n\nHabilidades\n- Formular, optimizar y escalar fragancias finas y productos cosméticos fragranciados, así como formas farmacéuticas sólidas, semisólidas y líquidas.\n- Diseñar y validar métodos analíticos para identificación, cuantificación y control de calidad de ingredientes aromáticos, materias primas y productos terminados.\n- Aplicar diseño de experimentos (DoE), análisis multivariante y herramientas quimiométricas para optimización sensorial y de desempeño.\n- Evaluar estabilidad físico-química, fotoestabilidad, compatibilidad envase-producto y desempeño sensorial en condiciones aceleradas y reales.\n- Operar, calibrar y mantener equipos de laboratorio y planta piloto, asegurando trazabilidad de mediciones y cumplimiento de BPF/BPM.\n- Gestionar sistemas de calidad, documentación técnica (POE, AMEF, PNO), auditorías internas y externas, y liberación de lotes.\n- Integrar conocimientos de mercadotecnia olfativa y tendencias del mercado para alinear el desarrollo de fragancias a perfiles de consumidor y normatividad.\n- Comunicar resultados técnicos mediante reportes, presentaciones y defensa de proyectos ante audiencias técnicas y no técnicas en español e inglés.\n\nActitudes y valores\n- Ética profesional, responsabilidad sanitaria y compromiso con la seguridad del consumidor y la protección ambiental.\n- Pensamiento crítico, innovación y mejora continua con enfoque de sostenibilidad y química verde.\n- Trabajo colaborativo, liderazgo técnico, gestión del tiempo y orientación a resultados en contextos multidisciplinarios e interculturales.", "diseno_curricular": "Rígido", "perfil_de_ingreso": "Conocimientos\n- Matemáticas: álgebra, trigonometría y nociones de cálculo diferencial.\n- Ciencias básicas: química general y orgánica básica, biología celular y microbiología introductoria, física (mecánica y termodinámica) básicas.\n- Comprensión lectora en español e inglés técnico (nivel A2-B1). \n\nHabilidades\n- Razonamiento lógico-matemático y manejo de operaciones algebraicas aplicadas a problemas de química.\n- Competencias básicas de laboratorio: manejo de material volumétrico, seguridad e higiene, preparación de soluciones, registro en bitácora.\n- Uso básico de TIC: hoja de cálculo, procesador de texto, gestor de referencias y plataformas institucionales.\n\nActitudes y aptitudes\n- Disciplina, perseverancia y atención al detalle.\n- Disposición para el trabajo en laboratorio y para el aprendizaje autónomo.\n- Conducta ética, responsabilidad y apertura al trabajo en equipo.", "curso_propedeutico": "Aplica para aspirantes sin antecedente en bachillerato químico-biológico o con rezago en ciencias básicas. Duración: 40 horas (2 semanas previas al inicio). Módulos: Química general, Matemáticas para ciencias, Habilidades de laboratorio y bioseguridad, Inducción a perfumería y ética. Modalidad: presencial con prácticas en laboratorio. Evaluación: diagnóstica y final; acreditación con 80% y cumplimiento de prácticas.", "modalidad_educativa": "Escolar", "antecedente_academico": "Bachillerato general concluido, preferentemente con orientación químico-biológica o de ciencias de la salud; o bachillerato tecnológico afín (p. ej., Técnico Laboratorista Químico). Presentar certificado de estudios conforme a la normativa vigente.", "carga_horaria_a_la_semana": 34, "programa_de_investigacion": null, "clave_del_plan_de_estudios": "ULSM-QFB-2026", "duracion_del_ciclo_escolar": "18 semanas", "fines_de_aprendizaje_o_formacion": "- Analizar la estructura, propiedades y reactividad de compuestos orgánicos, aromáticos y biomoléculas para resolver problemas de formulación y control de calidad.\n- Diseñar formulaciones de fragancias finas, cosméticos fragranciados y formas farmacéuticas, considerando desempeño, estabilidad, seguridad y normatividad aplicable (IFRA, COFEPRIS).\n- Evaluar la calidad de materias primas, insumos aromáticos y productos terminados mediante métodos instrumentales validados y estadística aplicada.\n- Aplicar Buenas Prácticas de Laboratorio y de Manufactura para asegurar trazabilidad, reproducibilidad y cumplimiento regulatorio.\n- Implementar diseños experimentales y análisis quimiométricos para optimizar perfiles sensoriales y funcionales de productos fragranciados.\n- Gestionar riesgos, seguridad e higiene en laboratorio y planta, incluyendo manejo de sustancias peligrosas y residuos conforme a normatividad.\n- Integrar conocimientos científicos, tecnológicos y de mercadotecnia olfativa para proponer soluciones pertinentes a necesidades del sector salud-cosmético y perfumería.\n- Comunicar resultados técnicos de forma clara, ética y sustentada, en español e inglés, a audiencias especializadas y no especializadas.\n- Emprender proyectos de innovación y mejora continua con enfoque de sostenibilidad y química verde en la industria farmacéutica, cosmética y de perfumería.", "nivel_y_nombre_del_plan_de_estudios": "Licenciatura en Químico Farmacéutico Biólogo (2026)", "nombre_autorizado_de_la_institucion": "Universidad La Salle México", "total_de_ciclos_del_plan_de_estudios": "8", "sustento_teorico_del_modelo_curricular": "El plan se fundamenta en un enfoque por competencias profesionales integrales, con base constructivista y de aprendizaje situado. Se articula mediante:\n- Resultados de aprendizaje observables alineados a la Taxonomía de Bloom y a estándares del sector salud-cosmético.\n- Integración teoría-práctica con alto componente de laboratorio y planta piloto; uso de problemas auténticos (ABP) y proyectos integradores por semestre.\n- Evaluación basada en evidencias: prácticas con bitácora, informes técnicos, portafolio, rúbricas y evaluación sensorial objetiva.\n- Transversalidad de ejes: ciencias básicas, profesionalizantes (farmacotecnia, análisis instrumental, calidad), y eje de perfumería (formulación, análisis, sensorial y regulación).\n- Vinculación industria–academia mediante estancias, seminarios con casas perfumistas y co-diseño de proyectos.\n- Enfoque de calidad y mejora continua (PDCA), seguridad y sostenibilidad (química verde e ISO 22716).", "justificacion_de_la_propuesta_curricular": null, "administracion_y_operatividad_del_plan_de_estudios": "Estructura y seriación\n- Diseño curricular rígido en 8 semestres. Semestres 1-4: bases científicas y metodológicas; semestres 5-8: integración profesional y especialización en perfumería y cosméticos.\n- Seriación por prerrequisitos académicos y de competencias de laboratorio; control de acreditaciones seriadas para acceso a talleres avanzados de perfumería.\n\nCargas y componentes formativos por semestre (referenciales)\n- 6 a 7 asignaturas por semestre, combinando teoría y laboratorio. Carga máxima semanal: 34 horas bajo conducción docente.\n- Componentes obligatorios: prácticas de laboratorio, seminarios de industria, proyecto integrador por semestre y actividades de seguridad e higiene.\n\nEje de perfumería (5º a 8º semestre)\n- Asignaturas y talleres: Química de Fragancias y Aromáticos, Análisis Instrumental Aplicado a Perfumería, Tecnología de Cosméticos y Perfumes, Evaluación Sensorial y Marketing Olfativo, Regulación y Seguridad de Fragancias, Taller de Formulación de Fragancias, Proyecto Integrador de Perfumado.\n\nVinculación, prácticas y servicio social\n- Servicio social: mínimo 480 horas a partir de 6º semestre en instituciones de salud, laboratorios de control de calidad o industria cosmética.\n- Prácticas profesionales: 240–480 horas en 7º–8º semestre en casas perfumistas, cosmética o farmacéutica; tutoría académica y evaluación por competencias.\n\nGestión académica y aseguramiento de la calidad\n- Coordinación de programa y Comité Curricular (académicos, industria y egresados) para seguimiento de resultados de aprendizaje y pertinencia.\n- Sistemas de información académica para trazabilidad de competencias, asistencia, calificaciones, bitácoras y POE.\n- Protocolos de seguridad, mantenimiento y calibración de equipo; auditorías internas semestrales de laboratorios.\n\nTitulación\n- Modalidades: tesis/proyecto de aplicación, examen general de conocimientos, o portafolio con evidencia de competencias y proyecto en perfumería.", "propuesta_de_evaluacion_periodica_del_plan_de_estudios": "Metodología y periodicidad\n- Evaluación continua anual y revisión integral trianual del plan bajo ciclo PDCA.\n\nIndicadores clave\n- Eficiencia terminal, tiempo de titulación, empleabilidad a 6 y 12 meses, satisfacción de empleadores, desempeño en EGEL afín, cumplimiento de BPF/ISO 22716 en prácticas, resultados de auditorías de laboratorio, proyectos con industria y producción académica estudiantil.\n\nInstrumentos y fuentes\n- Encuestas a estudiantes/egresados/empleadores, rúbricas de proyectos integradores, análisis de portafolios, evaluación externa por pares académicos e industriales (casas perfumistas y laboratorios cosméticos), benchmarking nacional/internacional y análisis de trazabilidad de evidencias.\n\nProcedimientos\n- Mapeo de resultados de aprendizaje vs. evidencias por asignatura; análisis de brechas; planes de mejora por unidad de aprendizaje; actualización de POE y contenidos; capacitación docente en tendencias de perfumería, métodos instrumentales y estadística sensorial.\n- Informe público de resultados y plan de mejora aprobado por el Comité Curricular y la Dirección Académica.", "nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios": "Mtra. Claudia López Hernández, Directora Académica de la Facultad de Ciencias Químicas y Salud"}, "nivel": "Licenciatura", "activo": true, "nombre": "Químico Farmacéutico Biólogo (2026)", "creado_en": "2026-02-16T22:42:41.82455+00:00", "plan_hash": "7b0e41946d11fba7efc40cd8", "carrera_id": "991edcde-b77e-4d22-b76b-3bf6ec3d3555", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "", "descripcionEnfoqueAcademico": "Genera un plan de estudios con énfasis especial en perfumería"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai_generate_plan", "ai_structured": {"model": "gpt-5-2025-08-07", "usage": {"input_tokens": 3766, "total_tokens": 9774, "output_tokens": 6008, "input_tokens_details": {"cached_tokens": 3712}, "output_tokens_details": {"reasoning_tokens": 3456}}, "responseId": "resp_08652921016d16350069939cf516ac81a0b23dd0d51a15afb0", "conversationId": null}}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "quimico farmaceutico biologo (2026)", "numero_ciclos": 8, "actualizado_en": "2026-02-16T22:42:41.82455+00:00", "actualizado_por": null, "estado_actual_id": "18f49b67-8077-4371-be6e-2019a3be3562"}', NULL),
