	('c75f642f-f407-4fe3-b4a4-ae4d409aa76c', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:23:03.864946+00', 'CREACION', NULL, NULL, '{"id": "198c763b-9d97-423b-b13a-5713437fc81b", "datos": {}, "nivel": "Licenciatura", "activo": true, "nombre": "Licenciatura en Educación Especial como sombra", "creado_en": "2026-02-27T22:23:03.864946+00:00", "plan_hash": "f2ac1c8af3a88f3cee859091", "carrera_id": "6d086d1b-aaea-4b76-9b16-fa8f3e29d9fa", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "No considerar específicamente el TDA si no todas las posibilidades de la educación especial, incluyendo discapacidades", "descripcionEnfoqueAcademico": "Una carrera relacionada con la educación especial, relacionada con la figura de sombra para educación primaria, y educación especial para personas con TDA"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai-generate-plan"}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "licenciatura en educacion especial como sombra", "numero_ciclos": 9, "actualizado_en": "2026-02-27T22:23:03.864946+00:00", "actualizado_por": null, "estado_actual_id": "f2abc804-1d7e-40d5-81bd-02f3a8e48f6f"}', NULL),
	('9f8f60ac-cef9-474f-aec1-9b8cd3359716', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'TRANSICION_ESTADO', 'estado_actual_id', '"f2abc804-1d7e-40d5-81bd-02f3a8e48f6f"', '"18f49b67-8077-4371-be6e-2019a3be3562"', NULL),
	('6b64fd36-e7c2-4f13-82ae-47f16ec01bdb', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'perfil_de_ingreso', NULL, '"Conocimientos previos:\n  - Educación media superior (bachillerato) completada.\n  - Conocimientos básicos de psicología del desarrollo y didáctica (preferente).\nHabilidades y destrezas:\n  - Capacidad de comunicación clara y trabajo en equipo.\n  - Habilidad para la observación y registro de conductas y procesos de aprendizaje.\n  - Manejo básico de herramientas informáticas (navegación web, edición de texto y acceso a plataformas educativas).\nAptitudes personales:\n  - Vocación por el trabajo con infancia y jóvenes.\n  - Paciencia, tolerancia y resiliencia para la resolución de conflictos en entornos escolares.\n  - Disponibilidad para realizar estancias prácticas en centros educativos y trabajo de campo."', NULL),
	('6985233a-e671-4606-9ef2-7035280748d2', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'programa_de_investigacion', NULL, 'null', NULL),
	('d3831e84-4c75-44da-8fcb-50ded9dde314', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'justificacion_de_la_propuesta_curricular', NULL, '"Descripción de la modalidad mixta y recursos tecnológicos:\n  - La modalidad mixta combina sesiones presenciales para talleres y prácticas de campo, con componentes virtuales para contenidos teóricos, seminarios y tutorías.\n  - Plataforma educativa: Uso de un LMS institucional (por ejemplo, Moodle o Canvas) para entregar contenidos asincrónicos, foros académicos, rúbricas y actividades de evaluación.\n  - Herramientas sincrónicas: Videoconferencias para seminarios, supervisión de prácticas y sesiones de retroalimentación (Zoom/Teams integradas al LMS).\n  - Recursos didácticos: Banco de recursos multimedia, casos clínicos, simulaciones y módulos interactivos para el desarrollo de competencias de observación y diseño de adaptaciones.\nAutogestión y flexibilidad espacio-temporal:\n  - Los estudiantes disponen de materiales asincrónicos que permiten avanzar de manera flexible, con itinerarios de estudio y fechas de entrega acotadas.\n  - Se garantiza acompañamiento mediante tutorías periódicas (individuales y grupales) y supervisión de prácticas en campo.\nVinculación con actividades de aprendizaje:\n  - Las asignaturas incluyen actividades de observación estructurada en aulas, prácticas acompañadas en centros educativos, diseño y aplicación de adaptaciones y proyectos integradores.\n  - La plataforma registra evidencias de aprendizaje (portafolio digital) y facilita la evaluación formativa por parte de docentes y supervisores de práctica."', NULL),
	('3d9f707f-ab10-47f0-85cb-09d156f1afe6', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'perfil_de_egreso', NULL, '"Conocimientos:\n  - Marco conceptual de la Educación Especial y modelos de atención a la diversidad.\n  - Normativa nacional e internacional sobre inclusión educativa y derechos de las personas con discapacidad.\n  - Características del desarrollo infantil y del aprendizaje en educación primaria.\n  - Estrategias pedagógicas y adaptaciones curriculares para diversas necesidades educativas.\nHabilidades:\n  - Identificar y diagnosticar barreras de aprendizaje en entornos escolares.\n  - Diseñar y aplicar adaptaciones curriculares y estrategias de apoyo individualizado.\n  - Intervenir como figura de sombra para facilitar la participación y el aprendizaje en aula regular.\n  - Colaborar con equipos docentes, familias y profesionales para la elaboración de planes de atención individualizada.\n  - Evaluar el progreso del estudiante mediante instrumentos cualitativos y cuantitativos.\nActitudes:\n  - Promover una práctica profesional ética, centrada en la dignidad y derechos del estudiantado.\n  - Mostrar sensibilidad hacia la diversidad cultural, funcional y socioemocional.\n  - Adoptar una postura reflexiva, colaborativa y comprometida con la mejora continua."', NULL),
	('6c9c6ae4-bb6e-44d9-8819-7e83c037db5d', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'propuesta_de_evaluacion_periodica_del_plan_de_estudios', NULL, '"Metodología e instrumentos:\n  - Evaluación cuatrienal interna con revisión anual de resultados: combinación de análisis de indicadores cuantitativos y cualitativos.\n  - Instrumentos: Encuestas a egresados y empleadores, informe de seguimiento de egresados (tracer study), evaluación de desempeño de estudiantes en prácticas, análisis de cargas y resultados académicos, reuniones del Comité Académico.\n  - Periodicidad: Revisión anual de indicadores clave (retención, titulación, desempeño en prácticas), evaluación curricular cada tres años para ajustes mayores.\n  - Participación de actores: Voces de estudiantes, egresados, docentes, escuelas vinculadas y sociedad civil en foros de evaluación.\n  - Mecanismos de mejora: Planes de acción derivados de la evaluación, actualización de asignaturas, capacitación docente y revisión de convenios de práctica."', NULL),
	('fcb6d5be-9e72-4733-8ead-e2a164106e2d', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'vigencia', NULL, '"(Espacio para uso exclusivo de la autoridad educativa)"', NULL),
	('b4224167-a7ec-4fbd-96e5-f321e987dc57', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'carga_horaria_a_la_semana', NULL, '40', NULL),
	('201be9b9-6667-4577-b4c9-3a21496967f4', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'area_de_estudio', NULL, '"Formación docente y ciencias de la educación"', NULL),
	('15a26981-505d-4913-b12b-94b4f8df018e', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'nivel_y_nombre_del_plan_de_estudios', NULL, '"Licenciatura - Licenciatura en Educación Especial (énfasis: figura de sombra para educación primaria)"', NULL),
	('6f7b819c-6ece-4b24-9720-fff0e6534c1e', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'curso_propedeutico', NULL, '"Situaciones de aplicación:\n  - Dirigido a aspirantes que no acrediten formación previa en áreas afines (psicopedagogía, educación o trabajo social).\nPoblación objetivo:\n  - Aspirantes a la licenciatura con bachillerato completo.\nDuración y estructura:\n  - 40 horas (presenciales o en modalidad mixta), organizado en 4 módulos.\nRelación con el plan de estudios:\n  - Introduce fundamentos del desarrollo infantil, terminología de inclusión y manejo básico de registros y observación; prepara para las prácticas iniciales."', NULL),
	('f2844c3b-c28c-499d-8f3e-2dcb42f279f6', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'administracion_y_operatividad_del_plan_de_estudios', NULL, '"Estructura administrativa y académica:\n  - Dirección Académica: Responsable general del programa y de la vinculación institucional.\n  - Coordinación de la Licenciatura: Gestión curricular, seguimiento a planes de estudio y coordinación de prácticas.\n  - Cuerpo académico: Perfil con experiencia en educación especial, psicopedagogía y práctica escolar inclusiva; se exige formación de posgrado preferente y experiencia en supervisión de prácticas.\n  - Tutoría académica: Sistema de tutorías para seguimiento individual del estudiante y acompañamiento en estancias prácticas.\nOperatividad del calendario y carga por ciclo:\n  - Diseño rígido: 9 semestres obligatorios.\n  - Asignaturas por semestre (típico): 5 a 6 asignaturas, combinando teoría, metodología y práctica; una asignatura práctica o de taller por semestre como mínimo.\n  - Estancias y prácticas: Prácticas progresivas con incremento de horas en los semestres superiores y prácticas intensivas de intervención en escuela en los últimos semestres.\nGestión de calidad y recursos:\n  - Espacios formativos: Aulas, laboratorios didácticos, centro de observación y convenios con escuelas de educación primaria para estancias.\n  - Recursos humanos: Profesores con perfil docente-investigador y supervisores de práctica con formación en educación especial.\n  - Documentación operativa: Manuales de práctica, rúbricas de evaluación, convenios de colaboración y normativa interna para el desarrollo de estancias."', NULL),
	('bc36de82-47a7-46ec-835e-fcb759b5c1e0', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'sustento_teorico_del_modelo_curricular', NULL, '"Lista de pasos conceptuales previos a la elaboración:\n  - Revisar requisitos normativos del Acuerdo 17/11/17 y correspondencia con ciclos semestrales.\n  - Definir perfil de egreso alineado con competencias profesionales para la figura de sombra.\n  - Estructurar asignaturas y prácticas que integren teoría, práctica reflexiva y colaboración interprofesional.\n\nMarco conceptual y fundamentos:\n  - Enfoque por competencias: El plan articula saberes, capacidades y actitudes necesarias para la práctica profesional en entornos inclusivos.\n  - Constructivismo social y aprendizaje situado: Se privilegia el aprendizaje contextualizado en aula y en comunidad, con énfasis en la observación y la práctica asistida.\n  - Diseño Universal para el Aprendizaje (DUA): Fundamenta la propuesta de adaptaciones curriculares y estrategias de accesibilidad.\n  - Enfoque de derechos humanos e inclusión educativa: La intervención pedagógica se orienta a garantizar la participación plena y no discriminación.\n  - Investigación-acción y reflexión profesional: Los practicantes desarrollan competencias para investigar su propia práctica y ajustar intervenciones.\n\nVinculación curricular:\n  - Las asignaturas teóricas, metodológicas y las prácticas profesionales se articulan para desarrollar progresivamente la capacidad de intervenir como sombra, evaluar necesidades y coordinar apoyos."', NULL),
	('d2c513d0-4fdd-47e4-b9e1-4165d6772217', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'duracion_del_ciclo_escolar', NULL, '"16 semanas"', NULL),
	('70aa5739-485f-45f0-bb40-5e54cbe0b279', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'nombre_autorizado_de_la_institucion', NULL, '"Universidad La Salle México"', NULL),
	('d909b82f-b5fd-466d-84ad-6e8ce75ad791', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'total_de_ciclos_del_plan_de_estudios', NULL, '"9 ciclos semestrales"', NULL),
	('95880fad-ca14-467d-b748-04356f5ea000', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'fines_de_aprendizaje_o_formacion', NULL, '" - Analizar los fundamentos teóricos y normativos de la Educación Especial y la atención a la diversidad.\n - Diagnosticar necesidades educativas individuales mediante técnicas de observación y evaluación formativa.\n - Diseñar intervenciones pedagógicas y adaptaciones curriculares orientadas a la inclusión en educación primaria.\n - Implementar estrategias de mediación y apoyo individual (figura de sombra) para facilitar la participación y el aprendizaje.\n - Colaborar con equipos docentes y familias para la planificación y seguimiento de planes de atención individualizada.\n - Evaluar el impacto de las estrategias de apoyo e intervenir de forma reflexiva para su mejora continua.\n - Promover prácticas profesionales éticas y respeto a los derechos de las personas con discapacidad."', NULL),
	('318185d0-0c34-4cd1-aeff-ea851cd6618c', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'clave_del_plan_de_estudios', NULL, '"LLSE-2026"', NULL),
	('70be7b27-0c96-4a0b-ae7a-1812c8034ba6', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'diseno_curricular', NULL, '"Rígido"', NULL),
	('5fc81e43-8310-4e30-a080-415be411c340', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'antecedente_academico', NULL, '"Bachillerato concluido (Certificado de educación media superior). Se valorará experiencia previa en entornos educativos o comunitarios; no es requisito excluyente."', NULL),
	('0097c249-ef92-43e6-afcf-5a410610bf6d', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-02-27 22:24:16.905076+00', 'ACTUALIZACION_CAMPO', 'modalidad_educativa', NULL, '"Mixta"', NULL),
	('2b1f4259-1750-45de-bd29-c3c238dccae8', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:28:10.322716+00', 'CREACION', NULL, NULL, '{"id": "f35bd838-6df7-4a3b-9fbf-879f9b3e6da9", "datos": {}, "nivel": "Licenciatura", "activo": true, "nombre": "Licenciatura en Educación Especial como sombra", "creado_en": "2026-02-27T22:28:10.322716+00:00", "plan_hash": "fbfb9a548cc84968bd331fef", "carrera_id": "b4e0ad06-84b0-40fc-8228-a75b0c9cbd9b", "creado_por": null, "tipo_ciclo": "Semestre", "meta_origen": {"iaConfig": {"usarMCP": false, "instruccionesAdicionalesIA": "Textos largos y extensos", "descripcionEnfoqueAcademico": "Textos extensos acerca de la educación especial con base a ser especialista en sombra, considera que deberán ser una investigación profunda y las respuestas deben tener al menos 500 palabras"}, "referencias": {"repositoriosIds": [], "archivosReferenciaIds": []}, "generado_por": "ai-generate-plan"}, "tipo_origen": "IA", "estructura_id": "69fb2b77-5a95-47e0-bf1f-389d384200e4", "nombre_search": "licenciatura en educacion especial como sombra", "numero_ciclos": 9, "actualizado_en": "2026-02-27T22:28:10.322716+00:00", "actualizado_por": null, "estado_actual_id": "f2abc804-1d7e-40d5-81bd-02f3a8e48f6f"}', NULL),
	('613b49a9-b77d-46eb-b89d-b7403775278c', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'TRANSICION_ESTADO', 'estado_actual_id', '"f2abc804-1d7e-40d5-81bd-02f3a8e48f6f"', '"18f49b67-8077-4371-be6e-2019a3be3562"', NULL),
	('b43fb6c2-5bd1-4e7e-9dc7-6ac3ac952aed', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'perfil_de_ingreso', NULL, '"Conocimientos previos:\n- Certificado de Bachillerato o equivalente con dominio básico de lectura, redacción y razonamiento lógico-matemático.\n- Conocimientos introductorios en psicología, pedagogía o atención a la diversidad (deseable, no obligatorio).\n\nHabilidades y aptitudes:\n- Habilidad comunicativa efectiva y disposición para el trabajo en equipo.\n- Capacidad de observación, registro y análisis de comportamientos en contextos educativos.\n- Actitud empática, paciente y respetuosa frente a la diversidad funcional y cultural.\n\nCondiciones personales:\n- Disponibilidad para prácticas en centros educativos y visitas domiciliarias.\n- Compromiso ético y disposición para formación continua y trabajo con poblaciones vulnerables."', NULL),
	('3b6d33b5-45a0-4877-945c-fc5ad10b2685', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'programa_de_investigacion', NULL, 'null', NULL),
	('d3d016e9-f3bf-4c2d-8704-c5d04ed59886', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'nombre_y_cargo_de_la_persona_facultada_para_autorizar_el_plan_de_estudios', NULL, '"Dr. Francisco Javier Ortega, Rector"', NULL),
	('d504e2e0-132e-4b17-a10d-1d2ef71967fd', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'justificacion_de_la_propuesta_curricular', NULL, '"Modalidad mixta: explicación de implementación tecnológica, autogestión y flexibilidad espacio-temporal.\n- Plataforma tecnológica: El programa empleará un LMS institucional (por ejemplo, Moodle institucional o plataforma propietaria) que soporta contenidos asincrónicos (módulos temáticos, lecturas, foros), actividades evaluables y repositorio de recursos adaptativos. Además se dispondrá de herramientas para videoconferencia (Zoom/Teams) para sesiones sincrónicas, tutorías y supervisión de práctica.\n- Autogestión del aprendizaje: Las actividades asincrónicas incluirán guías de estudio, rúbricas claras y recursos multimedia. Se promoverá la metacognición mediante diarios de aprendizaje y portafolios electrónicos que permitan evidenciar competencias profesionales.\n- Flexibilidad espacio-temporal: El diseño mixto permite que agentes (estudiantes, tutores, docentes) articulen sesiones presenciales para prácticas y evaluación, con trabajo a distancia para contenidos teóricos y asesorías. Esto facilita el acceso y la posibilidad de estancias en centros educativos diversos.\n- Recursos didácticos y tecnológicos: Materiales accesibles (texto enriquecido, transcripciones, subtítulos, lecturas en formatos alternativos) y simuladores para entrenamiento de situaciones complejas. Herramientas para registro y análisis de observación (plantillas digitales, apps para registro de conductas) soportarán la formación práctica.\n- Vinculación con asignaturas: Las plataformas alojarán los recursos de cada asignatura, enlaces a prácticas supervisadas, y espacios de interacción interprofesional. Los procesos de evaluación combinarán evidencias en línea y en campo, asegurando validez y confiabilidad.\n- Soporte institucional: Tutorías académicas y tecnopedagógicas, acompañamiento para prácticas y mesas de análisis de casos. Se garantizará la interoperabilidad entre las actividades presenciales y virtuales para mantener coherencia pedagógica y cumplimiento de competencias."', NULL),
	('f15f198a-0448-4b67-92f9-33915d71fa61', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'perfil_de_egreso', NULL, '"Conocimientos:\n- Conocer los fundamentos teóricos y normativos de la educación especial y la inclusión educativa, incluidas las leyes y políticas nacionales aplicables.\n- Conocer modelos de atención educativa (modelo ecológico, enfoque por competencias, Diseño Universal para el Aprendizaje, respuesta a la intervención) y sus implicaciones para la práctica de sombra.\n- Conocer características y necesidades educativas de estudiantes con discapacidad, trastornos del desarrollo y necesidades educativas especiales específicas.\n\nHabilidades:\n- Diseñar y aplicar estrategias individualizadas de acompañamiento (sombra) para facilitar la participación y el aprendizaje en contextos educativos regulares.\n- Realizar observaciones sistemáticas, registros conductuales y adaptaciones curriculares básicas en colaboración con el personal docente y familias.\n- Colaborar en equipos interdisciplinarios y comunicarse efectivamente con docentes, familias y especialistas para articular apoyos.\n- Aplicar procedimientos de evaluación formativa y ajustar estrategias de intervención basadas en evidencia.\n\nActitudes y valores:\n- Actuar con ética profesional, confidencialidad y respeto hacia la dignidad, autonomía y derechos de las personas con discapacidad.\n- Mantener una actitud reflexiva, crítica y de mejora continua sustentada en la evidencia y en el aprendizaje colaborativo.\n- Mostrar compromiso por la inclusión, la equidad y la promoción de entornos accesibles y participativos."', NULL),
	('fada9786-7058-42cb-9b86-4ede6bb4d0af', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'propuesta_de_evaluacion_periodica_del_plan_de_estudios', NULL, '"Metodología de evaluación del plan de estudios:\n- Objetivo: Mantener actualización curricular y pertinencia disciplinar mediante evaluación anual y revisiones integrales cada tres años.\n- Instrumentos: Encuestas de egresados y empleadores, análisis de desempeño en prácticas, revisión de trayectorias académicas, indicadores de inserción laboral y evaluación por pares académicos.\n- Periodicidad: Informes anuales de seguimiento; revisión curricular bianual focalizada en asignaturas clave; evaluación integral cada 3 años con participación de comité externo.\n- Procedimiento: Recolección de datos cuantitativos y cualitativos, análisis por la coordinación, diseño de plan de mejora con responsables y plazos, seguimiento de indicadores y reporte público de avances.\n- Indicadores clave: Tasa de titulación, desempeño en prácticas (evaluación de supervisores), satisfacción de empleadores, cumplimiento de cargas académicas, actualización de contenidos y vinculación con evidencia científica.\n- Participación: Incluye estudiantes, docentes, empleadores, instituciones receptoras de prácticas y expertos externos para asegurar validez y pertinencia."', NULL),
	('240746fd-4641-47e8-aba1-1af508f3676e', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'vigencia', NULL, '"2026 (espacio para uso exclusivo de la autoridad educativa)"', NULL),
	('1592173c-9048-4787-89f1-0692b344e6e7', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'carga_horaria_a_la_semana', NULL, '40', NULL),
	('5fe37d1f-9e3d-4cc8-b625-d0a4d26a37f6', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'area_de_estudio', NULL, '"Educación. Campo amplio: Formación docente y educación especial (según Clasificación Mexicana de Planes de Estudio por Campos de Formación Académica, CMPE 2016)."', NULL),
	('af110b41-428c-4381-8c5e-a464a2eb29f6', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'nivel_y_nombre_del_plan_de_estudios', NULL, '"Licenciatura en Educación Especial (orientación: Sombra)"', NULL),
	('8e94d119-a983-4186-af3f-f5a51ca4821d', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'curso_propedeutico', NULL, '"Se ofrecerá un curso propedéutico opcional dirigido a aspirantes que no cuenten con formación previa en pedagogía o atención a la diversidad. Características:\n- Población: Aspirantes sin experiencia formal en educación o con antecedentes en áreas no afines.\n- Duración: 8 semanas (40 horas totales), modalidad mixta (sincrónico y asincrónico).\n- Contenidos: Fundamentos de psicología del desarrollo, nociones básicas de pedagogía inclusiva, comunicación efectiva y manejo básico de registros.\n- Relación con el plan de estudios: Prepara al aspirante para cursar asignaturas iniciales de didáctica y atención a la diversidad; no substituye requisitos de admisión, pero fortalece rendimiento académico inicial.\n- Criterios de aplicación: Se recomienda para el 30% de la cohorte cuya evaluación de diagnóstico inicial identifique brechas relevantes en competencias lectoras, comunicativas o conocimientos básicos en educación."', NULL),
	('9f14f052-b6f8-424e-9b1a-eaf23d46f32b', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-03-25 19:00:25.341814+00', 'ACTUALIZACION_CAMPO', 'perfil_de_egreso', '"Conocimientos:\n- Conocer fundamentos teóricos y normativos de la educación especial y la inclusión educativa, incluidas las leyes y políticas nacionales aplicables.\n- Conocer modelos de atención educativa (modelo ecológico, enfoque por competencias, Diseño Universal para el Aprendizaje, intervención centrada en la diversidad) y sus implicaciones para la práctica de sombra.\n- Conocer características y necesidades educativas de estudiantes con discapacidad, trastornos del desarrollo y necesidades educativas especiales específicas.\n\nHabilidades:\n- Diseñar y aplicar estrategias de acompañamiento (sombra) para facilitar la participación y el aprendizaje en contextos educativos regulares.\n- Realizar observaciones sistemáticas, registros conductuales y adaptaciones curriculares básicas en colaboración con docentes y familias.\n- Colaborar en equipos interdisciplinarios y comunicarse efectivamente con docentes, familias y especialistas para articular apoyos.\n- Aplicar procedimientos de evaluación formativa y ajustar estrategias de intervención basadas en evidencia.\n\nActitudes:\n- Actuar con ética profesional, confidencialidad y respeto hacia la dignidad, autonomía y derechos de las personas con discapacidad.\n- Mantener una actitud reflexiva, crítica y de mejora continua sustentada en la evidencia y el aprendizaje colaborativo.\n- Mostrar compromiso por la inclusión, la equidad y la promoción de entornos accesibles y participativos."', '"Conocimientos:\n- Conocer fundamentos teóricos y normativos de la educación especial y la inclusión educativa, incluidas las leyes y políticas nacionales aplicables.\n- Conocer modelos de atención educativa (modelo ecológico, enfoque por competencias, Diseño Universal para el Aprendizaje, intervención centrada en la diversidad) y sus implicaciones para la práctica de sombra.\n- Conocer características y necesidades educativas de estudiantes con discapacidad, trastornos del desarrollo y necesidades educativas especiales específicas.\n\nHabilidades:\n- Diseñar y aplicar estrategias de acompañamiento (sombra) para facilitar la participación y el aprendizaje en contextos educativos regulares.\n- Realizar observaciones sistemáticas, registros conductuales y adaptaciones curriculares básicas en colaboración con docentes y familias.\n- Colaborar en equipos interdisciplinarios y comunicarse efectivamente con docentes, familias y especialistas para articular apoyos.\n- Aplicar procedimientos de evaluación formativa y ajustar estrategias de intervención basadas en evidencia.\n\nActitudes:\n- Actuar con ética profesional, confidencialidad y respeto hacia la dignidad, autonomía y derechos de las personas con discapacidad.\n- Mantener una actitud reflexiva, crítica y de mejora continua sustentada en la evidencia y en el aprendizaje colaborativo.\n- Mostrar compromiso por la inclusión, la equidad y la promoción de entornos accesibles y participativos."', NULL),
	('17004106-ad5d-41fc-96e1-5e3d9cfc1881', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'administracion_y_operatividad_del_plan_de_estudios', NULL, '"Estructura administrativa y operativa:\n- Coordinación académica: Existirá una Coordinación de la Licenciatura responsable del seguimiento académico, la vinculación con centros de práctica y la supervisión de procesos de aseguramiento de la calidad.\n- Organización de la oferta: Diseño rígido en 9 semestres, con secuencia establecida de asignaturas obligatorias y optativas estructuradas por niveles formativos.\n- Carga por ciclo: La carga promedio por semestre se organizará en torno a 40 horas semanales efectivas, que incluyen docencia teórica, actividades prácticas y tiempo de estudio guiado.\n- Prácticas y estancias: Prácticas profesionales progresivas desde el segundo semestre, con incremento de horas prácticas hasta culminar en estancias intensivas en contextos escolares en el último año. Se definirá un manual de prácticas con perfiles de supervisores y criterios de evaluación.\n- Plantilla docente: Perfil docente con grado mínimo de maestría en áreas afines, experiencia en inclusión y prácticas de sombra, y formación en investigación aplicada. Se promoverá la actualización continua y la supervisión por expertos.\n- Gestión curricular: Cronograma anual, sesiones de coordinación docente por asignatura, sistema de registro de evidencias curriculares y control de avance estudiantil.\n- Siembra de asignaturas por semestre (ejemplo operativo): Semestre 1-3: fundamentos y diagnóstico; Semestre 4-6: intervención y metodologías; Semestre 7-9: prácticas intensivas, proyectos integradores y seminario de titulación.\n- Tutoría académica: Cada estudiante contará con un tutor académico y un tutor de prácticas, responsables de seguimiento del avance y apoyo en la articulación teoría-práctica."', NULL),
	('d74d79d3-6817-4b4e-badd-100dddbdfdf5', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'sustento_teorico_del_modelo_curricular', NULL, '"Lista de pasos conceptuales previos:\n- Revisar requisitoss normativos del Acuerdo 17/11/17 y la normativa educativa nacional aplicable.\n- Estructurar campos obligatorios del Anexo 1 y verificar coherencia entre ingreso, perfil y fines de aprendizaje.\n- Diseñar el marco curricular alineado con teorías de inclusión, UDL y prácticas basadas en evidencia.\n- Determinar la operatividad administrativa y los mecanismos de evaluación periódica.\n- Validar la carga horaria, duración de ciclos y practicum con estándares nacionales y de buenas prácticas.\n\nMarco teórico y justificación del modelo curricular:\n  El modelo curricular de la Licenciatura en Educación Especial con orientación en acompañamiento tipo sombra parte de la premisa de que la inclusión educativa es un derecho humano y una responsabilidad institucional que requiere profesionales formados de manera específica para acompañar procesos de aprendizaje y participación en contextos escolares regulares. Se sustenta en los siguientes referentes teóricos y conceptuales:\n  - Diseño Universal para el Aprendizaje (UDL): plantea principios para anticipar barreras y diseñar múltiples vías de acceso al currículo, favoreciendo la planificación de adaptaciones y apoyos que el profesional en sombra debe conocer y aplicar.\n  - Enfoque ecológico y bio-psicosocial: reconoce que las necesidades de los estudiantes emergen de la interacción entre individuo, familia, escuela y comunidad; por tanto, la intervención del profesional sombra se concibe como mediación contextual, no como sustitución del docente.\n  - Teorías socioculturales del aprendizaje (Vygotsky): sustentan la importancia del andamiaje y la zona de desarrollo próximo, herramientas clave para la intervención individualizada y para promover la autonomía del estudiante mediante mediación intencional.\n  - Modelos colaborativos y de co-intervención: el plan se apoya en evidencia sobre la efectividad de prácticas colaborativas entre docente titular, especialista y familia para lograr inclusión sostenible; el profesional sombra es formado para integrarse de forma articulada en estos equipos.\n  - Prácticas basadas en evidencia y evaluación formativa: el currículo incorpora métodos de observación sistemática, medición del progreso y diseño de intervenciones ajustadas a resultados, promoviendo la investigación aplicada y la cultura de evaluación.\n  - Perspectiva de derechos y normativa nacional: el modelo articula la formación con el marco legal mexicano en materia educativa y de discapacidad, así como con principios de ética profesional y confidencialidad.\n\n  La estructura curricular combina contenidos conceptuales, metodológicos y prácticos; integra prácticas supervisadas desde el primer año, seminarios de reflexión profesional, y proyectos integradores que vinculan investigación aplicada con mejora institucional. La formación busca que el egresado maneje herramientas para la evaluación, diseño e implementación de apoyos que fomenten la inclusión, la participación y el desarrollo integral del estudiante."', NULL),
	('78f29871-d79b-40bd-92eb-094f1a91d22f', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'duracion_del_ciclo_escolar', NULL, '"16 semanas"', NULL),
	('413173fe-37ad-4158-86f3-3282b3f7e25d', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'nombre_autorizado_de_la_institucion', NULL, '"Universidad La Salle México"', NULL),
	('18353d70-b360-42aa-a98c-3dc80b0935fa', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'total_de_ciclos_del_plan_de_estudios', NULL, '"9"', NULL),
	('b973ba90-9e41-41a7-a1b7-28d4d2968336', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'fines_de_aprendizaje_o_formacion', NULL, '"El programa tiene por finalidad formar profesionales de la educación especializados en el acompañamiento tipo ''sombra'', capaces de intervenir en contextos educativos regulares y de atención especializada mediante prácticas fundamentadas en la evidencia, la colaboración interprofesional y el respeto a los derechos de las personas con discapacidad. Los fines de aprendizaje se articulan en competencias que guían la formación:\n- Analizar los marcos normativos, éticos y teóricos que sustentan la educación especial y la inclusión, con el fin de garantizar intervenciones respetuosas de los derechos y la dignidad de las personas con discapacidad.\n- Identificar las características desarrollo-cognitivas, socioemocionales y comunicativas de estudiantes con diferentes tipos de discapacidad o necesidades educativas especiales, para adecuar estrategias de apoyo.\n- Diseñar planes de acompañamiento individualizados basados en la evaluación formativa, que integren adaptaciones curriculares, apoyos conductuales y mediaciones pedagógicas pertinentes al contexto escolar.\n- Implementar técnicas de observación, registro y evaluación del comportamiento y del progreso académico, utilizando instrumentos estandarizados y protocolos de registro confiables.\n- Colaborar y coordinar con docentes titulares, equipos interdisciplinares y familias para articular apoyos, comunicando hallazgos y proponiendo ajustes en el entorno y la práctica pedagógica.\n- Implementar estrategias de mediación y apoyo que promuevan la participación activa, la autonomía funcional y la inclusión social del alumno dentro del aula regular.\n- Evaluar la eficacia de las intervenciones de sombra mediante indicadores cualitativos y cuantitativos, ajustando las acciones en ciclos de mejora continua.\n- Promover entornos accesibles y diseñar ajustes razonables y recursos didácticos adaptados que favorezcan el aprendizaje y la interacción social.\n- Fomentar actitudes profesionales basadas en la ética, la confidencialidad, el respeto a la diversidad cultural y la toma de decisiones centrada en la persona.\n- Difundir prácticas basadas en evidencia y favorecer la investigación aplicada en contextos escolares para la mejora de modelos de acompañamiento y políticas inclusivas.\n\nEstos fines se desarrollan a través de una secuencia curricular que integra formación teórica avanzada, práctica supervisada en distintos niveles educativos y proyectos integradores que promueven la investigación aplicada en contexto."', NULL),
	('b1399c0e-8440-4826-92d8-bdcb067c5d25', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'clave_del_plan_de_estudios', NULL, '"LLS-LESE-2026"', NULL),
	('6749e872-7c77-4efb-a1bc-b7a23a503cb8', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'diseno_curricular', NULL, '"Rígido"', NULL),
	('abc901f1-7fb9-47d8-a8fe-805f6b0b3569', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'antecedente_academico', NULL, '"Certificado de Bachillerato o equivalente. Preferentemente procedencia de áreas afines como Ciencias de la Educación, Psicología, Trabajo Social, Pedagogía o áreas de ciencias sociales relacionadas con atención a la infancia y discapacidad."', NULL),
	('2598af01-608e-4f2e-8e73-c4e40f6fce00', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-02-27 22:29:35.027381+00', 'ACTUALIZACION_CAMPO', 'modalidad_educativa', NULL, '"Mixta"', NULL),
	('27217ea8-84f5-4b95-b0de-26203ee62b09', 'dc286072-c649-43aa-8a2f-aa3ef6166647', NULL, '2026-03-04 15:42:54.388936+00', 'ACTUALIZACION_CAMPO', 'area_de_estudio', '"07 Salud (CMPE 2016, campo amplio)"', '"07 Salud (CMPE 2016). Campo de formación específico: Química Farmacéutica, Farmacotecnia, Cosmética y Perfumería (con énfasis en análisis instrumental, regulación y seguridad sanitaria)."', NULL),
	('e4eaff59-b432-4ecc-ade3-1ef745651726', 'f35bd838-6df7-4a3b-9fbf-879f9b3e6da9', NULL, '2026-03-06 19:59:16.460883+00', 'ACTUALIZACION', 'nombre', '"Licenciatura en Educación Especial como sombra"', '"Educación Especial como sombra"', NULL),
	('db546c6b-5fb5-4f80-b7c5-9d395bf36c81', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-03-09 16:28:20.394326+00', 'ACTUALIZACION_CAMPO', 'perfil_de_egreso', '"Conocimientos:\n  - Marco conceptual de la Educación Especial y modelos de atención a la diversidad.\n  - Normativa nacional e internacional sobre inclusión educativa y derechos de las personas con discapacidad.\n  - Características del desarrollo infantil y del aprendizaje en educación primaria.\n  - Estrategias pedagógicas y adaptaciones curriculares para diversas necesidades educativas.\nHabilidades:\n  - Identificar y diagnosticar barreras de aprendizaje en entornos escolares.\n  - Diseñar y aplicar adaptaciones curriculares y estrategias de apoyo individualizado.\n  - Intervenir como figura de sombra para facilitar la participación y el aprendizaje en aula regular.\n  - Colaborar con equipos docentes, familias y profesionales para la elaboración de planes de atención individualizada.\n  - Evaluar el progreso del estudiante mediante instrumentos cualitativos y cuantitativos.\nActitudes:\n  - Promover una práctica profesional ética, centrada en la dignidad y derechos del estudiantado.\n  - Mostrar sensibilidad hacia la diversidad cultural, funcional y socioemocional.\n  - Adoptar una postura reflexiva, colaborativa y comprometida con la mejora continua."', '"Conocimientos:\n  - Marco conceptual de la Educación Especial y modelos de atención a la diversidad, con énfasis en la figura de sombra como mediadora del aprendizaje en educación primaria.\n  - Normativa nacional e internacional sobre inclusión educativa, derechos de las personas con discapacidad y derechos humanos aplicados a contextos escolares.\n  - Características del desarrollo infantil y del aprendizaje en educación primaria, con atención a la diversidad cultural y socioemocional.\n  - Fundamentos de evaluación formativa, diseño universal para el aprendizaje (DUA) y estrategias de adaptación curricular y de apoyo.\n  - Diseño y gestión de entornos de aprendizaje inclusivos, uso de tecnologías de apoyo y técnicas de observación y intervención.\nHabilidades:\n  - Identificar, registrar y analizar barreras de aprendizaje y necesidades educativas a partir de observación estructurada y evidencias.\n  - Diseñar, adaptar y aplicar intervenciones pedagógicas y apoyos individualizados, incluida la figura de sombra, para promover participación y aprendizaje en aula regular.\n  - Planificar y coordinar planes de atención individualizada en colaboración con docentes, familias y equipos de apoyo interprofesional.\n  - Facilitar la mediación, la comunicación y la interacción en contextos diversos, promoviendo estrategias DUA y uso responsable de tecnologías.\n  - Evaluar el progreso estudiantil con instrumentos cualitativos y cuantitativos y ajustar intervenciones con base en evidencia.\nActitudes:\n  - Compromiso ético con la dignidad, derechos y bienestar de las personas con discapacidad; ética profesional, confidencialidad y respeto a la diversidad.\n  - Sensibilidad intercultural y socioemocional; respeto a la diversidad y a la dignidad de la persona.\n  - Enfoque reflexivo y colaborativo; orientación a la mejora continua, investigación-acción y aprendizaje a lo largo de la vida.\n  - Tolerancia, empatía y resiliencia para trabajar en entornos educativos complejos y con comunidades escolares; responsabilidad social y compromiso con la inclusión."', NULL),
	('51e74cdf-939d-495b-aab0-d2ff17f88cc8', '198c763b-9d97-423b-b13a-5713437fc81b', NULL, '2026-03-12 21:57:19.162202+00', 'ACTUALIZACION_CAMPO', 'diseno_curricular', '"Rígido"', '"Flexible"', NULL),
